export const LESSONS: any[] = [{"id": "gramm-activist-investing#0", "t": "Screen for bad capital allocation to avoid rather than great allocation to find — disasters are predictable, brilliance is not.", "guest": "Jeff Gramm", "slug": "gramm-activist-investing", "date": "2016-09-11", "type": "Hedge Fund"}, {"id": "gramm-activist-investing#1", "t": "Qualify buyback programs by conviction: lumpy, opportunistic repurchases at big discounts outperform; front-loaded EPS-driven programs are a red flag.", "guest": "Jeff Gramm", "slug": "gramm-activist-investing", "date": "2016-09-11", "type": "Hedge Fund"}, {"id": "mauboussin-active-asset-management#0", "t": "Step back on every decision and compare fundamentals to expectations — the gap, not the news, is where excess return lives.", "guest": "Michael Mauboussin", "slug": "mauboussin-active-asset-management", "date": "2016-09-20", "type": "Academic / Author"}, {"id": "mauboussin-active-asset-management#1", "t": "Buy alongside intrinsic-value buybacks (the Stiritz signal) and treat EPS- or dilution-driven repurchase programs as a warning.", "guest": "Michael Mauboussin", "slug": "mauboussin-active-asset-management", "date": "2016-09-20", "type": "Academic / Author"}, {"id": "zweig-the-power-of-serendipity#0", "t": "Before trusting any backtest, demand a motivating theory, decades of data, and out-of-sample validation — most of the 300 published factors fail all three.", "guest": "Jason Zweig", "slug": "zweig-the-power-of-serendipity", "date": "2016-09-27", "type": "Academic / Author"}, {"id": "zweig-the-power-of-serendipity#1", "t": "Pay for advice, not portfolio assembly: the commodity piece costs 1% while the priceless planning is free — an inversion ripe for disruption.", "guest": "Jason Zweig", "slug": "zweig-the-power-of-serendipity", "date": "2016-09-27", "type": "Academic / Author"}, {"id": "zweig-the-power-of-serendipity#2", "t": "Know your emotional weak link; Zweig could buy well but not sell, so he indexed everything and hasn't traded since Q4 2008.", "guest": "Jason Zweig", "slug": "zweig-the-power-of-serendipity", "date": "2016-09-27", "type": "Academic / Author"}, {"id": "housel-walking-and-thinking#0", "t": "Distrust the precision of models: a complicated DCF invites belief 'down to the decimal point' while VC's admitted 100x-or-zero range is more honest about uncertainty.", "guest": "Morgan Housel", "slug": "housel-walking-and-thinking", "date": "2016-10-04", "type": "Academic / Author"}, {"id": "housel-walking-and-thinking#1", "t": "Judge failed ideas on timing, not merit — the ridiculed business of one cycle often becomes the profitable one two decades later once infrastructure catches up.", "guest": "Morgan Housel", "slug": "housel-walking-and-thinking", "date": "2016-10-04", "type": "Academic / Author"}, {"id": "housel-walking-and-thinking#2", "t": "Wealth is built at the base of the pyramid: savings rate beats asset allocation, and the three levers that matter are school, house, and car.", "guest": "Morgan Housel", "slug": "housel-walking-and-thinking", "date": "2016-10-04", "type": "Academic / Author"}, {"id": "rudder-the-quantified-self#0", "t": "Pick the metric you manage against by working backward from what customers actually want - the industry-standard KPI can be exactly wrong for your business.", "guest": "Christian Rudder", "slug": "rudder-the-quantified-self", "date": "2016-10-11", "type": "Founder / Operator"}, {"id": "rudder-the-quantified-self#2", "t": "Differentiated, polarizing offerings outperform iterative generic ones - bestsellers carry lots of one-star AND five-star reviews.", "guest": "Christian Rudder", "slug": "rudder-the-quantified-self", "date": "2016-10-11", "type": "Founder / Operator"}, {"id": "rowley-vanguards-gerry-oreilly-and-jim-rowley#0", "t": "Your stock-bond split, not security selection, is the dominant risk-return decision in a diversified portfolio - get that right before anything else.", "guest": "Gerry O'Reilly & Jim Rowley", "slug": "rowley-vanguards-gerry-oreilly-and-jim-rowley", "date": "2016-10-18", "type": "Public Markets"}, {"id": "seides-a-deep-dive-into-hedge-funds#1", "t": "A hot 2-year track record is the least useful signal a seeder can buy — outsized short-run returns are the most likely to revert.", "guest": "Ted Seides", "slug": "seides-a-deep-dive-into-hedge-funds", "date": "2016-10-25", "type": "Public Markets"}, {"id": "seides-a-deep-dive-into-hedge-funds#2", "t": "Judge a spinout by what made the parent firm work: a teachable process travels with the person, a platform's infrastructure does not.", "guest": "Ted Seides", "slug": "seides-a-deep-dive-into-hedge-funds", "date": "2016-10-25", "type": "Public Markets"}, {"id": "adams-an-internal-locus-of-control#0", "t": "Outcomes under stress are set in preparation: build the checklist detail-by-detail because you will default to your training, not your intentions.", "guest": "Kiley Adams", "slug": "adams-an-internal-locus-of-control", "date": "2016-10-28", "type": "Athlete / Coach"}, {"id": "adams-an-internal-locus-of-control#1", "t": "Adopt an internal locus of control — treating every miss as a fixable process error compounds skill faster than blaming conditions.", "guest": "Kiley Adams", "slug": "adams-an-internal-locus-of-control", "date": "2016-10-28", "type": "Athlete / Coach"}, {"id": "stein-the-state-of-automated-investing#0", "t": "Surface consequences at the moment of decision — Betterment's pre-trade tax preview stopped 75% of costly trades cold", "guest": "Jon Stein", "slug": "stein-the-state-of-automated-investing", "date": "2016-11-01", "type": "Founder / Operator"}, {"id": "stein-the-state-of-automated-investing#1", "t": "Rent scale where it exists (4bp ETFs) and compete only where you have an edge; manufacturing your own product is often value-destructive", "guest": "Jon Stein", "slug": "stein-the-state-of-automated-investing", "date": "2016-11-01", "type": "Founder / Operator"}, {"id": "stein-the-state-of-automated-investing#2", "t": "Universal customer complaints plus zero innovation in a category is a buy signal for entrants, not a warning", "guest": "Jon Stein", "slug": "stein-the-state-of-automated-investing", "date": "2016-11-01", "type": "Founder / Operator"}, {"id": "beshore-cultivating-a-disaster-resistant-compound-interest-machine#0", "t": "Price small private companies off owner earnings (EBITDA minus true capital needs), and assume the headline number overstates reality", "guest": "Brent Beshore", "slug": "beshore-cultivating-a-disaster-resistant-compound-interest-machine", "date": "2016-11-08", "type": "PE / Buyout"}, {"id": "beshore-cultivating-a-disaster-resistant-compound-interest-machine#1", "t": "In markets where value is tied to the seller, being the trustworthy, non-flaky buyer who honors term sheets is a durable competitive advantage", "guest": "Brent Beshore", "slug": "beshore-cultivating-a-disaster-resistant-compound-interest-machine", "date": "2016-11-08", "type": "PE / Buyout"}, {"id": "beshore-cultivating-a-disaster-resistant-compound-interest-machine#2", "t": "Extraordinary yields signal extraordinary difficulty, not free money — 2,000 looks for 3 deals, 22% LOI close rates, and 130 open issues two weeks before close", "guest": "Brent Beshore", "slug": "beshore-cultivating-a-disaster-resistant-compound-interest-machine", "date": "2016-11-08", "type": "PE / Buyout"}, {"id": "shapiro-better-for-you-better-for-the-world#0", "t": "Screen mission-driven deals with the villain test: if the product doesn't win on naked self-interest, the addressable market is a rounding error.", "guest": "Craig Shapiro", "slug": "shapiro-better-for-you-better-for-the-world", "date": "2016-11-14", "type": "VC"}, {"id": "shapiro-better-for-you-better-for-the-world#2", "t": "Diligence the origin story: ideas born from a founder's own pain point survive the trough; ideas born from market-size reports don't.", "guest": "Craig Shapiro", "slug": "shapiro-better-for-you-better-for-the-world", "date": "2016-11-14", "type": "VC"}, {"id": "simler-exploring-the-frontier#0", "t": "Smart generalists plus data do not equal edge: Palantir's finance tool failed because nobody building it lived the analyst's minutiae — domain passion is part of the moat.", "guest": "Kevin Simler", "slug": "simler-exploring-the-frontier", "date": "2016-11-22", "type": "Academic / Author"}, {"id": "simler-exploring-the-frontier#1", "t": "Watch for honest vs. mimicked signals in markets and pitches: a signal anyone can cheaply copy carries no information, and mimics proliferate until trust collapses.", "guest": "Kevin Simler", "slug": "simler-exploring-the-frontier", "date": "2016-11-22", "type": "Academic / Author"}, {"id": "simler-exploring-the-frontier#2", "t": "Culture is an asset that compounds in hypergrowth and gets stress-tested in drawdowns — evaluate teams on how they'd behave when the trajectory flips.", "guest": "Kevin Simler", "slug": "simler-exploring-the-frontier", "date": "2016-11-22", "type": "Academic / Author"}, {"id": "cole-small-bets-huge-payoffs#0", "t": "Pair a small long-volatility sleeve with beta or value: the CBOE long-vol index plus the S&P 500 beat the average hedge fund by 90% since 2005.", "guest": "Chris Cole", "slug": "cole-small-bets-huge-payoffs", "date": "2016-11-29", "type": "Hedge Fund"}, {"id": "cole-small-bets-huge-payoffs#2", "t": "Distinguish tail-risk insurance from long-vol alpha before sizing: a hedge that bleeds 10% a year digs a hole no crisis payout can fill.", "guest": "Chris Cole", "slug": "cole-small-bets-huge-payoffs", "date": "2016-11-29", "type": "Hedge Fund"}, {"id": "brown-the-reformation#0", "t": "Never structure manager selection as a short-horizon winner-take-all contest — the incentive design itself produces reckless portfolios.", "guest": "Josh Brown", "slug": "brown-the-reformation", "date": "2016-12-06", "type": "Public Markets"}, {"id": "brown-the-reformation#1", "t": "Distrust anyone selling proximity to greatness ('I trained that famous manager') — Jedi instincts don't transfer, and products claiming otherwise are a scam.", "guest": "Josh Brown", "slug": "brown-the-reformation", "date": "2016-12-06", "type": "Public Markets"}, {"id": "maddox-the-ace-of-spades#0", "t": "Follow anomalies that don't make sense — a fish pond built mid-war and one enemy-free bodyguard staying put were the threads that led to Saddam", "guest": "Eric Maddox", "slug": "maddox-the-ace-of-spades", "date": "2016-12-13", "type": "Other"}, {"id": "maddox-the-ace-of-spades#1", "t": "Measure your method's base rate; a 4% process can persist for decades because replacing it demands courage that looks like weakness", "guest": "Eric Maddox", "slug": "maddox-the-ace-of-spades", "date": "2016-12-13", "type": "Other"}, {"id": "maddox-the-ace-of-spades#2", "t": "Align incentives before extracting information — sources start leading the hunt once helping you clearly serves their freedom and their family", "guest": "Eric Maddox", "slug": "maddox-the-ace-of-spades", "date": "2016-12-13", "type": "Other"}, {"id": "ptak-the-prospects-for-active-management#0", "t": "Buy from the cheapest quintile: fees are the most reliable forward predictor, with cheap funds 3x likelier to survive and succeed", "guest": "Jeff Ptak", "slug": "ptak-the-prospects-for-active-management", "date": "2016-12-20", "type": "Other"}, {"id": "ptak-the-prospects-for-active-management#1", "t": "Before picking any active fund, ask if you can endure a 10-year stretch of underperformance; if not, index — the behavior gap will eat the alpha", "guest": "Jeff Ptak", "slug": "ptak-the-prospects-for-active-management", "date": "2016-12-20", "type": "Other"}, {"id": "ptak-the-prospects-for-active-management#2", "t": "Treat a torrent of inflows into a strategy as a warning sign; bloat precedes mean reversion and managers close funds only after it's too late", "guest": "Jeff Ptak", "slug": "ptak-the-prospects-for-active-management", "date": "2016-12-20", "type": "Other"}, {"id": "parrish-mastering-mental-models#0", "t": "Alpha in any field comes from correct deviation from industry norms — same-as-everyone strategies only win on cost or speed", "guest": "Shane Parrish", "slug": "parrish-mastering-mental-models", "date": "2016-12-27", "type": "Academic / Author"}, {"id": "parrish-mastering-mental-models#2", "t": "Whoever holds the data holds the advantage — before outsourcing, ask which advantage you're handing over and whether it compounds", "guest": "Shane Parrish", "slug": "parrish-mastering-mental-models", "date": "2016-12-27", "type": "Academic / Author"}, {"id": "egan-designing-better-decisions#1", "t": "Remove yourself from execution: define entry, exit, and rules in a cold state, then let a system trade so hot emotions never touch the order", "guest": "Dan Egan", "slug": "egan-designing-better-decisions", "date": "2017-01-03", "type": "Founder / Operator"}, {"id": "egan-designing-better-decisions#2", "t": "Whipsaw 10-20% drawdowns do the real damage — they train investors to flee false alarms and miss the rebound", "guest": "Dan Egan", "slug": "egan-designing-better-decisions", "date": "2017-01-03", "type": "Founder / Operator"}, {"id": "shapiro-watching-a-venture-fund-at-work#0", "t": "At seed stage, price the round to set the company up for a successful next raise, not to win the deal today.", "guest": "Craig Shapiro, Lauren Loktev & Kanyi Maqubela", "slug": "shapiro-watching-a-venture-fund-at-work", "date": "2017-01-10", "type": "VC"}, {"id": "shapiro-watching-a-venture-fund-at-work#2", "t": "Weight the founder/team above traditional diligence — stress-test how they react when a store kicks them out or a competitor launches.", "guest": "Craig Shapiro, Lauren Loktev & Kanyi Maqubela", "slug": "shapiro-watching-a-venture-fund-at-work", "date": "2017-01-10", "type": "VC"}, {"id": "lowin-machine-intelligence-and-risk-management#1", "t": "Guard against overfitting by preferring simpler, regularized models and distrusting your own confidence in a great backtest.", "guest": "Jeremiah Lowin", "slug": "lowin-machine-intelligence-and-risk-management", "date": "2017-01-17", "type": "Other"}, {"id": "lowin-machine-intelligence-and-risk-management#2", "t": "Manage risk by understanding how a portfolio's exposures evolve over time — creep sneaks in slowly like a boiling frog.", "guest": "Jeremiah Lowin", "slug": "lowin-machine-intelligence-and-risk-management", "date": "2017-01-17", "type": "Other"}, {"id": "koppelman-chasing-curiosity#0", "t": "Standing pat — refusing to change when your own read differs from the crowd — is as valuable as knowing when to change.", "guest": "Brian Koppelman", "slug": "koppelman-chasing-curiosity", "date": "2017-01-24", "type": "Other"}, {"id": "beshore-private-equity-venture-capital-and-the-future-of-money-management#0", "t": "Discard seller projections entirely; underwrite only the historical trajectory and hunt for a moat independent of the founder's personality.", "guest": "Brent Beshore", "slug": "beshore-private-equity-venture-capital-and-the-future-of-money-management", "date": "2017-01-31", "type": "PE / Buyout"}, {"id": "beshore-private-equity-venture-capital-and-the-future-of-money-management#2", "t": "Fee-driven pressure to deploy capital is the enemy of good decisions; the willingness to withstand lumpiness and wait for the right deal is the edge.", "guest": "Brent Beshore", "slug": "beshore-private-equity-venture-capital-and-the-future-of-money-management", "date": "2017-01-31", "type": "PE / Buyout"}, {"id": "mansueto-lessons-from-the-founder-of-morningstar#1", "t": "Prefer buybacks to dividends when a stock trades at or below fair value — it hands shareholders the timing of the tax hit.", "guest": "Joe Mansueto", "slug": "mansueto-lessons-from-the-founder-of-morningstar", "date": "2017-02-07", "type": "Founder / Operator"}, {"id": "mansueto-lessons-from-the-founder-of-morningstar#2", "t": "Beware closet indexers: index-like performance at active fees is exactly what the passive wave should erase.", "guest": "Joe Mansueto", "slug": "mansueto-lessons-from-the-founder-of-morningstar", "date": "2017-02-07", "type": "Founder / Operator"}, {"id": "cassel-investing-in-tiny-stocks#0", "t": "In microcaps, seek illiquidity: it drives both the perceived risk and the real opportunity, since larger money can't compete there.", "guest": "Ian Cassel", "slug": "cassel-investing-in-tiny-stocks", "date": "2017-02-14", "type": "Public Markets"}, {"id": "cassel-investing-in-tiny-stocks#2", "t": "Avoid capital-intensive microcaps — dilution from weak capital-raisers is the category's core risk.", "guest": "Ian Cassel", "slug": "cassel-investing-in-tiny-stocks", "date": "2017-02-14", "type": "Public Markets"}, {"id": "moazed-building-modern-monopolies#1", "t": "Screen platforms by producer switching cost and whether hardware raises the barrier; commoditized services get their price set by the platform itself.", "guest": "Alex Moazed", "slug": "moazed-building-modern-monopolies", "date": "2017-02-21", "type": "Founder / Operator"}, {"id": "rogers-slow-and-steady-wins-the-race#1", "t": "Use ETF-driven misclassification as a hunting ground — companies like JLL/CBRE trade on their last-crisis behavior, not their diversified present.", "guest": "John Rogers", "slug": "rogers-slow-and-steady-wins-the-race", "date": "2017-02-28", "type": "Public Markets"}, {"id": "rogers-slow-and-steady-wins-the-race#2", "t": "Treat capital allocation as central to the value equation: reward discount buybacks, avoid leveraged empire-building and priced-for-perfection balance sheets.", "guest": "John Rogers", "slug": "rogers-slow-and-steady-wins-the-race", "date": "2017-02-28", "type": "Public Markets"}, {"id": "attia-how-to-live-a-longer-higher-quality-life#0", "t": "The best interventions are often subtractive — removing sugar, gluten, and food from the day beats adding new things, just like investing.", "guest": "Peter Attia", "slug": "attia-how-to-live-a-longer-higher-quality-life", "date": "2017-03-07", "type": "Scientist"}, {"id": "attia-how-to-live-a-longer-higher-quality-life#1", "t": "Change the default environment, not just the information — policy and friction move behavior far more than awareness of facts.", "guest": "Peter Attia", "slug": "attia-how-to-live-a-longer-higher-quality-life", "date": "2017-03-07", "type": "Scientist"}, {"id": "higgins-permanent-equity#0", "t": "Screen small-business acquisitions on durability (survives 15-20 years) rather than 3-5 year growth projections.", "guest": "Trish & James Higgins", "slug": "higgins-permanent-equity", "date": "2017-03-14", "type": "PE / Buyout"}, {"id": "higgins-permanent-equity#1", "t": "Add value by centralizing scarce expertise — CFO, HR, tech — across a portfolio the individual companies could never afford alone.", "guest": "Trish & James Higgins", "slug": "higgins-permanent-equity", "date": "2017-03-14", "type": "PE / Buyout"}, {"id": "higgins-permanent-equity#3", "t": "Structure manager comp around carry, not management fees, to stay aligned and avoid asset-gathering incentives.", "guest": "Trish & James Higgins", "slug": "higgins-permanent-equity", "date": "2017-03-14", "type": "PE / Buyout"}, {"id": "oshaughnessy-premeditated-success#0", "t": "Discipline dominates the factors themselves — a naive deep-value screen beats brilliant, well-resourced managers because they can't hold it through drawdowns.", "guest": "Jim O'Shaughnessy", "slug": "oshaughnessy-premeditated-success", "date": "2017-03-21", "type": "Public Markets"}, {"id": "oshaughnessy-premeditated-success#1", "t": "Judge and hold strategies over 10+ year horizons; three-year windows are mostly noise and set you up to fire and hire at exactly the wrong time.", "guest": "Jim O'Shaughnessy", "slug": "oshaughnessy-premeditated-success", "date": "2017-03-21", "type": "Public Markets"}, {"id": "oshaughnessy-premeditated-success#2", "t": "Even indexing has a failure point — you can still sell near the bottom, so mastering your emotions matters more than the vehicle you choose.", "guest": "Jim O'Shaughnessy", "slug": "oshaughnessy-premeditated-success", "date": "2017-03-21", "type": "Public Markets"}, {"id": "seides-the-future-of-asset-management#1", "t": "Longer-duration capital is a genuine edge: it lets you buy events that resolve with certainty over years but at unknown timing, priced cheaper than dated catalysts.", "guest": "Ted Seides & Brent Beshore", "slug": "seides-the-future-of-asset-management", "date": "2017-03-28", "type": "Hedge Fund"}, {"id": "seides-the-future-of-asset-management#2", "t": "When evaluating a small business, price the owner's intuition and relationships, not the quoted $150K replacement cost — that's where the moat actually lives.", "guest": "Ted Seides & Brent Beshore", "slug": "seides-the-future-of-asset-management", "date": "2017-03-28", "type": "Hedge Fund"}, {"id": "hy-quant-hedge-funds-and-the-fear-of-death#0", "t": "Insist on proof of a repeatable process that has already survived a genuine stress test, not just a 2002-2006 everything-works run.", "guest": "Khe Hy", "slug": "hy-quant-hedge-funds-and-the-fear-of-death", "date": "2017-04-04", "type": "Hedge Fund"}, {"id": "hy-quant-hedge-funds-and-the-fear-of-death#1", "t": "Get to funds early — small and young managers outperform, and by the roadshow stage the edge is gone.", "guest": "Khe Hy", "slug": "hy-quant-hedge-funds-and-the-fear-of-death", "date": "2017-04-04", "type": "Hedge Fund"}, {"id": "varty-the-art-of-tracking#0", "t": "Anytime you follow a pre-written playbook instead of reading the live situation, you're toast — imitation is suicide.", "guest": "Boyd Varty", "slug": "varty-the-art-of-tracking", "date": "2017-04-11", "type": "Other"}, {"id": "varty-the-art-of-tracking#2", "t": "When you lose the thread, stop and go still rather than thrashing — new signal appears only when you're quiet enough to notice it.", "guest": "Boyd Varty", "slug": "varty-the-art-of-tracking", "date": "2017-04-11", "type": "Other"}, {"id": "yudkoff-really-private-equity#0", "t": "Buy enduringly profitable, dull businesses at ~4x EBITDA where senior debt is ~2x—the structure makes default very hard and go-to-zero risk low.", "guest": "Royce Yudkoff & Rick Ruback", "slug": "yudkoff-really-private-equity", "date": "2017-04-18", "type": "Academic / Author"}, {"id": "yudkoff-really-private-equity#1", "t": "Screen hardest for recurring revenue with real switching costs; treat growth as a risk multiplier, not a virtue, and never pay up for it.", "guest": "Royce Yudkoff & Rick Ruback", "slug": "yudkoff-really-private-equity", "date": "2017-04-18", "type": "Academic / Author"}, {"id": "yudkoff-really-private-equity#2", "t": "Favor products that are a tiny share of the customer's spend but mission-critical—price sensitivity vanishes and incumbency compounds.", "guest": "Royce Yudkoff & Rick Ruback", "slug": "yudkoff-really-private-equity", "date": "2017-04-18", "type": "Academic / Author"}, {"id": "moses-the-big-short-and-beyond#1", "t": "When borrow costs and dividends make shorting a stock uneconomic, buy protection on the underlying bonds instead.", "guest": "Danny Moses", "slug": "moses-the-big-short-and-beyond", "date": "2017-04-25", "type": "Hedge Fund"}, {"id": "moses-the-big-short-and-beyond#2", "t": "Interrogate how a company gets paid; finance-arm fees and non-GAAP add-backs can hide the real economics.", "guest": "Danny Moses", "slug": "moses-the-big-short-and-beyond", "date": "2017-04-25", "type": "Hedge Fund"}, {"id": "moses-the-big-short-and-beyond#3", "t": "You can't outrun a benchmark that's absorbing your own fund's outflows — understand the ETF structure before stock-picking.", "guest": "Danny Moses", "slug": "moses-the-big-short-and-beyond", "date": "2017-04-25", "type": "Hedge Fund"}, {"id": "seides-the-bet-with-buffett#0", "t": "A bet against an expensive index is really a valuation bet — the vehicle you choose to express it is secondary.", "guest": "Ted Seides", "slug": "seides-the-bet-with-buffett", "date": "2017-05-02", "type": "Hedge Fund"}, {"id": "seides-the-bet-with-buffett#1", "t": "Dollar-weighted (real) returns matter more than time-weighted (paper) returns; pick strategies you can actually hold through drawdowns.", "guest": "Ted Seides", "slug": "seides-the-bet-with-buffett", "date": "2017-05-02", "type": "Hedge Fund"}, {"id": "seides-the-bet-with-buffett#2", "t": "Low-cost investing does not have to mean the S&P 500 — choosing that index is itself an active bet on US outperformance.", "guest": "Ted Seides", "slug": "seides-the-bet-with-buffett", "date": "2017-05-02", "type": "Hedge Fund"}, {"id": "thorndike-how-skilled-capital-allocators-compound-capital#0", "t": "Judge CEOs on per-share value creation over long tenures, not size, growth, or charisma.", "guest": "Will Thorndike", "slug": "thorndike-how-skilled-capital-allocators-compound-capital", "date": "2017-05-09", "type": "PE / Buyout"}, {"id": "thorndike-how-skilled-capital-allocators-compound-capital#1", "t": "Insurance float plus a talented investor is one of the hardest compounding machines to beat over 20 years.", "guest": "Will Thorndike", "slug": "thorndike-how-skilled-capital-allocators-compound-capital", "date": "2017-05-09", "type": "PE / Buyout"}, {"id": "thorndike-how-skilled-capital-allocators-compound-capital#2", "t": "A narrow, disciplined screen that generates fast no's beats a wide net — early rejection is a feature, not a limitation.", "guest": "Will Thorndike", "slug": "thorndike-how-skilled-capital-allocators-compound-capital", "date": "2017-05-09", "type": "PE / Buyout"}, {"id": "mauboussin-man-machine-moats-and-power-of-the-outside-view#0", "t": "Before modeling a company, build the base rate: how many comparable firms ever achieved what your forecast assumes.", "guest": "Michael Mauboussin", "slug": "mauboussin-man-machine-moats-and-power-of-the-outside-view", "date": "2017-05-16", "type": "Public Markets"}, {"id": "mauboussin-man-machine-moats-and-power-of-the-outside-view#1", "t": "Hunt where sellers are forced and non-fundamental — spinoffs, margin calls, index-rule thresholds — and be the liquidity provider.", "guest": "Michael Mauboussin", "slug": "mauboussin-man-machine-moats-and-power-of-the-outside-view", "date": "2017-05-16", "type": "Public Markets"}, {"id": "mauboussin-man-machine-moats-and-power-of-the-outside-view#2", "t": "Combine man and machine: your domain model (inside view) plus large-sample base rates (outside view) beats either alone.", "guest": "Michael Mauboussin", "slug": "mauboussin-man-machine-moats-and-power-of-the-outside-view", "date": "2017-05-16", "type": "Public Markets"}, {"id": "salem-the-art-of-asset-allocation#1", "t": "In worst-case conditions the 15 asset classes collapse into a few real factors: equity beta, sovereign credit, and miscellaneous flotsam.", "guest": "David Salem", "slug": "salem-the-art-of-asset-allocation", "date": "2017-05-23", "type": "Other"}, {"id": "salem-the-art-of-asset-allocation#2", "t": "Read a manager's timestamped, ex-ante writing to distinguish skill from luck and expose single-scenario thinking.", "guest": "David Salem", "slug": "salem-the-art-of-asset-allocation", "date": "2017-05-23", "type": "Other"}, {"id": "chilton-the-human-blitzkrieg#0", "t": "Buy into forced selling — index deletions and dividend cuts create prices far below intrinsic value with the lowest actual risk.", "guest": "David Chilton", "slug": "chilton-the-human-blitzkrieg", "date": "2017-05-30", "type": "Founder / Operator"}, {"id": "chilton-the-human-blitzkrieg#2", "t": "Screen out founders with poor attention to detail and no marketing math — a good product with margins that can't fund positioning will fail.", "guest": "David Chilton", "slug": "chilton-the-human-blitzkrieg", "date": "2017-05-30", "type": "Founder / Operator"}, {"id": "judelson-bail-street-with-nycs-leading-bail-bondsman#0", "t": "Underwrite the person, not just the paper — reading character in real time can beat any checklist when default risk is the whole game.", "guest": "Ira Judelson & Danny Moses", "slug": "judelson-bail-street-with-nycs-leading-bail-bondsman", "date": "2017-06-06", "type": "Founder / Operator"}, {"id": "judelson-bail-street-with-nycs-leading-bail-bondsman#2", "t": "Take hard, liquid collateral (real estate) over exotic assets — a pizzeria's ovens are worthless when the owner strips and vanishes.", "guest": "Ira Judelson & Danny Moses", "slug": "judelson-bail-street-with-nycs-leading-bail-bondsman", "date": "2017-06-06", "type": "Founder / Operator"}, {"id": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas#0", "t": "Never put a backtested strategy into production without an out-of-sample test and a causal hypothesis for why it works.", "guest": "Leigh Drogen", "slug": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas", "date": "2017-06-13", "type": "Founder / Operator"}, {"id": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas#1", "t": "Judge an alternative dataset by where it sits on its adoption curve — early upslope has alpha, table-stakes data does not.", "guest": "Leigh Drogen", "slug": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas", "date": "2017-06-13", "type": "Founder / Operator"}, {"id": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas#2", "t": "Distinguish intrinsic edges (value, momentum, liquidity — behavioral, permanent) from informational edges, which decay as they're arbitraged.", "guest": "Leigh Drogen", "slug": "drogen-quant-vs-traditional-investors-and-how-alphas-become-betas", "date": "2017-06-13", "type": "Founder / Operator"}, {"id": "rachleff-building-something-people-want-to-buy#1", "t": "The best alternative-asset funds only accept long-term LPs like endowments — broad retail access is a signal of a weak fund.", "guest": "Andy Rachleff", "slug": "rachleff-building-something-people-want-to-buy", "date": "2017-06-20", "type": "VC"}, {"id": "rachleff-building-something-people-want-to-buy#2", "t": "Bet on emerging markets, not big ones — it's far harder to take share from incumbents than to ride a new inflection point.", "guest": "Andy Rachleff", "slug": "rachleff-building-something-people-want-to-buy", "date": "2017-06-20", "type": "VC"}, {"id": "neumann-the-deployment-age-power-laws-and-venture-capital#0", "t": "Embrace Knightian uncertainty; best alpha comes from opportunities where outcomes are unpredictable but systemically possible.", "guest": "Jerry Neumann", "slug": "neumann-the-deployment-age-power-laws-and-venture-capital", "date": "2017-07-11", "type": "VC"}, {"id": "neumann-the-deployment-age-power-laws-and-venture-capital#1", "t": "Analyze complementary asset dependencies; avoid relying on non-generic assets controlled by powerful suppliers—they extract the value.", "guest": "Jerry Neumann", "slug": "neumann-the-deployment-age-power-laws-and-venture-capital", "date": "2017-07-11", "type": "VC"}, {"id": "neumann-the-deployment-age-power-laws-and-venture-capital#2", "t": "Venture concentration vs. diversification is a trade-off: specialized bets on knowable signals vs. more picks for outlier capture, but mixing both dilutes alpha.", "guest": "Jerry Neumann", "slug": "neumann-the-deployment-age-power-laws-and-venture-capital", "date": "2017-07-11", "type": "VC"}, {"id": "ganti-esoteric-assets#0", "t": "Avoid highly liquid, competed markets (stocks, bonds, venture capital). Seek non-bid, non-auctioned, orphaned assets where price mechanisms don't exist and you're the only bidder.", "guest": "Rishi Ganti", "slug": "ganti-esoteric-assets", "date": "2017-07-18", "type": "Founder / Operator"}, {"id": "ganti-esoteric-assets#2", "t": "High human capital—expertise, relationships, legal/accounting knowledge, local networks—is the durable competitive advantage in esoteric markets because assets remain non-traded.", "guest": "Rishi Ganti", "slug": "ganti-esoteric-assets", "date": "2017-07-18", "type": "Founder / Operator"}, {"id": "drogen-sink-or-swim-how-to-combine-quant-and-traditional-asset-management-techniques#1", "t": "Factor model alpha decays as capital chases crowded factors; sustainable edges require unique data and genuine domain expertise.", "guest": "Leigh Drogen", "slug": "drogen-sink-or-swim-how-to-combine-quant-and-traditional-asset-management-techniques", "date": "2017-08-01", "type": "Founder / Operator"}, {"id": "stulberg-just-manageable-challenges#1", "t": "Manage your energy allocation like portfolio diversification—concentrate bets on one or two growth areas per period to avoid burnout and maintain capacity for future stress.", "guest": "Brad Stulberg", "slug": "stulberg-just-manageable-challenges", "date": "2017-08-08", "type": "Academic / Author"}, {"id": "zweig-business-vs-investing#0", "t": "Behavioral edges (patience, long-term thinking) are the last remaining inefficiencies in public markets and more valuable than analytical edges which are arbitraged away.", "guest": "Morgan Housel & Jason Zweig", "slug": "zweig-business-vs-investing", "date": "2017-08-15", "type": "Public Markets"}, {"id": "zweig-business-vs-investing#1", "t": "Private markets are 50+ years less efficient than public markets were in the 1950s; lower liquidity forces long-term thinking and prevents panic volatility.", "guest": "Morgan Housel & Jason Zweig", "slug": "zweig-business-vs-investing", "date": "2017-08-15", "type": "Public Markets"}, {"id": "zweig-business-vs-investing#2", "t": "Most of the outsized returns (Amazon 50,000x gain) accrue to early-stage private investors; companies staying private longer means public markets miss the hypergrowth years.", "guest": "Morgan Housel & Jason Zweig", "slug": "zweig-business-vs-investing", "date": "2017-08-15", "type": "Public Markets"}, {"id": "dorsey-buying-companies-with-economic-moats#0", "t": "Moats allow sustained pricing power and reinvestment at high returns; most businesses (60-70% of market) lack durable moats and face competition driving returns to WACC.", "guest": "Pat Dorsey", "slug": "dorsey-buying-companies-with-economic-moats", "date": "2017-08-22", "type": "Public Markets"}, {"id": "dorsey-buying-companies-with-economic-moats#1", "t": "Capital allocation quality matters as much as moat strength: same moat with thoughtful vs. careless allocation can produce vastly different investor returns; look for lumpy, discretionary allocation decisions.", "guest": "Pat Dorsey", "slug": "dorsey-buying-companies-with-economic-moats", "date": "2017-08-22", "type": "Public Markets"}, {"id": "dorsey-buying-companies-with-economic-moats#2", "t": "Positional brands (Rolex, Cartier) get cheaper when statistically cheap and moat unimpaired; search-cost brands (Tide) face disruption from low-cost digital competitors; trust-based brands (Gartner) compound through network effects.", "guest": "Pat Dorsey", "slug": "dorsey-buying-companies-with-economic-moats", "date": "2017-08-22", "type": "Public Markets"}, {"id": "brown-the-wu-tang-clan-of-finance#1", "t": "Value trap screening: cheap portfolios win probabilistically; isolate quality, balance-sheet, momentum factors to tilt odds in your favor.", "guest": "Josh Brown & Michael Batnick & Barry Ritholtz", "slug": "brown-the-wu-tang-clan-of-finance", "date": "2017-08-29", "type": "Founder / Operator"}, {"id": "brown-the-wu-tang-clan-of-finance#2", "t": "Separate speculative from core: let clients reserve 5% for 'mad money' experimentation so core wealth philosophy remains intact.", "guest": "Josh Brown & Michael Batnick & Barry Ritholtz", "slug": "brown-the-wu-tang-clan-of-finance", "date": "2017-08-29", "type": "Founder / Operator"}, {"id": "faber-factors-dividends-and-angel-investing#0", "t": "Avoid dividend funds in taxable accounts; use value-screen avoiding high-dividend payers saves 40-400bps annually vs dividend-heavy strategy.", "guest": "Meb Faber", "slug": "faber-factors-dividends-and-angel-investing", "date": "2017-09-07", "type": "Founder / Operator"}, {"id": "faber-factors-dividends-and-angel-investing#1", "t": "Early-stage portfolio requires 10-year horizon, multiple vintages, hundreds of looks; expect one 20% winner and many zeros as normal.", "guest": "Meb Faber", "slug": "faber-factors-dividends-and-angel-investing", "date": "2017-09-07", "type": "Founder / Operator"}, {"id": "faber-factors-dividends-and-angel-investing#2", "t": "Asymmetric fee: long lockup (10 years) + declining redemption penalties justifies much lower fees (50bps vs 1%+); captive capital funds better investing.", "guest": "Meb Faber", "slug": "faber-factors-dividends-and-angel-investing", "date": "2017-09-07", "type": "Founder / Operator"}, {"id": "gardner-finding-companies-that-break-the-rules#0", "t": "Long-term holding (10+ years) on rule-breakers: top dogs in emerging industries + visionary CEOs + strong momentum; stay in jersey through drawdowns, don't sell on dips.", "guest": "David Gardner", "slug": "gardner-finding-companies-that-break-the-rules", "date": "2017-09-12", "type": "Founder / Operator"}, {"id": "gardner-finding-companies-that-break-the-rules#1", "t": "Avoid value trap mentality—buy stocks that have already done well, with high P/E; overvalued by conventional metrics is feature not bug for rule-breakers.", "guest": "David Gardner", "slug": "gardner-finding-companies-that-break-the-rules", "date": "2017-09-12", "type": "Founder / Operator"}, {"id": "gardner-finding-companies-that-break-the-rules#2", "t": "Generate ideas from three sources (personal use, community crowdsource, macro trends) to avoid echo chambers; research deeply before entry, then hold forever.", "guest": "David Gardner", "slug": "gardner-finding-companies-that-break-the-rules", "date": "2017-09-12", "type": "Founder / Operator"}, {"id": "tisch-tech-investing-outside-of-silicon-valley#0", "t": "Seed investors must source deeply (3,000-4,000 companies/year) to avoid fatal omissions. The companies you see and pass on cost the fund, not the ones you lose.", "guest": "David Tisch", "slug": "tisch-tech-investing-outside-of-silicon-valley", "date": "2017-09-19", "type": "VC"}, {"id": "tisch-tech-investing-outside-of-silicon-valley#1", "t": "Founders must articulate their business model and capital plan to reach scale. Betting on 'figure it out later' signals the founder lacks vision.", "guest": "David Tisch", "slug": "tisch-tech-investing-outside-of-silicon-valley", "date": "2017-09-19", "type": "VC"}, {"id": "seims-hash-power-part-2#2", "t": "Resilience through crisis is a signal. Bitcoin survived Silk Road, Mt. Gox, regulatory threats, and crashes with a floor. Survival despite bad fundamentals signals true believer base and real value.", "guest": "Olaf Carlson-Wee, Naval Ravikant, Ari Paul & contributors", "slug": "seims-hash-power-part-2", "date": "2017-10-03", "type": "Other"}, {"id": "ehrsam-hash-power-part-3#1", "t": "Token valuation requires decomposing network utility, speculation premium, and new possibilities; many ICOs lack real use case.", "guest": "Fred Ehrsam & multiple guests (Olaf Carlson-Wee, Naval Ravikant, Peter Van Valkenburgh, Juan Benet, Muneeb Ali)", "slug": "ehrsam-hash-power-part-3", "date": "2017-10-10", "type": "Other"}, {"id": "urban-grand-theft-life#1", "t": "Deep expertise compounds from intellectual curiosity sustained over years; 150 hours on one post beats surface coverage.", "guest": "Tim Urban & Andrew Finn", "slug": "urban-grand-theft-life", "date": "2017-10-17", "type": "Founder / Operator"}, {"id": "urban-grand-theft-life#2", "t": "Creator-dependent content (blog, podcast) sacrifices scale for defensibility and irreplaceability—trade-off favors compounding audiences.", "guest": "Tim Urban & Andrew Finn", "slug": "urban-grand-theft-life", "date": "2017-10-17", "type": "Founder / Operator"}, {"id": "maloley-ladder-the-fitness-marketplace#1", "t": "Franchise economics trump license models because coaching/guidance reduces operator failure and improves retention.", "guest": "Brett Maloley", "slug": "maloley-ladder-the-fitness-marketplace", "date": "2017-10-24", "type": "Founder / Operator"}, {"id": "maloley-ladder-the-fitness-marketplace#2", "t": "Two-sided marketplace requires proving value to both sides before scale; asymmetric growth favors one side and dooms the platform.", "guest": "Brett Maloley", "slug": "maloley-ladder-the-fitness-marketplace", "date": "2017-10-24", "type": "Founder / Operator"}, {"id": "katsuyama-what-happens-when-you-hit-buy#0", "t": "Hidden market structure problems silently destroy institutional execution: latency arbitrage reduces fill rates and increases price impact across large orders.", "guest": "Brad Katsuyama", "slug": "katsuyama-what-happens-when-you-hit-buy", "date": "2017-10-31", "type": "Founder / Operator"}, {"id": "katsuyama-what-happens-when-you-hit-buy#1", "t": "Intermediary business models create perverse incentives misaligned with end customers; brokers paid to route to worst venues, exchanges profit from complexity not efficiency.", "guest": "Brad Katsuyama", "slug": "katsuyama-what-happens-when-you-hit-buy", "date": "2017-10-31", "type": "Founder / Operator"}, {"id": "leonard-capital-light-compounders-reinvestment-moats#0", "t": "Moats are rare (≤5% of companies); most businesses should be ignored entirely to avoid capital-destroying value traps and commodity competition.", "guest": "Connor Leonard", "slug": "leonard-capital-light-compounders-reinvestment-moats", "date": "2017-11-21", "type": "Public Markets"}, {"id": "leonard-capital-light-compounders-reinvestment-moats#1", "t": "Capital-light businesses with negative working capital (customers pre-pay, suppliers paid later) represent the apex form of compounding; they grow earnings without capital deployment.", "guest": "Connor Leonard", "slug": "leonard-capital-light-compounders-reinvestment-moats", "date": "2017-11-21", "type": "Public Markets"}, {"id": "leonard-capital-light-compounders-reinvestment-moats#2", "t": "Concentrated portfolios only work when anchored to 5-10 year time horizons; patience lets you find and hold mispriced compounders through market volatility.", "guest": "Connor Leonard", "slug": "leonard-capital-light-compounders-reinvestment-moats", "date": "2017-11-21", "type": "Public Markets"}, {"id": "wilson-angel-investing-and-trend-spotting#1", "t": "Angel investing flexibility beats VC returns chasing: accept $30-40M lifestyle exits, skip bad investor rounds with ugly economics, support founders personally.", "guest": "Joanne Wilson", "slug": "wilson-angel-investing-and-trend-spotting", "date": "2017-11-28", "type": "VC"}, {"id": "foer-world-without-mind#0", "t": "Platform companies reveal danger through their 'actor drift': they pivot from neutral infrastructure to competitors on their own networks, hiding power asymmetries.", "guest": "Franklin Foer", "slug": "foer-world-without-mind", "date": "2017-12-12", "type": "Academic / Author"}, {"id": "foer-world-without-mind#1", "t": "Tech monopolies are insidious because users love them (cheap/convenient). Regulation requires showing users the hidden costs (data, intellectual autonomy, market opportunity).", "guest": "Franklin Foer", "slug": "foer-world-without-mind", "date": "2017-12-12", "type": "Academic / Author"}, {"id": "higgins-retail-contrarians#0", "t": "Passive index flows create persistent mispricing in less-liquid sectors like CMBS/REITs. Deep specialization and bottom-up analysis unlock alpha others can't see.", "guest": "Jim Higgins & Tom Digan (with Rick & Joel)", "slug": "higgins-retail-contrarians", "date": "2017-12-19", "type": "Hedge Fund"}, {"id": "higgins-retail-contrarians#2", "t": "Liquid alternatives to illiquid assets (public CMBS bonds vs. direct CRE loans) provide optionality during crises. Illiquidity is expensive when you need to move.", "guest": "Jim Higgins & Tom Digan (with Rick & Joel)", "slug": "higgins-retail-contrarians", "date": "2017-12-19", "type": "Hedge Fund"}, {"id": "dixon-the-future-of-tech#0", "t": "Early-stage venture prioritizes founder quality and strong technological tailwinds over proven market demand; market can pivot, founders rarely do.", "guest": "Chris Dixon", "slug": "dixon-the-future-of-tech", "date": "2017-12-26", "type": "VC"}, {"id": "dixon-the-future-of-tech#1", "t": "Decentralized networks must capture developer hearts and minds, not just compete on performance. This is how Internet beat AOL.", "guest": "Chris Dixon", "slug": "dixon-the-future-of-tech", "date": "2017-12-26", "type": "VC"}, {"id": "tyle-the-future-of-venture-capital#1", "t": "Market frothiness signals when discipline is critical: uncapped notes and pre-launch valuations 3-5x normal indicate bubble and reduced return potential.", "guest": "Sheel Tyle", "slug": "tyle-the-future-of-venture-capital", "date": "2018-01-02", "type": "VC"}, {"id": "tyle-the-future-of-venture-capital#2", "t": "Founders should raise deliberately, not excessively. More capital accelerates burn, forces faster growth, increases downside risk if milestones miss.", "guest": "Sheel Tyle", "slug": "tyle-the-future-of-venture-capital", "date": "2018-01-02", "type": "VC"}, {"id": "hamed-creative-investing#1", "t": "Sustainable advantage compounds with scale. If your edge doesn't widen with each deal, it's temporary arbitrage, not a business.", "guest": "Ali Hamed", "slug": "hamed-creative-investing", "date": "2018-01-09", "type": "Founder / Operator"}, {"id": "hamed-creative-investing#2", "t": "Cost of capital varies wildly; first-round funds can accept lower returns than unknown firms. Different products merit different return thresholds.", "guest": "Ali Hamed", "slug": "hamed-creative-investing", "date": "2018-01-09", "type": "Founder / Operator"}, {"id": "byrne-cryptopocalypse#0", "t": "Cryptocurrency investment returns depend entirely on greater-fool dynamics—buying because you believe others will buy higher, with no cash flows or enforceable rights.", "guest": "Preston Byrne", "slug": "byrne-cryptopocalypse", "date": "2018-01-16", "type": "Founder / Operator"}, {"id": "byrne-cryptopocalypse#1", "t": "Exchange liquidity is a hard constraint; if withdrawals exceed deposits, runs happen. Look for signs of stablecoin backing, tether audits, and regulatory surveillance.", "guest": "Preston Byrne", "slug": "byrne-cryptopocalypse", "date": "2018-01-16", "type": "Founder / Operator"}, {"id": "byrne-cryptopocalypse#2", "t": "Most ICOs are unregistered securities with zero legal recourse if the team disappears or promised functionality never materializes.", "guest": "Preston Byrne", "slug": "byrne-cryptopocalypse", "date": "2018-01-16", "type": "Founder / Operator"}, {"id": "hunt-the-three-body-portfolio#0", "t": "Central bank purchases eliminate traditional valuation drivers; quality and value factors work only when central banks step back—a multi-decade wait unlikely.", "guest": "Ben Hunt", "slug": "hunt-the-three-body-portfolio", "date": "2018-01-23", "type": "Hedge Fund"}, {"id": "hunt-the-three-body-portfolio#1", "t": "Harvest beta cheaply via risk-balanced global portfolios; spend the alpha hunt exclusively in private markets where private information still exists.", "guest": "Ben Hunt", "slug": "hunt-the-three-body-portfolio", "date": "2018-01-23", "type": "Hedge Fund"}, {"id": "hunt-the-three-body-portfolio#2", "t": "Reputation risk is bigger than portfolio risk—winding down a business before losses accelerate protects the asset that truly cannot be recovered.", "guest": "Ben Hunt", "slug": "hunt-the-three-body-portfolio", "date": "2018-01-23", "type": "Hedge Fund"}, {"id": "pompliano-full-tilt-investing#1", "t": "Aim for above-average returns consistently (50% annually) rather than binary extreme outcomes (30,000% or zero); compound long-term beats lottery-ticket thinking.", "guest": "Anthony Pompliano", "slug": "pompliano-full-tilt-investing", "date": "2018-01-30", "type": "Founder / Operator"}, {"id": "pompliano-full-tilt-investing#2", "t": "Align incentives: charge no management fee, earn carry only after returning principal to LPs—this shifts focus from AUM to LP returns.", "guest": "Anthony Pompliano", "slug": "pompliano-full-tilt-investing", "date": "2018-01-30", "type": "Founder / Operator"}, {"id": "sawikin-emerging-market-opportunities#0", "t": "Frontier market moats for outsiders: custody gaps, valuation extremes (1/100th Western comps), insider access — Russia vouchers 40–100x because companies only needed to become 95% worse than Mobil.", "guest": "Harvey Sawikin", "slug": "sawikin-emerging-market-opportunities", "date": "2018-02-06", "type": "Hedge Fund"}, {"id": "sawikin-emerging-market-opportunities#1", "t": "Travel-verified operations trump financial models — chose X5 over Magnit after store visits showed inventory discipline and format, predicting outperformance by 200%+.", "guest": "Harvey Sawikin", "slug": "sawikin-emerging-market-opportunities", "date": "2018-02-06", "type": "Hedge Fund"}, {"id": "sawikin-emerging-market-opportunities#2", "t": "Free cashflow and dividend payouts are honest signals of capital discipline; theft-proof dividends signal trust in management intent to return value.", "guest": "Harvey Sawikin", "slug": "sawikin-emerging-market-opportunities", "date": "2018-02-06", "type": "Hedge Fund"}, {"id": "wolfe-this-is-who-you-are-up-against#0", "t": "Track capital inflows into a sector, not market-size forecasts — rising capital is the most reliable predictor of falling returns.", "guest": "Josh Wolfe", "slug": "wolfe-this-is-who-you-are-up-against", "date": "2018-02-13", "type": "VC"}, {"id": "wolfe-this-is-who-you-are-up-against#1", "t": "When the whole partnership loves a founder on the spot, rein it in: you've only observed their ability to raise money, not to operate.", "guest": "Josh Wolfe", "slug": "wolfe-this-is-who-you-are-up-against", "date": "2018-02-13", "type": "VC"}, {"id": "wolfe-this-is-who-you-are-up-against#2", "t": "Ask LPs their target vs. actual allocation before taking their money — their liquidity problem becomes your secondary-sale problem.", "guest": "Josh Wolfe", "slug": "wolfe-this-is-who-you-are-up-against", "date": "2018-02-13", "type": "VC"}, {"id": "dorsey-the-moat-portfolio#0", "t": "Long-term concentrated portfolios reward thesis depth on moats + capital allocation + option value—Facebook's WhatsApp optionality was heavily discounted by market despite management's monetization discipline and zero marginal cost.", "guest": "Pat Dorsey", "slug": "dorsey-the-moat-portfolio", "date": "2018-02-20", "type": "Hedge Fund"}, {"id": "dorsey-the-moat-portfolio#1", "t": "Vertical SaaS creates durable moats through switching costs + subscription revenue + human capital embeddedness; market systematically undervalues lifetime value uplift vs legacy software licensing.", "guest": "Pat Dorsey", "slug": "dorsey-the-moat-portfolio", "date": "2018-02-20", "type": "Hedge Fund"}, {"id": "dorsey-the-moat-portfolio#2", "t": "Zero marginal cost businesses (ads, SaaS) allow qualitative operator judgment on monetization pace to create edge—moderation of ad load to protect user engagement is contrarian signal of long-term thinking.", "guest": "Pat Dorsey", "slug": "dorsey-the-moat-portfolio", "date": "2018-02-20", "type": "Hedge Fund"}, {"id": "attia-peter-attia-live#1", "t": "Genetics can trump behavior—but you can't change parents. Gamify health metrics for real-time feedback loops; without tight feedback, delayed outcomes (decades away) won't change behavior.", "guest": "Peter Attia", "slug": "attia-peter-attia-live", "date": "2018-03-27", "type": "Scientist"}, {"id": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene#0", "t": "Identify 80/20 market splits: 15% optimizers (Peloton) vs. 85% behavior-change seekers. Build for the hard case. Larger TAM, higher adoption friction, higher moat.", "guest": "Brett Hoover & Taylor Greene (Ladder deep-dive)", "slug": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene", "date": "2018-04-17", "type": "Founder / Operator"}, {"id": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene#1", "t": "Institutional VC demands irrationality (mission, personal experience, world-changing vision). Founder psychology is the best predictor of long-term returns, not near-term exit size.", "guest": "Brett Hoover & Taylor Greene (Ladder deep-dive)", "slug": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene", "date": "2018-04-17", "type": "Founder / Operator"}, {"id": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene#2", "t": "Network effects require supply-side first. Enable professionals (coaches) to scale before chasing consumers. Compounding networks (Uber's Black→X→Pool→Eats model) beat horizontal play.", "guest": "Brett Hoover & Taylor Greene (Ladder deep-dive)", "slug": "maloley-shark-tank-with-thatcher-bell-and-taylor-greene", "date": "2018-04-17", "type": "Founder / Operator"}, {"id": "douvos-a-value-investor-lost-in-the-valley#0", "t": "Build concentrated venture portfolios of 12-20 companies with rigorous process; construct so any single investment can return the entire fund.", "guest": "Chris Douvos", "slug": "douvos-a-value-investor-lost-in-the-valley", "date": "2018-05-01", "type": "VC"}, {"id": "douvos-a-value-investor-lost-in-the-valley#1", "t": "Prioritize size discipline over track record—track record is lagging; watch for funds raising follow-on funds on perceived early success.", "guest": "Chris Douvos", "slug": "douvos-a-value-investor-lost-in-the-valley", "date": "2018-05-01", "type": "VC"}, {"id": "karp-opportunities-in-public-and-private-markets#0", "t": "Find value-with-growth at 12-16x earnings where cash flows compound; avoid deep value traps where 'cheap' means structurally broken.", "guest": "Jason Karp", "slug": "karp-opportunities-in-public-and-private-markets", "date": "2018-05-08", "type": "Hedge Fund"}, {"id": "karp-opportunities-in-public-and-private-markets#1", "t": "Allocate to public value only if you can hold 3-5 years for fundamentals to catch up; short-term dislocations from quants/passive are irresolvable.", "guest": "Jason Karp", "slug": "karp-opportunities-in-public-and-private-markets", "date": "2018-05-08", "type": "Hedge Fund"}, {"id": "hinkie-data-decisions-and-basketball#0", "t": "Asymmetric outcomes exist where uncertainty is highest—less measured, less consensus, and less data means more opportunity.", "guest": "Sam Hinkie", "slug": "hinkie-data-decisions-and-basketball", "date": "2018-05-22", "type": "Founder / Operator"}, {"id": "hinkie-data-decisions-and-basketball#1", "t": "Draft picks and young talent have asymmetric upside because long time horizons and uncertainty allow compounding.", "guest": "Sam Hinkie", "slug": "hinkie-data-decisions-and-basketball", "date": "2018-05-22", "type": "Founder / Operator"}, {"id": "hinkie-data-decisions-and-basketball#2", "t": "Contrarian positioning only works when genuinely misvalued; once consensus prices it in, you're at market rates.", "guest": "Sam Hinkie", "slug": "hinkie-data-decisions-and-basketball", "date": "2018-05-22", "type": "Founder / Operator"}, {"id": "zapata-the-darkest-night-lessons-from-battle-and-value-investing#0", "t": "Hard liquidation analysis protects downside; aggressively test balance sheets and discount for liquidation friction.", "guest": "Mike Zapata", "slug": "zapata-the-darkest-night-lessons-from-battle-and-value-investing", "date": "2018-05-29", "type": "Public Markets"}, {"id": "zapata-the-darkest-night-lessons-from-battle-and-value-investing#1", "t": "Small-cap inefficiency persists because most institutional capital cannot deploy at sub-$100M market caps.", "guest": "Mike Zapata", "slug": "zapata-the-darkest-night-lessons-from-battle-and-value-investing", "date": "2018-05-29", "type": "Public Markets"}, {"id": "zapata-the-darkest-night-lessons-from-battle-and-value-investing#2", "t": "Manager alignment via $1 salary and multi-year restricted stock is more reliable than stated strategic intent.", "guest": "Mike Zapata", "slug": "zapata-the-darkest-night-lessons-from-battle-and-value-investing", "date": "2018-05-29", "type": "Public Markets"}, {"id": "fontana-investing-in-artificial-intelligence#0", "t": "Virtuous loops where customers provide corrective feedback create sustainable advantage; fast followers cannot compete once established.", "guest": "Ash Fontana", "slug": "fontana-investing-in-artificial-intelligence", "date": "2018-06-05", "type": "VC"}, {"id": "fontana-investing-in-artificial-intelligence#1", "t": "AI-first product design captures strategic data rights; retrofitting AI later loses competitive advantage from renegotiation friction.", "guest": "Ash Fontana", "slug": "fontana-investing-in-artificial-intelligence", "date": "2018-06-05", "type": "VC"}, {"id": "reece-tim-cooks-dashboard#0", "t": "Use transaction-level alternative data to model business health at granular levels (cohorts, products, geographies) rather than relying on top-line metrics.", "guest": "Michael Reece", "slug": "reece-tim-cooks-dashboard", "date": "2018-06-12", "type": "Public Markets"}, {"id": "reece-tim-cooks-dashboard#2", "t": "Create a sustainable data moat by combining multiple overlapping data sources for confirmatory views and detecting which signals are real vs. noise.", "guest": "Michael Reece", "slug": "reece-tim-cooks-dashboard", "date": "2018-06-12", "type": "Public Markets"}, {"id": "balchunas-the-past-present-future-of-etfs#0", "t": "Recognize that the active/passive debate is reductive; most flows split between low-cost beta (Vanguard/BlackRock) and smart-beta indexes that are thinly disguised active strategies.", "guest": "Eric Balchunas", "slug": "balchunas-the-past-present-future-of-etfs", "date": "2018-06-26", "type": "Academic / Author"}, {"id": "balchunas-the-past-present-future-of-etfs#1", "t": "Understand the creation-redemption mechanism; this tax-deferral feature rivals low fees as a structural advantage and is unlikely to be legislated away.", "guest": "Eric Balchunas", "slug": "balchunas-the-past-present-future-of-etfs", "date": "2018-06-26", "type": "Academic / Author"}, {"id": "mclean-business-gone-bad-and-the-art-of-persistence#0", "t": "Apply journalistic rigor to due diligence: ask uncomfortable questions, follow the money, talk to insiders, and verify claims independently.", "guest": "Bethany McLean", "slug": "mclean-business-gone-bad-and-the-art-of-persistence", "date": "2018-07-24", "type": "Other"}, {"id": "mclean-business-gone-bad-and-the-art-of-persistence#1", "t": "Misaligned incentives in executive comp + pressure to hit numbers = precursor to fraud; culture and narrative matter as much as fundamentals.", "guest": "Bethany McLean", "slug": "mclean-business-gone-bad-and-the-art-of-persistence", "date": "2018-07-24", "type": "Other"}, {"id": "beshore-what-you-learn-about-business#0", "t": "In cyclical businesses, avoid leverage and vertical integration in up cycles. Keep models capital-light to survive down cycles and acquire distressed competitors.", "guest": "Brent Beshore", "slug": "beshore-what-you-learn-about-business", "date": "2018-08-21", "type": "PE / Buyout"}, {"id": "beshore-what-you-learn-about-business#1", "t": "Structure and flexibility beat aggressive leverage returns. Simple deal terms (no Mezz debt, friendly seller notes) attract family businesses and enable permanent ownership.", "guest": "Brent Beshore", "slug": "beshore-what-you-learn-about-business", "date": "2018-08-21", "type": "PE / Buyout"}, {"id": "gil-how-to-identify-interesting-markets#0", "t": "Market selection is #1. Evaluate market first, then team, then likeability. A great market with mediocre team beats opposite.", "guest": "Elad Gil", "slug": "gil-how-to-identify-interesting-markets", "date": "2018-08-28", "type": "Founder / Operator"}, {"id": "gil-how-to-identify-interesting-markets#1", "t": "Three types of non-obvious markets: new tech waves, crowded-looking markets with poor existing products, and distribution/channel openings.", "guest": "Elad Gil", "slug": "gil-how-to-identify-interesting-markets", "date": "2018-08-28", "type": "Founder / Operator"}, {"id": "gil-how-to-identify-interesting-markets#3", "t": "Power users can carry entire business early on. Identify, delight, then expand to mainstream via crossing-the-chasm playbook.", "guest": "Elad Gil", "slug": "gil-how-to-identify-interesting-markets", "date": "2018-08-28", "type": "Founder / Operator"}, {"id": "gil-how-to-identify-interesting-markets#4", "t": "Distribution is underrated. Find one channel that works, saturate it, then broaden. One channel >> multiple weak channels.", "guest": "Elad Gil", "slug": "gil-how-to-identify-interesting-markets", "date": "2018-08-28", "type": "Founder / Operator"}, {"id": "craib-crowdsourcing-predictive-algorithms#0", "t": "Data quality > algorithm sophistication. Long, clean historical data beats alternative or cutting-edge data sources.", "guest": "Richard Craib", "slug": "craib-crowdsourcing-predictive-algorithms", "date": "2018-09-04", "type": "Founder / Operator"}, {"id": "craib-crowdsourcing-predictive-algorithms#1", "t": "Cryptocurrency staking as incentive dramatically improves prediction quality (sharpe 1.5→2.1); skin-in-game is powerful.", "guest": "Richard Craib", "slug": "craib-crowdsourcing-predictive-algorithms", "date": "2018-09-04", "type": "Founder / Operator"}, {"id": "minshew-how-employers-and-employees-should-build-careers#2", "t": "Candidate experience predicts employee success. Those treated well during hiring stay longer and perform better.", "guest": "Kathryn Minshew", "slug": "minshew-how-employers-and-employees-should-build-careers", "date": "2018-09-11", "type": "Founder / Operator"}, {"id": "minshew-how-employers-and-employees-should-build-careers#3", "t": "Interview optimization: 4-5 rounds max, 3-4 week timeline. Speed + respect closes top talent before competitors do.", "guest": "Kathryn Minshew", "slug": "minshew-how-employers-and-employees-should-build-careers", "date": "2018-09-11", "type": "Founder / Operator"}, {"id": "oshaughnessy-lessons-from-two-years-of-the-podcast#0", "t": "Focus on downside risk mitigation and avoiding known pitfalls rather than predicting what will work—the unknown reasons for success vastly outnumber predictable ones.", "guest": "Trail Magic", "slug": "oshaughnessy-lessons-from-two-years-of-the-podcast", "date": "2018-09-18", "type": "Other"}, {"id": "oshaughnessy-lessons-from-two-years-of-the-podcast#2", "t": "Distinguish true investors from yellow blazers by asking deep, specific questions; surface-level smooth talkers lack the compound discoveries of real inquiry.", "guest": "Trail Magic", "slug": "oshaughnessy-lessons-from-two-years-of-the-podcast", "date": "2018-09-18", "type": "Other"}, {"id": "lowin-machine-learning-in-investing#1", "t": "Data quality and feature engineering are 90% of the game—model architecture is secondary. Spend time on clean, unique, well-curated data.", "guest": "Jeremiah Lowin", "slug": "lowin-machine-learning-in-investing", "date": "2018-09-25", "type": "Founder / Operator"}, {"id": "lowin-machine-learning-in-investing#2", "t": "Test on time-series data by splitting on time, not randomly. Models can cheat by learning patterns only visible in the future; keep your test set truly unseen.", "guest": "Jeremiah Lowin", "slug": "lowin-machine-learning-in-investing", "date": "2018-09-25", "type": "Founder / Operator"}, {"id": "moses-pot-stocks-tesla-the-wild-bill-rule-for-quants#0", "t": "Cannabis sector: understand state-by-state regulatory dynamics, scarcity value, and vertical integration. Don't chase hyped stocks; focus on survivors with capital and execution.", "guest": "Danny Moses", "slug": "moses-pot-stocks-tesla-the-wild-bill-rule-for-quants", "date": "2018-09-28", "type": "Hedge Fund"}, {"id": "moses-pot-stocks-tesla-the-wild-bill-rule-for-quants#1", "t": "On Tesla/misclassified companies: analyze where earnings actually originate (industrial, not tech), ignore narrative. Look at balance sheet deterioration and key person exit rates as early warnings.", "guest": "Danny Moses", "slug": "moses-pot-stocks-tesla-the-wild-bill-rule-for-quants", "date": "2018-09-28", "type": "Hedge Fund"}, {"id": "hamed-esoteric-credit-with-ali-hamed-brian-harwitt-and-marc-porzecanski#0", "t": "Lend against assets with unique data advantages or distribution barriers, not just better underwriting of existing products.", "guest": "Ali Hamed & Brian Harwitt & Marc Porzecanski", "slug": "hamed-esoteric-credit-with-ali-hamed-brian-harwitt-and-marc-porzecanski", "date": "2018-10-16", "type": "PE / Buyout"}, {"id": "hamed-esoteric-credit-with-ali-hamed-brian-harwitt-and-marc-porzecanski#1", "t": "Short-duration, low-LTV lending with strong repayment mechanisms (payroll deduction, POS integration) outperforms long-duration high-LTV.", "guest": "Ali Hamed & Brian Harwitt & Marc Porzecanski", "slug": "hamed-esoteric-credit-with-ali-hamed-brian-harwitt-and-marc-porzecanski", "date": "2018-10-16", "type": "PE / Buyout"}, {"id": "lindzon-fintech-and-trend-following#1", "t": "Find teams with engineering or design chops who can hide complex infrastructure behind simple UIs.", "guest": "Howard Lindzon", "slug": "lindzon-fintech-and-trend-following", "date": "2018-10-23", "type": "VC"}, {"id": "caldbeck-quant-in-private-markets#1", "t": "Small data signals (packaging words, social sentiment, engagement rate) often outpredict human intuition and conventional metrics.", "guest": "Ryan Caldbeck", "slug": "caldbeck-quant-in-private-markets", "date": "2018-10-30", "type": "VC"}, {"id": "caldbeck-quant-in-private-markets#2", "t": "Offline retail distribution remains far more predictive of scaling than D2C/online; build for physical retail presence.", "guest": "Ryan Caldbeck", "slug": "caldbeck-quant-in-private-markets", "date": "2018-10-30", "type": "VC"}, {"id": "krug-high-yield-credit-investing#1", "t": "Forced selling from ratings downgrades (BBB to BB) is predictable technical dislocation; smart investors use this structural inefficiency to buy.", "guest": "Bryan Krug", "slug": "krug-high-yield-credit-investing", "date": "2018-12-11", "type": "PE / Buyout"}, {"id": "krug-high-yield-credit-investing#2", "t": "Portfolio diversification should favor cashflow-generating businesses (software, insurance brokers) over asset-heavy commodities that can crater in downturns.", "guest": "Bryan Krug", "slug": "krug-high-yield-credit-investing", "date": "2018-12-11", "type": "PE / Buyout"}, {"id": "rabois-if-you-cant-sell-them-compete-with-them#0", "t": "Look for founders who are talent magnets: call their former colleagues to gauge their ability to recruit. Hesitation is a red flag; enthusiasm is green.", "guest": "Keith Rabois", "slug": "rabois-if-you-cant-sell-them-compete-with-them", "date": "2018-12-18", "type": "VC"}, {"id": "rabois-if-you-cant-sell-them-compete-with-them#1", "t": "Evaluate capital efficiency by asking if it unlocks breakthrough results (10x) or just incremental progress (10%). Early-stage breakthroughs often justify high spend.", "guest": "Keith Rabois", "slug": "rabois-if-you-cant-sell-them-compete-with-them", "date": "2018-12-18", "type": "VC"}, {"id": "johnson-future-of-finance#0", "t": "Asset management will consolidate into barbell: mega-scale (distribution + economies) and niche specialists (pure alpha track record). Mid-market $50B managers most at risk.", "guest": "Abby Johnson, Tom Jessop, & Vipin Mayar", "slug": "johnson-future-of-finance", "date": "2019-01-08", "type": "Public-Co CEO"}, {"id": "johnson-future-of-finance#1", "t": "Fintech wins on UX and millennial acquisition, but long-term value depends on monetization model and customer lifetime value, not user count.", "guest": "Abby Johnson, Tom Jessop, & Vipin Mayar", "slug": "johnson-future-of-finance", "date": "2019-01-08", "type": "Public-Co CEO"}, {"id": "wasserman-real-estate-investing#0", "t": "Buy multifamily apartments in recession/post-recession: when rents drop 20-30% peak-to-trough in weak markets like Phoenix 2009, prices are cheap, recovery is inevitable.", "guest": "Keith Wasserman", "slug": "wasserman-real-estate-investing", "date": "2019-02-05", "type": "Founder / Operator"}, {"id": "wasserman-real-estate-investing#2", "t": "Manufactured housing (mobile home parks) beats apartments now: no new supply, high cashflow (8-16% cash-on-cash), residents own homes so parks own only the lot—recession-proof.", "guest": "Keith Wasserman", "slug": "wasserman-real-estate-investing", "date": "2019-02-05", "type": "Founder / Operator"}, {"id": "danco-scarcity-abundance-and-bubbles#0", "t": "Identify emerging scarcities: as technology solves old bottlenecks, new scarcities emerge (regulation, coordination, attention). Winners and moats cluster around new scarcities.", "guest": "Alex Danco", "slug": "danco-scarcity-abundance-and-bubbles", "date": "2019-02-12", "type": "VC"}, {"id": "danco-scarcity-abundance-and-bubbles#2", "t": "Avoid competitive traps: many tech markets are undifferentiated Red Queen races where similarity forces constant acceleration. Seek pointy/differentiated functions, not product battles.", "guest": "Alex Danco", "slug": "danco-scarcity-abundance-and-bubbles", "date": "2019-02-12", "type": "VC"}, {"id": "kitces-the-past-present-future-of-financial-advice#0", "t": "Business model beats regulation: regulated fixed commissions (pre-1975) blocked innovation and competition. Deregulation + technology created a 90% cost reduction in 20 years—far more impactful than client preferences.", "guest": "Michael Kitces", "slug": "kitces-the-past-present-future-of-financial-advice", "date": "2019-02-26", "type": "Founder / Operator"}, {"id": "kitces-the-past-present-future-of-financial-advice#2", "t": "AUM fees compress relentlessly; specialize to survive: as pure asset management commoditizes (0.25-0.5% at scale), advisors must own unique expertise (tax, psychology, niche planning) to justify fees.", "guest": "Michael Kitces", "slug": "kitces-the-past-present-future-of-financial-advice", "date": "2019-02-26", "type": "Founder / Operator"}, {"id": "zeihan-the-future-of-geopolitics#1", "t": "Capital will flee disorder zones (Europe, Asia, Middle East) to US & NAFTA; currency/bond rotation into USD inevitable.", "guest": "Peter Zeihan", "slug": "zeihan-the-future-of-geopolitics", "date": "2019-03-05", "type": "Academic / Author"}, {"id": "zeihan-the-future-of-geopolitics#2", "t": "Precision agriculture & automation lift yields while cutting input cost; farm productivity gains compound for decades.", "guest": "Peter Zeihan", "slug": "zeihan-the-future-of-geopolitics", "date": "2019-03-05", "type": "Academic / Author"}, {"id": "zeihan-the-future-of-geopolitics#3", "t": "Supply chain fragmentation creates opportunity for regionalized manufacturing; bet on North America integration, not global arbitrage.", "guest": "Peter Zeihan", "slug": "zeihan-the-future-of-geopolitics", "date": "2019-03-05", "type": "Academic / Author"}, {"id": "mayer-pseudonymous-social-capital-and-bottomless-coffee#1", "t": "Marketplace platforms that own customer relationship capture all supplier leverage; roasters become commodities.", "guest": "Michael Mayer", "slug": "mayer-pseudonymous-social-capital-and-bottomless-coffee", "date": "2019-03-12", "type": "Founder / Operator"}, {"id": "mayer-pseudonymous-social-capital-and-bottomless-coffee#2", "t": "Hardware as moat: free scale subsidized by margins on coffee creates switching cost unmatched by software.", "guest": "Michael Mayer", "slug": "mayer-pseudonymous-social-capital-and-bottomless-coffee", "date": "2019-03-12", "type": "Founder / Operator"}, {"id": "mayer-pseudonymous-social-capital-and-bottomless-coffee#3", "t": "Bundling creates zero-marginal-cost expansion; future products push free through existing shipment channel.", "guest": "Michael Mayer", "slug": "mayer-pseudonymous-social-capital-and-bottomless-coffee", "date": "2019-03-12", "type": "Founder / Operator"}, {"id": "duke-wanna-bet#0", "t": "Separate decision quality from outcome quality; most financial regret is resulting (blaming good strategy for bad luck).", "guest": "Annie Duke", "slug": "duke-wanna-bet", "date": "2019-03-19", "type": "Academic / Author"}, {"id": "duke-wanna-bet#2", "t": "Probability thinking beats deterministic thinking; 'do you want to bet?' reveals overconfidence and forces calibration.", "guest": "Annie Duke", "slug": "duke-wanna-bet", "date": "2019-03-19", "type": "Academic / Author"}, {"id": "duke-wanna-bet#3", "t": "Gather feedback before outcomes, not after; outcomes cognitively contaminate others' ability to evaluate decisions fairly.", "guest": "Annie Duke", "slug": "duke-wanna-bet", "date": "2019-03-19", "type": "Academic / Author"}, {"id": "duke-wanna-bet#4", "t": "Transparency into decision logic reduces outcome bias; showing your process lets group catch blind spots.", "guest": "Annie Duke", "slug": "duke-wanna-bet", "date": "2019-03-19", "type": "Academic / Author"}, {"id": "mauboussin-the-four-sources-of-alpha#0", "t": "Before every trade, ask who is on the other side and which BAIT bucket supplies their error — if you can't name it, you don't have edge", "guest": "Michael Mauboussin", "slug": "mauboussin-the-four-sources-of-alpha", "date": "2019-03-26", "type": "Academic / Author"}, {"id": "mauboussin-the-four-sources-of-alpha#1", "t": "Structure capital to arrive at extremes: Ulysses contracts and pre-committed calls beat courage, because principals never want to write the check when spreads gap", "guest": "Michael Mauboussin", "slug": "mauboussin-the-four-sources-of-alpha", "date": "2019-03-26", "type": "Academic / Author"}, {"id": "mauboussin-the-four-sources-of-alpha#2", "t": "Score your theses like a meteorologist — probabilistic signposts with deadlines (Brier scores) turn noisy multi-year feedback into a learnable loop", "guest": "Michael Mauboussin", "slug": "mauboussin-the-four-sources-of-alpha", "date": "2019-03-26", "type": "Academic / Author"}, {"id": "collins-impact-and-esg-investing#0", "t": "Material, relevant ESG issues properly weighted can generate 700+ basis points of alpha; Serafeim's study proved plain-vanilla ESG underperforms, but material-weighted ESG massively outperforms.", "guest": "Katherine Collins", "slug": "collins-impact-and-esg-investing", "date": "2019-04-16", "type": "Public Markets"}, {"id": "collins-impact-and-esg-investing#2", "t": "ESG must be integrated into core investment process; separate ESG teams generate compliance, not alpha—integration into daily fundamental work is essential.", "guest": "Katherine Collins", "slug": "collins-impact-and-esg-investing", "date": "2019-04-16", "type": "Public Markets"}, {"id": "wolfe-the-tech-imperative#0", "t": "Founders, not white-space analysis: bet on the person's ability to execute, raise money, and recruit talent. Top-down models for frontier tech are usually wrong by orders of magnitude.", "guest": "Josh Wolfe", "slug": "wolfe-the-tech-imperative", "date": "2019-04-23", "type": "VC"}, {"id": "wolfe-the-tech-imperative#2", "t": "Watch for cultural panic ('it will rot your brain') as a leading indicator of $10B+ markets; video-game-playing kids became drone pilots and robotic surgeons.", "guest": "Josh Wolfe", "slug": "wolfe-the-tech-imperative", "date": "2019-04-23", "type": "VC"}, {"id": "cohen-the-evolution-of-ma-and-corporate-strategy#0", "t": "M&A fails when it chases growth to meet expectations rather than executing defined strategy; 'we need to grow' is not a thesis.", "guest": "Stephanie Cohen", "slug": "cohen-the-evolution-of-ma-and-corporate-strategy", "date": "2019-05-07", "type": "Public-Co CEO"}, {"id": "cohen-the-evolution-of-ma-and-corporate-strategy#1", "t": "Synergies must be concrete and disciplined, not wishful; relational/cultural fit matters as much as financial models in determining success.", "guest": "Stephanie Cohen", "slug": "cohen-the-evolution-of-ma-and-corporate-strategy", "date": "2019-05-07", "type": "Public-Co CEO"}, {"id": "parker-the-art-of-gathering#1", "t": "Boundaries and rules, when tied to legitimate purpose, attract higher-quality participants and outcomes than open-ended inclusivity.", "guest": "Priya Parker", "slug": "parker-the-art-of-gathering", "date": "2019-05-21", "type": "Academic / Author"}, {"id": "epstein-wide-or-deep#1", "t": "Feedback loops in stable, rule-based systems are reliable; in dynamic markets, invest cautiously in what 'feels' obviously correct—hidden feedback often teaches wrong lessons.", "guest": "David Epstein", "slug": "epstein-wide-or-deep", "date": "2019-05-28", "type": "Academic / Author"}, {"id": "epstein-wide-or-deep#2", "t": "Constraint breeds innovation; leaders and companies that solve problems with limited resources (withered tech) often outcompete high-complexity alternatives.", "guest": "David Epstein", "slug": "epstein-wide-or-deep", "date": "2019-05-28", "type": "Academic / Author"}, {"id": "neumann-why-venture-is-hard#1", "t": "The grace period from competition shrinks as markets mature; invest earliest when ambiguity is highest and capital most abundant.", "guest": "Jerry Neumann", "slug": "neumann-why-venture-is-hard", "date": "2019-06-11", "type": "VC"}, {"id": "neumann-why-venture-is-hard#2", "t": "Value chain analysis reveals profit sustainability; a startup capturing only 5% of total ecosystem value will struggle to achieve venture returns, regardless of growth.", "guest": "Jerry Neumann", "slug": "neumann-why-venture-is-hard", "date": "2019-06-11", "type": "VC"}, {"id": "akre-the-three-legged-stool#0", "t": "Understand the true economics and distribution model of a business before analyzing its financials. Bandag wasn't truly in the tire business—it was in franchise dealer loyalty.", "guest": "Chuck Akre", "slug": "akre-the-three-legged-stool", "date": "2019-06-18", "type": "Public Markets"}, {"id": "akre-the-three-legged-stool#1", "t": "Look for businesses that can reinvest capital at high rates of return indefinitely. This single factor drives 100x returns over decades more than any other.", "guest": "Chuck Akre", "slug": "akre-the-three-legged-stool", "date": "2019-06-18", "type": "Public Markets"}, {"id": "akre-the-three-legged-stool#3", "t": "Pricing power derived from essential infrastructure (like tower companies) or high switching costs creates sustainable competitive advantages that compound over time.", "guest": "Chuck Akre", "slug": "akre-the-three-legged-stool", "date": "2019-06-18", "type": "Public Markets"}, {"id": "livermore-the-search-for-the-truth-with-the-anonymous-master#0", "t": "Inflation distorts earnings metrics profoundly. Use free cash flow instead of accounting earnings to see the true economics. Adjust for inflation-driven depreciation understatement in historical cost accounting.", "guest": "Jesse Livermore", "slug": "livermore-the-search-for-the-truth-with-the-anonymous-master", "date": "2019-06-25", "type": "Other"}, {"id": "livermore-the-search-for-the-truth-with-the-anonymous-master#1", "t": "Trend investing's success depends on deep drawdowns. In low-volatility, Fed-supported markets, trend may underperform. Consider recession probability overlays to avoid whipsaws.", "guest": "Jesse Livermore", "slug": "livermore-the-search-for-the-truth-with-the-anonymous-master", "date": "2019-06-25", "type": "Other"}, {"id": "livermore-the-search-for-the-truth-with-the-anonymous-master#3", "t": "Call your statistical shot before testing. Multiple comparison bias—accidentally p-hacking through many hypotheses—is invisible but ruins conclusions. Test out of sample or in different regimes to validate.", "guest": "Jesse Livermore", "slug": "livermore-the-search-for-the-truth-with-the-anonymous-master", "date": "2019-06-25", "type": "Other"}, {"id": "gurley-all-things-business-and-investing#0", "t": "Test every marketplace with the value-vs-penetration curve — a flat curve means fragmentation, not winner-take-all, no matter what the deck claims", "guest": "Bill Gurley", "slug": "gurley-all-things-business-and-investing", "date": "2019-07-02", "type": "VC"}, {"id": "gurley-all-things-business-and-investing#1", "t": "Heavy paid marketing that never tips organic marks a lead-gen business worth 1-2x revenue, not a network effect", "guest": "Bill Gurley", "slug": "gurley-all-things-business-and-investing", "date": "2019-07-02", "type": "VC"}, {"id": "gurley-all-things-business-and-investing#2", "t": "Cash flow relative to earnings drives multiples in the end — capital-intensive startups priced like software will disappoint everyone at the exit", "guest": "Bill Gurley", "slug": "gurley-all-things-business-and-investing", "date": "2019-07-02", "type": "VC"}, {"id": "mcgonigal-how-games-make-life-better#0", "t": "Games create rapid feedback loops that accelerate skill development and identity formation—the opposite of real-world delays that reduce motivation.", "guest": "Jane McGonigal", "slug": "mcgonigal-how-games-make-life-better", "date": "2019-07-16", "type": "Academic / Author"}, {"id": "sorensen-how-quant-evolves#1", "t": "Risk parity only works when asset correlations are low; when they converge (crashes), diversification fails—diversified portfolios require periods of disappointment.", "guest": "Eric Sorensen", "slug": "sorensen-how-quant-evolves", "date": "2019-07-23", "type": "Public Markets"}, {"id": "sorensen-how-quant-evolves#2", "t": "Portfolio construction (how you weight factors and allocate risk) drives more alpha than finding individual factors; most edge is structural.", "guest": "Eric Sorensen", "slug": "sorensen-how-quant-evolves", "date": "2019-07-23", "type": "Public Markets"}, {"id": "christian-how-to-live-with-computers#0", "t": "Explore/exploit tradeoff applies to capital allocation and career strategy: more time horizon justifies more R&D; shorter timeline justifies dividends and buybacks.", "guest": "Brian Christian", "slug": "christian-how-to-live-with-computers", "date": "2019-07-30", "type": "Academic / Author"}, {"id": "gurley-direct-listing-vs-ipo#0", "t": "Traditional IPO underpricing costs founders and employees $12B+ annually through hand-allocated pricing; direct listings eliminate this single-day wealth transfer using fairer algorithms.", "guest": "Bill Gurley", "slug": "gurley-direct-listing-vs-ipo", "date": "2019-09-24", "type": "VC"}, {"id": "gurley-direct-listing-vs-ipo#1", "t": "Privileged access concentrates to 10 accounts (of 9,000 mutual funds) who capture $171B over 40 years; most buy-side firms get 1% of desired positions even as long-term believers.", "guest": "Bill Gurley", "slug": "gurley-direct-listing-vs-ipo", "date": "2019-09-24", "type": "VC"}, {"id": "cascarilla-the-future-of-blockchain-and-financial-services#0", "t": "Financial services sector structural decline (30% to 15% of S&P over 20 years) from higher capital requirements + lower rates; blockchain-based products can disintermediate incumbent banks.", "guest": "Chad Cascarilla", "slug": "cascarilla-the-future-of-blockchain-and-financial-services", "date": "2019-10-29", "type": "Founder / Operator"}, {"id": "cascarilla-the-future-of-blockchain-and-financial-services#1", "t": "Outside assets (gold, Bitcoin, real estate) essential for tail-risk protection; tokenization enables 24/7 access with minimal fees, vs traditional assets locked in 9-5 markets.", "guest": "Chad Cascarilla", "slug": "cascarilla-the-future-of-blockchain-and-financial-services", "date": "2019-10-29", "type": "Founder / Operator"}, {"id": "rzepecki-investing-in-africa#0", "t": "Foundational infrastructure gaps (food, payments, logistics) create outsized returns; companies solving $200B+ TAM with 50-90% valuation discount to US peers.", "guest": "George Rzepecki", "slug": "rzepecki-investing-in-africa", "date": "2019-11-05", "type": "VC"}, {"id": "rzepecki-investing-in-africa#2", "t": "China's multi-decade capital strategy (60B per 3-year cycle) creates enabling infrastructure for next-generation VC investments; US capital less active at this stage.", "guest": "George Rzepecki", "slug": "rzepecki-investing-in-africa", "date": "2019-11-05", "type": "VC"}, {"id": "ek-the-future-of-audio#0", "t": "Bifurcation thesis: globalization and digitization eliminate the middle market; winners are either mega-scale or profitable niches. Mid-market strategy is vaporized.", "guest": "Daniel Ek", "slug": "ek-the-future-of-audio", "date": "2019-11-12", "type": "Founder / Operator"}, {"id": "ek-the-future-of-audio#1", "t": "True addressable market often vastly exceeds current penetration. Spotify sees 2-3B person audio market, is <3% penetrated = 10-15x growth potential.", "guest": "Daniel Ek", "slug": "ek-the-future-of-audio", "date": "2019-11-12", "type": "Founder / Operator"}, {"id": "krieger-how-to-build-a-great-product#1", "t": "Early hiring discipline: scale your team in lockstep with growth. Waiting to hire until overloaded creates compounding problems that multiply faster than hiring can fix.", "guest": "Kevin Systrom & Mike Krieger", "slug": "krieger-how-to-build-a-great-product", "date": "2019-11-19", "type": "Founder / Operator"}, {"id": "krieger-how-to-build-a-great-product#2", "t": "Focus ruthlessly on product during critical periods. Say no to everything external (meetings, investors) if it costs shipping velocity. Product-market fit is worth 4 months of radio silence.", "guest": "Kevin Systrom & Mike Krieger", "slug": "krieger-how-to-build-a-great-product", "date": "2019-11-19", "type": "Founder / Operator"}, {"id": "baker-tech-and-consumer-growth-investing#0", "t": "Invest where disruption is still accelerating. The microchip was invented in 1959; peak disruption won't arrive until 2030-2050. Today's tech/consumer growth are early innings.", "guest": "Gavin Baker", "slug": "baker-tech-and-consumer-growth-investing", "date": "2019-11-26", "type": "Public Markets"}, {"id": "baker-tech-and-consumer-growth-investing#1", "t": "High ROIC with growing competitive advantages at 5-7 year horizon beats valuation compression. Scale is the moat; mean reversion is broken by regulatory capture.", "guest": "Gavin Baker", "slug": "baker-tech-and-consumer-growth-investing", "date": "2019-11-26", "type": "Public Markets"}, {"id": "tan-quality-and-innovation#0", "t": "Companies with distinctive quality philosophies (Apple, Pixar) command premium valuations due to brand loyalty and pricing power.", "guest": "Vaughn Tan", "slug": "tan-quality-and-innovation", "date": "2019-12-03", "type": "Academic / Author"}, {"id": "ma-making-decisions-with-data#0", "t": "Look for markets where participants systematically misprice value; competitive advantage often lies in accurate probability assessment.", "guest": "Jeff Ma", "slug": "ma-making-decisions-with-data", "date": "2019-12-10", "type": "Public Markets"}, {"id": "ma-making-decisions-with-data#1", "t": "Build teams and systems that can tolerate variance and drawdowns without panic, as long-term returns require surviving volatility.", "guest": "Jeff Ma", "slug": "ma-making-decisions-with-data", "date": "2019-12-10", "type": "Public Markets"}, {"id": "savage-all-things-fintech-investing#0", "t": "Look for fintech where regulation limits incumbent competition or creates artificial pricing power that disruption can exploit.", "guest": "Ben Savage", "slug": "savage-all-things-fintech-investing", "date": "2019-12-17", "type": "VC"}, {"id": "savage-all-things-fintech-investing#1", "t": "Focus on opportunities that expand investable assets or market access, not just reducing costs in existing markets.", "guest": "Ben Savage", "slug": "savage-all-things-fintech-investing", "date": "2019-12-17", "type": "VC"}, {"id": "clifford-investing-pre-company#1", "t": "Cheap early capital creates better long-term outcomes by forcing focus and capital efficiency through the critical early years.", "guest": "Matt Clifford", "slug": "clifford-investing-pre-company", "date": "2020-01-14", "type": "Founder / Operator"}, {"id": "clifford-investing-pre-company#2", "t": "Deep tech requires different management playbooks: longer runways, higher capital reserves, founder persistence over 10+ year cycles.", "guest": "Matt Clifford", "slug": "clifford-investing-pre-company", "date": "2020-01-14", "type": "Founder / Operator"}, {"id": "kaden-thesis-driven-investing#1", "t": "Female founder and investor networks provide durable edge: mentorship, honest feedback, co-investment, and career integration wisdom.", "guest": "Rebecca Kaden", "slug": "kaden-thesis-driven-investing", "date": "2020-01-21", "type": "VC"}, {"id": "kaden-thesis-driven-investing#2", "t": "Access and distribution inefficiencies are the largest alpha source; build moats around who gets information and opportunity first.", "guest": "Rebecca Kaden", "slug": "kaden-thesis-driven-investing", "date": "2020-01-21", "type": "VC"}, {"id": "puttagunta-go-slow-to-go-fast-software-building-and-investing#1", "t": "Cloud infrastructure still has massive upside: AWS at 59% YoY growth off a huge base shows trillion-dollar enterprise IT spend is mostly still on-premise", "guest": "Chetan Puttagunta", "slug": "puttagunta-go-slow-to-go-fast-software-building-and-investing", "date": "2020-01-28", "type": "VC"}, {"id": "puttagunta-go-slow-to-go-fast-software-building-and-investing#2", "t": "Build software solutions for underserved use cases before competing head-on with incumbents; Salesforce and Siebel rarely saw each other directly", "guest": "Chetan Puttagunta", "slug": "puttagunta-go-slow-to-go-fast-software-building-and-investing", "date": "2020-01-28", "type": "VC"}, {"id": "canner-become-a-perfect-instrument#1", "t": "Building culture as a competitive moat requires early deliberate choices about differentiation—not retrofitting it later", "guest": "Niko Canner", "slug": "canner-become-a-perfect-instrument", "date": "2020-02-25", "type": "Founder / Operator"}, {"id": "canner-become-a-perfect-instrument#2", "t": "The Red Test reveals management quality better than any metric: do leaders explicitly discuss and act on what's off-track?", "guest": "Niko Canner", "slug": "canner-become-a-perfect-instrument", "date": "2020-02-25", "type": "Founder / Operator"}, {"id": "lawson-how-to-build-a-platform#0", "t": "Platform businesses unlock observation-based product discovery; developers' actual usage patterns reveal unmet market segments", "guest": "Jeff Lawson", "slug": "lawson-how-to-build-a-platform", "date": "2020-03-03", "type": "Founder / Operator"}, {"id": "lawson-how-to-build-a-platform#2", "t": "Developer-first businesses have 10x leverage: APIs reduce friction for thousands of companies versus point solutions to hundreds", "guest": "Jeff Lawson", "slug": "lawson-how-to-build-a-platform", "date": "2020-03-03", "type": "Founder / Operator"}, {"id": "zeihan-disunited-nations#0", "t": "Companies treating COVID supply-chain disruption as permanent structural change (Mexico, diversification plays) outperform those treating it as temporary (Apple, China-dependent). Watch behavioral response to crisis.", "guest": "Peter Zeihan", "slug": "zeihan-disunited-nations", "date": "2020-03-10", "type": "Academic / Author"}, {"id": "zeihan-disunited-nations#1", "t": "In a deglobalizing world, invest in producers with territorial self-sufficiency: Argentina (agriculture, energy), Mexico (manufacturing proximity), Japan (isolation + capability) beat Germany/China-dependent models.", "guest": "Peter Zeihan", "slug": "zeihan-disunited-nations", "date": "2020-03-10", "type": "Academic / Author"}, {"id": "smith-oil-price-war-and-its-implications#0", "t": "Shale crash reveals structural winners (capital-efficient, clean ops) vs. losers (overleveraged, high-cost). Only winners merit capital post-correction; others are value traps.", "guest": "Matt Smith & Ian Singer & Kobi Platt", "slug": "smith-oil-price-war-and-its-implications", "date": "2020-03-11", "type": "Hedge Fund"}, {"id": "smith-oil-price-war-and-its-implications#1", "t": "Energy valuation requires forward-curve NAV with downside stress, not book value or P/B. Impairments are hidden in annual filings; anticipate them.", "guest": "Matt Smith & Ian Singer & Kobi Platt", "slug": "smith-oil-price-war-and-its-implications", "date": "2020-03-11", "type": "Hedge Fund"}, {"id": "krug-an-update-on-corporate-credit#1", "t": "Energy credit at 40-50 cents on dollar offers 500%+ upside if oil recovers to $50-55, but requires conviction COVID is transitory (1-2 quarters, cure within 12mo). Don't assume government bailouts.", "guest": "Bryan Krug", "slug": "krug-an-update-on-corporate-credit", "date": "2020-03-12", "type": "Public Markets"}, {"id": "krug-an-update-on-corporate-credit#2", "t": "Credit spreads (IG/HY, loan prices) lead equity moves during crises. Equity investors should watch bond market as early warning—spreads at 660+ bps signal attractive risk-reward before equities find a floor.", "guest": "Bryan Krug", "slug": "krug-an-update-on-corporate-credit", "date": "2020-03-12", "type": "Public Markets"}, {"id": "gurley-an-update-on-consumer-enterprise-venture-capital#1", "t": "Enterprise software survives crises better than consumer—focus on cash cycles, customer payment terms, and deepening value propositions rather than chasing new logos", "guest": "Bill Gurley & Chetan Puttagunta", "slug": "gurley-an-update-on-consumer-enterprise-venture-capital", "date": "2020-03-13", "type": "VC"}, {"id": "gurley-an-update-on-consumer-enterprise-venture-capital#2", "t": "Never do 5-10% layoffs; the cultural pain outweighs savings. If cutting headcount, do it decisively at a level that extends runway significantly", "guest": "Bill Gurley & Chetan Puttagunta", "slug": "gurley-an-update-on-consumer-enterprise-venture-capital", "date": "2020-03-13", "type": "VC"}, {"id": "rasmussen-investing-through-a-crisis#0", "t": "Value factor works 70-80% of crises vs 55% in bull markets—buy cheap, cash-generative companies with high ROE when spreads spike to 650+ bps", "guest": "Dan Rasmussen", "slug": "rasmussen-investing-through-a-crisis", "date": "2020-03-16", "type": "Hedge Fund"}, {"id": "rasmussen-investing-through-a-crisis#2", "t": "Small-caps rally earliest when liquidity returns; 1932-1936 small-caps up 800% vs 12-year recovery for large-cap to 1929 peak", "guest": "Dan Rasmussen", "slug": "rasmussen-investing-through-a-crisis", "date": "2020-03-16", "type": "Hedge Fund"}, {"id": "beshore-update-on-small-business-and-private-equity#0", "t": "Unlevered PE structures weather crises better than leveraged—2x EBITDA leverage becomes unsustainable when EBITDA collapses; equity infusion required or asset sales ensue", "guest": "Brent Beshore", "slug": "beshore-update-on-small-business-and-private-equity", "date": "2020-03-20", "type": "PE / Buyout"}, {"id": "beshore-update-on-small-business-and-private-equity#2", "t": "Long-amortized debt (10-30 year terms) at 3% interest with 1-year payment holiday bridges solvency gaps without permanent equity impairment or forcing business closure", "guest": "Brent Beshore", "slug": "beshore-update-on-small-business-and-private-equity", "date": "2020-03-20", "type": "PE / Buyout"}, {"id": "cascarilla-update-on-tail-risk#0", "t": "Build a diversified portfolio across stocks, cash, gold, and Bitcoin to hedge both inflation and deflation tail scenarios simultaneously.", "guest": "Chad Cascarilla", "slug": "cascarilla-update-on-tail-risk", "date": "2020-03-25", "type": "Founder / Operator"}, {"id": "cascarilla-update-on-tail-risk#1", "t": "Use segregated T-bill accounts or tokenized dollar products for cash holdings above FDIC insurance limits rather than bank deposits.", "guest": "Chad Cascarilla", "slug": "cascarilla-update-on-tail-risk", "date": "2020-03-25", "type": "Founder / Operator"}, {"id": "wallach-investing-in-healthcare#1", "t": "Follow the biology, not hype cycles. Microbiome may be too early despite venture funding; timing in biotech is binary—too early is as bad as wrong.", "guest": "D.A. Wallach", "slug": "wallach-investing-in-healthcare", "date": "2020-03-31", "type": "VC"}, {"id": "wallach-investing-in-healthcare#2", "t": "Big pharma's shift from internal R&D to acquisitions creates structural venture opportunity: 20-30B annual acquisition need drives entire biotech pipeline.", "guest": "D.A. Wallach", "slug": "wallach-investing-in-healthcare", "date": "2020-03-31", "type": "VC"}, {"id": "baker-investing-through-a-bear-market#1", "t": "Focus on companies whose competitors go bankrupt. Quick service restaurants and omni-channel retailers benefit from consolidation as SMB competitors fail.", "guest": "Gavin Baker", "slug": "baker-investing-through-a-bear-market", "date": "2020-04-02", "type": "Hedge Fund"}, {"id": "baker-investing-through-a-bear-market#2", "t": "Metaverse and video games are foundational to next decade. Discord, Roblox, Fortnite platforms matter more than hardware (Oculus). Watch infrastructure layers.", "guest": "Gavin Baker", "slug": "baker-investing-through-a-bear-market", "date": "2020-04-02", "type": "Hedge Fund"}, {"id": "tavel-consumer-marketplace-investing#1", "t": "Niche vertical marketplaces (Hipcamp vs. Airbnb, Etsy vs. eBay) can coexist with incumbents by owning specialized discovery, trust, and engagement models in ways the bigger platform can't.", "guest": "Sarah Tavel", "slug": "tavel-consumer-marketplace-investing", "date": "2020-04-07", "type": "VC"}, {"id": "tavel-consumer-marketplace-investing#2", "t": "Search costs and information opacity in markets are opportunities: companies that reduce friction or set information free (OpenTable, Zillow, Glassdoor) create enormous value.", "guest": "Sarah Tavel", "slug": "tavel-consumer-marketplace-investing", "date": "2020-04-07", "type": "VC"}, {"id": "stotz-frontier-markets-investing#0", "t": "Frontier markets offer 40% of world population at fastest growth rates, yet trade at distressed valuations due to daily-liquidity fund redemptions. Long-term capital with visa access and domain expertise has structural edge.", "guest": "Manny Stotz", "slug": "stotz-frontier-markets-investing", "date": "2020-04-21", "type": "Hedge Fund"}, {"id": "stotz-frontier-markets-investing#1", "t": "Quality businesses (high ROIC, intangible moats, low capital intensity) deliver mid-teens returns even in developed markets; in frontier markets with secular tailwinds from demographics and consumption S-curves, returns can exceed 20%+ for 30+ years.", "guest": "Manny Stotz", "slug": "stotz-frontier-markets-investing", "date": "2020-04-21", "type": "Hedge Fund"}, {"id": "kopelman-the-past-present-and-future-of-seed-investing#0", "t": "Founder evaluation is primarily about personality and non-conformist patterns, not the original idea. Best founders iterate relentlessly; the company looks different at scale than at seed. Evaluate their ability to learn and synthesize, not their upfront answers.", "guest": "Josh Kopelman", "slug": "kopelman-the-past-present-and-future-of-seed-investing", "date": "2020-04-28", "type": "VC"}, {"id": "kopelman-the-past-present-and-future-of-seed-investing#1", "t": "Seed investors should fund founders solving existing pain points (people searching/asking now) rather than forecasted problems, given typical 24-month runways. Use the Google Query test to force clarity on the market need.", "guest": "Josh Kopelman", "slug": "kopelman-the-past-present-and-future-of-seed-investing", "date": "2020-04-28", "type": "VC"}, {"id": "kopelman-the-past-present-and-future-of-seed-investing#2", "t": "Risk asymmetry creates startup opportunity when incumbents face regulatory or reputational constraints that startups embrace. PayPal beat eBay not on product but because Wells Fargo couldn't take the regulatory risk that PayPal did.", "guest": "Josh Kopelman", "slug": "kopelman-the-past-present-and-future-of-seed-investing", "date": "2020-04-28", "type": "VC"}, {"id": "bloomstran-an-update-on-public-markets#0", "t": "Own businesses with unshakeable pricing power and fortress balance sheets during deflationary cycles; leverage becomes toxic.", "guest": "Chris Bloomstran", "slug": "bloomstran-an-update-on-public-markets", "date": "2020-04-30", "type": "VC"}, {"id": "bloomstran-an-update-on-public-markets#2", "t": "Track velocity of money and debt-to-GDP ratios as leading indicators for deflation; don't rely on headline money supply growth.", "guest": "Chris Bloomstran", "slug": "bloomstran-an-update-on-public-markets", "date": "2020-04-30", "type": "VC"}, {"id": "hamed-an-update-on-private-credit#0", "t": "When uncertainty spikes, lower advance rates and maintain origination volume for better quality credits; resist yield-chasing.", "guest": "Ali Hamed", "slug": "hamed-an-update-on-private-credit", "date": "2020-05-05", "type": "VC"}, {"id": "hamed-an-update-on-private-credit#2", "t": "Track originator health and servicer viability as closely as underlying asset performance; they determine recovery outcomes in default.", "guest": "Ali Hamed", "slug": "hamed-an-update-on-private-credit", "date": "2020-05-05", "type": "VC"}, {"id": "lutke-building-a-modern-business#1", "t": "Remove process, not people; solve for friction through design changes, not policies or rules. Trust good hires with best judgment.", "guest": "Tobi Lütke", "slug": "lutke-building-a-modern-business", "date": "2020-05-12", "type": "Founder / Operator"}, {"id": "lutke-building-a-modern-business#2", "t": "Compress skill-building through high-feedback environments (games, real-time decisions); transfer learning shapes decision-making far more than theory.", "guest": "Tobi Lütke", "slug": "lutke-building-a-modern-business", "date": "2020-05-12", "type": "Founder / Operator"}, {"id": "helmer-power-business#0", "t": "Sustainable competitive advantage requires both a benefit (superior product/business model) and a barrier that prevents rivals from quickly emulating it.", "guest": "Hamilton Helmer", "slug": "helmer-power-business", "date": "2020-05-19", "type": "Academic / Author"}, {"id": "helmer-power-business#1", "t": "In network and scale businesses, acquiring customers unprofitably is often strategic because customer value accrues as you build defensible advantages—distinguish real Power from growth without moats.", "guest": "Hamilton Helmer", "slug": "helmer-power-business", "date": "2020-05-19", "type": "Academic / Author"}, {"id": "helmer-power-business#2", "t": "Barriers are built through experimentation and path dependency over years, rarely created intentionally; focus on finding paths where barriers might emerge rather than forcing them.", "guest": "Hamilton Helmer", "slug": "helmer-power-business", "date": "2020-05-19", "type": "Academic / Author"}, {"id": "mehrotra-the-art-and-science-of-the-bundle#1", "t": "Fair provider valuations in a bundle are determined by marginal churn contribution—not negotiating power—which forces all parties toward quality and efficiency.", "guest": "Shishir Mehrotra", "slug": "mehrotra-the-art-and-science-of-the-bundle", "date": "2020-05-26", "type": "Founder / Operator"}, {"id": "mehrotra-the-art-and-science-of-the-bundle#2", "t": "Intra-product bundling (combining previously separate tools) captures network effects and switching costs; users locked in because context loss and context-switching costs are high.", "guest": "Shishir Mehrotra", "slug": "mehrotra-the-art-and-science-of-the-bundle", "date": "2020-05-26", "type": "Founder / Operator"}, {"id": "thompson-platforms-ecosystems-and-aggregators#0", "t": "Aggregators win by capturing consumer attention and offering zero marginal costs to scale; they differ from platforms by not controlling the ecosystem, only distribution.", "guest": "Ben Thompson", "slug": "thompson-platforms-ecosystems-and-aggregators", "date": "2020-06-02", "type": "Academic / Author"}, {"id": "thompson-platforms-ecosystems-and-aggregators#2", "t": "Platform businesses benefit from high churn—more users entering the funnel at zero marginal cost outweighs individual success rates; this is a feature, not a bug.", "guest": "Ben Thompson", "slug": "thompson-platforms-ecosystems-and-aggregators", "date": "2020-06-02", "type": "Academic / Author"}, {"id": "grantham-an-uncertain-crisis#1", "t": "The greatest valuation spreads between growth and value stocks create asymmetric opportunities; seek resources and metals trading at historic discounts while FAANG trades at highs.", "guest": "Jeremy Grantham", "slug": "grantham-an-uncertain-crisis", "date": "2020-06-09", "type": "Public Markets"}, {"id": "grantham-an-uncertain-crisis#2", "t": "Metals represent genuine long-term opportunity as ore grades decline and supply tightens; avoid commodity exposure in food and oil which face different supply dynamics.", "guest": "Jeremy Grantham", "slug": "grantham-an-uncertain-crisis", "date": "2020-06-09", "type": "Public Markets"}, {"id": "collison-growing-the-internet-economy#0", "t": "Business defensibility comes from building genuine competitive advantages through tight integration and proprietary systems, not just asset hoarding.", "guest": "John Collison", "slug": "collison-growing-the-internet-economy", "date": "2020-06-16", "type": "Founder / Operator"}, {"id": "collison-growing-the-internet-economy#1", "t": "Public investors should demand transparency on capital allocation: what percentage of spending maintains the business versus what builds future value?", "guest": "John Collison", "slug": "collison-growing-the-internet-economy", "date": "2020-06-16", "type": "Founder / Operator"}, {"id": "gerstner-public-and-private-investing#0", "t": "Bet on large TAMs with poor customer experiences and trusted teams; success requires all three, and the TAM matters most.", "guest": "Brad Gerstner", "slug": "gerstner-public-and-private-investing", "date": "2020-06-23", "type": "VC"}, {"id": "gerstner-public-and-private-investing#2", "t": "Algorithm-driven platforms will displace search-driven commerce; Facebook, ByteDance, and Chinese super-apps are leading this shift globally.", "guest": "Brad Gerstner", "slug": "gerstner-public-and-private-investing", "date": "2020-06-23", "type": "VC"}, {"id": "robbins-investing-in-gaming#0", "t": "Invest pre-launch in game studios because post-launch valuations are uneconomical; free-to-play games become cash-flow machines with no marginal cost.", "guest": "Blake Robbins", "slug": "robbins-investing-in-gaming", "date": "2020-06-30", "type": "VC"}, {"id": "robbins-investing-in-gaming#1", "t": "Use index approach for early-stage gaming: fund 50+ studios rather than cherry-pick, since hit-driven nature requires volume for returns.", "guest": "Blake Robbins", "slug": "robbins-investing-in-gaming", "date": "2020-06-30", "type": "VC"}, {"id": "songhurst-lessons-from-investing-in-483-companies#0", "t": "Pre-seed/seed: founder quality and team chemistry matter most; near-guaranteed failure if first hires don't replicate excellence upward, creating downward culture spiral.", "guest": "Charlie Songhurst", "slug": "songhurst-lessons-from-investing-in-483-companies", "date": "2020-07-07", "type": "VC"}, {"id": "songhurst-lessons-from-investing-in-483-companies#1", "t": "Series A inflection: transition to formal management before 30 people or face productive collapse; this is the highest-failure threshold most startups hit.", "guest": "Charlie Songhurst", "slug": "songhurst-lessons-from-investing-in-483-companies", "date": "2020-07-07", "type": "VC"}, {"id": "songhurst-lessons-from-investing-in-483-companies#2", "t": "Best returns from geographically-dispersed founders solving global problems in secondary cities; capital markets at seed stage miss obvious winners outside Silicon Valley.", "guest": "Charlie Songhurst", "slug": "songhurst-lessons-from-investing-in-483-companies", "date": "2020-07-07", "type": "VC"}, {"id": "songhurst-lessons-from-investing-in-483-companies#4", "t": "Avoid data-value narratives; 99% of startups claiming unique data value actually lack real competitive advantage—look for network effects and switching costs instead.", "guest": "Charlie Songhurst", "slug": "songhurst-lessons-from-investing-in-483-companies", "date": "2020-07-07", "type": "VC"}, {"id": "novak-the-past-present-and-future-of-consumer-social-companies#1", "t": "Mobile-first product design with reduced friction (algorithm + no follower graph) drives creator supply; enables fastest-growing content platforms historically.", "guest": "Turner Novak", "slug": "novak-the-past-present-and-future-of-consumer-social-companies", "date": "2020-07-14", "type": "VC"}, {"id": "novak-the-past-present-and-future-of-consumer-social-companies#2", "t": "Social graphs create defensibility but cap creator upside; algorithm graphs do opposite—verify business model alignment before investing in creator tools.", "guest": "Turner Novak", "slug": "novak-the-past-present-and-future-of-consumer-social-companies", "date": "2020-07-14", "type": "VC"}, {"id": "novak-the-past-present-and-future-of-consumer-social-companies#4", "t": "Distinguish broadcast networks (content destination) from social networks (connection platform); media-only networks face structural challenges competing against social-backed platforms.", "guest": "Turner Novak", "slug": "novak-the-past-present-and-future-of-consumer-social-companies", "date": "2020-07-14", "type": "VC"}, {"id": "novak-the-past-present-and-future-of-consumer-social-companies#5", "t": "Commerce + social + infrastructure (payments, logistics) is a winning combination; isolated social without commerce defensibility (Zynn) gets copied and crushed.", "guest": "Turner Novak", "slug": "novak-the-past-present-and-future-of-consumer-social-companies", "date": "2020-07-14", "type": "VC"}, {"id": "vishria-the-past-present-and-future-of-saas-and-software#0", "t": "SaaS companies trading at 10-11x forward revenue are justified: index averages 35% growth + 7-8% free cash flow margin, exceeding Rule of 40 across the entire sector.", "guest": "Eric Vishria", "slug": "vishria-the-past-present-and-future-of-saas-and-software", "date": "2020-07-21", "type": "VC"}, {"id": "vishria-the-past-present-and-future-of-saas-and-software#1", "t": "Cloud/SaaS penetration is only 15% of total IT spend; remaining 85% on legacy systems, on-premise infrastructure, and labor represents massive TAM for next decade.", "guest": "Eric Vishria", "slug": "vishria-the-past-present-and-future-of-saas-and-software", "date": "2020-07-21", "type": "VC"}, {"id": "cole-how-to-operate-lessons-in-brand-distribution-and-leadership#0", "t": "Understanding operational phases (zero-to-one, one-to-two, scale) makes you a better investor. Don't expect execution miracles on one-time activities; grade founders on repeatable operations.", "guest": "Kat Cole", "slug": "cole-how-to-operate-lessons-in-brand-distribution-and-leadership", "date": "2020-07-28", "type": "Founder / Operator"}, {"id": "cole-how-to-operate-lessons-in-brand-distribution-and-leadership#1", "t": "Brands with deep community and fan love are most acquisitionable. Scale is achieved many ways; look for obsession, differentiation, and frequency roots.", "guest": "Kat Cole", "slug": "cole-how-to-operate-lessons-in-brand-distribution-and-leadership", "date": "2020-07-28", "type": "Founder / Operator"}, {"id": "ball-the-future-of-media-movies-the-metaverse-and-more#0", "t": "Video games reach engagement equivalent to TV but monetize at fractions of TV's hourly rate. Generational shift from 50+ TV audience to Gen X/Z gaming means huge monetization upside.", "guest": "Matthew Ball", "slug": "ball-the-future-of-media-movies-the-metaverse-and-more", "date": "2020-08-04", "type": "VC"}, {"id": "ball-the-future-of-media-movies-the-metaverse-and-more#2", "t": "Platform leadership is not portable. Yesterday's arcade/console/PC/mobile leaders rarely lead next category. Diversify across gaming categories; always expect new winners.", "guest": "Matthew Ball", "slug": "ball-the-future-of-media-movies-the-metaverse-and-more", "date": "2020-08-04", "type": "VC"}, {"id": "lake-the-next-wave-of-ecommerce#0", "t": "Capital constraints force discipline: Stitch Fix raised $50M vs competitors' hundreds of millions, but forced capital efficiency became durable advantage.", "guest": "Katrina Lake", "slug": "lake-the-next-wave-of-ecommerce", "date": "2020-08-18", "type": "Public-Co CEO"}, {"id": "lake-the-next-wave-of-ecommerce#2", "t": "Overlooked opportunities with underestimated founders often generate best returns: gender bias masked a $5B business hiding in plain sight.", "guest": "Katrina Lake", "slug": "lake-the-next-wave-of-ecommerce", "date": "2020-08-18", "type": "Public-Co CEO"}, {"id": "puttagunta-open-source-crash-course#0", "t": "Open source success requires layering defensibility (convenience, managed cloud, proprietary services) on top of a truly differentiated free core; free alone fails.", "guest": "Jeremiah Lowin & Chetan Puttagunta", "slug": "puttagunta-open-source-crash-course", "date": "2020-08-25", "type": "Founder / Operator"}, {"id": "puttagunta-open-source-crash-course#2", "t": "Cloud commoditization forces differentiation: managed infrastructure becomes the business; pure open source companies that only manage compute will lose to AWS/Azure/Google.", "guest": "Jeremiah Lowin & Chetan Puttagunta", "slug": "puttagunta-open-source-crash-course", "date": "2020-08-25", "type": "Founder / Operator"}, {"id": "mauboussin-great-migration-public-to-private-equity#0", "t": "Regulatory/legal IPO costs now exceed capital-access benefits for most small companies; strategic acquisition has become rationally superior to public markets for growth firms.", "guest": "Michael Mauboussin", "slug": "mauboussin-great-migration-public-to-private-equity", "date": "2020-09-01", "type": "Public Markets"}, {"id": "mauboussin-great-migration-public-to-private-equity#1", "t": "Manager skill persistence in venture is real; identify and commit to top-quartile funds; scale moderation in buyout persistence suggests skill exists but is harder to sustain.", "guest": "Michael Mauboussin", "slug": "mauboussin-great-migration-public-to-private-equity", "date": "2020-09-01", "type": "Public Markets"}, {"id": "mauboussin-great-migration-public-to-private-equity#2", "t": "Proper intangible accounting transforms valuation analysis: capitalizing R&D/SG&A/training increases reported earnings and invested capital, shifting value/book ratios and revealing mispriced value opportunities.", "guest": "Michael Mauboussin", "slug": "mauboussin-great-migration-public-to-private-equity", "date": "2020-09-01", "type": "Public Markets"}, {"id": "seibel-lessons-from-thousands-of-startups#1", "t": "In marketplaces, identify the supply-side customer (who needs frequent, intense help) before chasing demand. Viable supply unlocks everything else.", "guest": "Michael Seibel", "slug": "seibel-lessons-from-thousands-of-startups", "date": "2020-09-08", "type": "VC"}, {"id": "seibel-lessons-from-thousands-of-startups#2", "t": "Get to product-market fit with customers before raising money. Paying customers give you leverage, reduce investor dependence, and prove your model works.", "guest": "Michael Seibel", "slug": "seibel-lessons-from-thousands-of-startups", "date": "2020-09-08", "type": "VC"}, {"id": "sutherland-moonshots-and-marketing#0", "t": "Invest in counterintuitive ideas with absurdity—Red Bull (worse, more expensive, smaller) outperformed logic. Psychological innovation beats engineering.", "guest": "Rory Sutherland", "slug": "sutherland-moonshots-and-marketing", "date": "2020-09-15", "type": "Other"}, {"id": "sutherland-moonshots-and-marketing#1", "t": "Flip weaknesses into strengths via marketing psychology. Avis #2, Cunard slow ship, Bailey's awkward ask—all became competitive advantages.", "guest": "Rory Sutherland", "slug": "sutherland-moonshots-and-marketing", "date": "2020-09-15", "type": "Other"}, {"id": "sutherland-moonshots-and-marketing#2", "t": "Look for undervalued businesses that could be repositioned via pricing or psychological framing. Hotel chains, grocery retail, niche focus all have untapped lever arms.", "guest": "Rory Sutherland", "slug": "sutherland-moonshots-and-marketing", "date": "2020-09-15", "type": "Other"}, {"id": "taylor-the-modern-activist-toolkit#0", "t": "Focus activism on high-quality small-to-mid-cap businesses (500M-8B market cap) where competitive moats and market dominance create alpha. Time is your friend in compounding.", "guest": "Lauren Taylor Wolfe", "slug": "taylor-the-modern-activist-toolkit", "date": "2020-09-22", "type": "VC"}, {"id": "taylor-the-modern-activist-toolkit#1", "t": "ESG initiatives drive bottom-line returns when tied to concrete business cases: lower labor costs (retention), higher utilization (diversity), reduced customer acquisition (values alignment).", "guest": "Lauren Taylor Wolfe", "slug": "taylor-the-modern-activist-toolkit", "date": "2020-09-22", "type": "VC"}, {"id": "proposal-better-cheaper-faster-why-companies-that-reduce-friction-win#0", "t": "Focus on friction removal in large TAMs migrating digital; the speed of consumer adoption post-friction removal is nonlinear and predictable.", "guest": "Modest Proposal", "slug": "proposal-better-cheaper-faster-why-companies-that-reduce-friction-win", "date": "2020-09-29", "type": "Public Markets"}, {"id": "proposal-better-cheaper-faster-why-companies-that-reduce-friction-win#1", "t": "Weaker network effects in ride-sharing than marketplaces meant Lyft could co-exist via arrival time. Duopolies, not monopolies, are stable.", "guest": "Modest Proposal", "slug": "proposal-better-cheaper-faster-why-companies-that-reduce-friction-win", "date": "2020-09-29", "type": "Public Markets"}, {"id": "livermore-upside-down-markets#0", "t": "Fiscal stimulus creates forced asset reallocations: savers flooded with cash/bonds earning near-zero are pushed into equities, creating demand pressure independent of earnings.", "guest": "Jesse Livermore", "slug": "livermore-upside-down-markets", "date": "2020-10-06", "type": "Public Markets"}, {"id": "livermore-upside-down-markets#1", "t": "Inflation risk from fiscal is delayed (post-pandemic normalization), not immediate. Current spending constraints hide the magnitude—monitor wealth injection timing.", "guest": "Jesse Livermore", "slug": "livermore-upside-down-markets", "date": "2020-10-06", "type": "Public Markets"}, {"id": "novogratz-investing-in-dignity-and-character#1", "t": "Patient capital + blended finance unlock trillion-dollar problems (sanitation, water, primary healthcare, agriculture) that pure markets or government alone can't solve.", "guest": "Jacqueline Novogratz", "slug": "novogratz-investing-in-dignity-and-character", "date": "2020-10-13", "type": "Founder / Operator"}, {"id": "novogratz-investing-in-dignity-and-character#2", "t": "Stakeholder models (all value-chain players valued and incentivized) outperform extractive chains long-term: happier workers, loyal farmers, repeat customers, resilience to crises.", "guest": "Jacqueline Novogratz", "slug": "novogratz-investing-in-dignity-and-character", "date": "2020-10-13", "type": "Founder / Operator"}, {"id": "gilbert-lessons-on-early-stage-investing-and-getting-acquired#0", "t": "Network effects and zero-marginal-cost models unlock disproportionate acquisition returns; top 10 M&A deals are dominated by these dynamics.", "guest": "Ben Gilbert & David Rosenthal", "slug": "gilbert-lessons-on-early-stage-investing-and-getting-acquired", "date": "2020-10-20", "type": "VC"}, {"id": "gilbert-lessons-on-early-stage-investing-and-getting-acquired#2", "t": "Founder-led rounds with fewer, more committed investors outperform party rounds where only founders have real career risk.", "guest": "Ben Gilbert & David Rosenthal", "slug": "gilbert-lessons-on-early-stage-investing-and-getting-acquired", "date": "2020-10-20", "type": "VC"}, {"id": "gerstner-thriving-in-changing-markets#0", "t": "SPACs by reputable sponsors reduce cap table randomization, give founders price control and narrative ownership, and align investors on long-term value.", "guest": "Rich Barton & Brad Gerstner", "slug": "gerstner-thriving-in-changing-markets", "date": "2020-10-27", "type": "Founder / Operator"}, {"id": "gerstner-thriving-in-changing-markets#1", "t": "In zero-marketing scenarios, product excellence becomes the moat; virality happens when the product is so provocative people discuss it unprompted.", "guest": "Rich Barton & Brad Gerstner", "slug": "gerstner-thriving-in-changing-markets", "date": "2020-10-27", "type": "Founder / Operator"}, {"id": "hariharan-lessons-in-growth-investing#0", "t": "Analyze startups by business model, not industry; marketplace, advertising, and SaaS unit economics repeat across B2B and B2C contexts.", "guest": "Anu Hariharan", "slug": "hariharan-lessons-in-growth-investing", "date": "2020-11-03", "type": "VC"}, {"id": "hariharan-lessons-in-growth-investing#1", "t": "Organic growth >50% signals defensibility; product-driven growth compounds better than paid acquisition and scales efficiently later.", "guest": "Anu Hariharan", "slug": "hariharan-lessons-in-growth-investing", "date": "2020-11-03", "type": "VC"}, {"id": "karp-the-power-of-brand#0", "t": "Identify authentic founders solving real market needs with strong gross margins (50%+) to sustain growth without continuous capital burn.", "guest": "Jason Karp & Rohan Oza", "slug": "karp-the-power-of-brand", "date": "2020-11-10", "type": "VC"}, {"id": "karp-the-power-of-brand#1", "t": "Premium brands maintain pricing power through selective retail distribution and scarcity; oversaturation erodes brand equity regardless of product quality.", "guest": "Jason Karp & Rohan Oza", "slug": "karp-the-power-of-brand", "date": "2020-11-10", "type": "VC"}, {"id": "scevak-wild-hearts-and-wild-ideas#1", "t": "High gross margins create margin for error in software; lower-margin businesses die while succeeding with execution, unlike high-margin peers.", "guest": "Niki Scevak", "slug": "scevak-wild-hearts-and-wild-ideas", "date": "2020-11-17", "type": "VC"}, {"id": "scevak-wild-hearts-and-wild-ideas#2", "t": "Product obsession—measured by customer love and consistent board-deck focus—predicts long-term success better than market size or competitive claims.", "guest": "Niki Scevak", "slug": "scevak-wild-hearts-and-wild-ideas", "date": "2020-11-17", "type": "VC"}, {"id": "singareddy-investing-in-the-future-of-healthcare#0", "t": "Invest in companies solving sequentially: interoperability first, then point solutions. Downstream innovation (payer analytics, clinician tools, patient transparency) depends on it.", "guest": "Raju Rishi, Nikita Singareddy & Jason Black", "slug": "singareddy-investing-in-the-future-of-healthcare", "date": "2020-11-24", "type": "VC"}, {"id": "singareddy-investing-in-the-future-of-healthcare#2", "t": "COVID forced permanent regulatory changes (telehealth parity, credentialing reciprocity). Build businesses on these shifted incentives; they won't fully reverse.", "guest": "Raju Rishi, Nikita Singareddy & Jason Black", "slug": "singareddy-investing-in-the-future-of-healthcare", "date": "2020-11-24", "type": "VC"}, {"id": "gross-finding-undiscovered-talent#0", "t": "Talent screening is the single most important skill—it's required to do anything interesting. Measurement matters: 25% of Pioneer finds get funded by others.", "guest": "Daniel Gross", "slug": "gross-finding-undiscovered-talent", "date": "2020-12-01", "type": "Founder / Operator"}, {"id": "gross-finding-undiscovered-talent#1", "t": "Prioritize founders with high learning velocity (derivative) over static energy. They pivot efficiently and find product-market fit faster than raw hustle.", "guest": "Daniel Gross", "slug": "gross-finding-undiscovered-talent", "date": "2020-12-01", "type": "Founder / Operator"}, {"id": "meyer-the-power-of-hospitality#1", "t": "The 51/49 emotional-to-technical hiring split is non-negotiable for service businesses; you can train a sommelier but not kindness.", "guest": "Danny Meyer", "slug": "meyer-the-power-of-hospitality", "date": "2020-12-08", "type": "Founder / Operator"}, {"id": "meyer-the-power-of-hospitality#2", "t": "Test business essentiality with 'Would I notice if this closed?' Non-essential businesses disappear without trace—build to matter irreplaceably.", "guest": "Danny Meyer", "slug": "meyer-the-power-of-hospitality", "date": "2020-12-08", "type": "Founder / Operator"}, {"id": "hinkie-find-your-people#0", "t": "Study the breadcrumb trail — old blogs, theses, GitHub, videos of their parents — before the pitch; artifacts over time beat any deck or interview.", "guest": "Sam Hinkie", "slug": "hinkie-find-your-people", "date": "2020-12-15", "type": "VC"}, {"id": "hinkie-find-your-people#1", "t": "Back high-ceiling people running at a field, not a plan: founders, like drafted athletes, must 10x skills that aren't even on their radar yet.", "guest": "Sam Hinkie", "slug": "hinkie-find-your-people", "date": "2020-12-15", "type": "VC"}, {"id": "hinkie-find-your-people#2", "t": "Distrust the eight-minute conviction race; refusing to decide by Friday costs you exactly the transactional people you wanted to lose.", "guest": "Sam Hinkie", "slug": "hinkie-find-your-people", "date": "2020-12-15", "type": "VC"}, {"id": "cibelli-cornerstone-investing-insights#0", "t": "Deep operational diligence—factory tours, supply-chain mechanics, labor bottlenecks—often reveals undervalued moats that financial analysis misses.", "guest": "Mario Cibelli", "slug": "cibelli-cornerstone-investing-insights", "date": "2020-12-22", "type": "Hedge Fund"}, {"id": "cibelli-cornerstone-investing-insights#1", "t": "Cyclical mispricing in commodity-dependent businesses (agave pricing, for Becle) creates asymmetric entry points when multiples are already depressed.", "guest": "Mario Cibelli", "slug": "cibelli-cornerstone-investing-insights", "date": "2020-12-22", "type": "Hedge Fund"}, {"id": "graham-investing-in-overlooked-businesses#1", "t": "Customer profitability data uncovers hidden value: many companies subsidize unprofitable customers with cash from a small profitable core.", "guest": "Tracy Graham", "slug": "graham-investing-in-overlooked-businesses", "date": "2020-12-29", "type": "PE / Buyout"}, {"id": "graham-investing-in-overlooked-businesses#2", "t": "Lower-middle market businesses at 8x LTM EBITDA provide cash flow to fund technology transformation with margins unavailable to pure-play software.", "guest": "Tracy Graham", "slug": "graham-investing-in-overlooked-businesses", "date": "2020-12-29", "type": "PE / Buyout"}, {"id": "parameswaran-internet-scale-businesses#1", "t": "Freemium adoption and viral coefficient are stronger predictors than sales teams for software companies.", "guest": "Ram Parameswaran", "slug": "parameswaran-internet-scale-businesses", "date": "2021-01-05", "type": "VC"}, {"id": "fuss-breaking-down-the-food-ecosystem#0", "t": "Study value chains deeply: profits concentrate at the least commoditized link, not where most activity happens. McDonald's and Domino's own distribution/brand, not production.", "guest": "Zack Fuss", "slug": "fuss-breaking-down-the-food-ecosystem", "date": "2021-01-12", "type": "PE / Buyout"}, {"id": "fuss-breaking-down-the-food-ecosystem#1", "t": "Unit economics trump macro trends: a sustainable 30%+ cash-on-cash return on store investment (Domino's vs 15-20% for Burger King) compounds into market dominance regardless of category.", "guest": "Zack Fuss", "slug": "fuss-breaking-down-the-food-ecosystem", "date": "2021-01-12", "type": "PE / Buyout"}, {"id": "fuss-breaking-down-the-food-ecosystem#2", "t": "Decentralized franchises with aligned incentives outperform traditional corporate models: franchisees reinvest profits in expansion, creating virtuous flywheels publishers can't replicate.", "guest": "Zack Fuss", "slug": "fuss-breaking-down-the-food-ecosystem", "date": "2021-01-12", "type": "PE / Buyout"}, {"id": "cormier-the-future-of-cities-and-real-estate#1", "t": "Flight to quality compounds through cycles: recession forces tenants to upgrade from subpar buildings to premium ones; design and experience insure occupancy better than location alone.", "guest": "Claire Cormier Thielke", "slug": "cormier-the-future-of-cities-and-real-estate", "date": "2021-01-19", "type": "PE / Buyout"}, {"id": "cormier-the-future-of-cities-and-real-estate#2", "t": "Execution risk is alpha, macro risk is beta: location and timing are table-stakes (beta); true returns come from design choices, construction management, tenant mix, and timing sales—hard to copy.", "guest": "Claire Cormier Thielke", "slug": "cormier-the-future-of-cities-and-real-estate", "date": "2021-01-19", "type": "PE / Buyout"}, {"id": "van-unlocking-value-in-gaming#0", "t": "Invest in uncluttered spaces where incumbents sit idle: mobile (2007-2009) succeeded because legacy publishers dismissed touchscreen economics as unmarketable. Look for next category where apex predators have mental inertia.", "guest": "Joost van Dreunen", "slug": "van-unlocking-value-in-gaming", "date": "2021-01-26", "type": "VC"}, {"id": "van-unlocking-value-in-gaming#1", "t": "Business model innovation compounds more than game novelty: free-to-play was perpendicular to $60 retail model, attracted 3B users globally, made mobile a $85B market vs console $20B. Model beats content.", "guest": "Joost van Dreunen", "slug": "van-unlocking-value-in-gaming", "date": "2021-01-26", "type": "VC"}, {"id": "grantham-a-historic-market-bubble#0", "t": "Watch for valuation extremes, acceleration in price moves, and crazy behavior (media attention, retail activity) as bubble warning signs—together they're more reliable than any single metric.", "guest": "Jeremy Grantham", "slug": "grantham-a-historic-market-bubble", "date": "2021-02-23", "type": "VC"}, {"id": "grantham-a-historic-market-bubble#2", "t": "Build cash reserves as an individual; even being 18 months early on an exit pays off handsomely on the round trip when the crash comes.", "guest": "Jeremy Grantham", "slug": "grantham-a-historic-market-bubble", "date": "2021-02-23", "type": "VC"}, {"id": "wolfe-the-past-present-and-future-of-defense#1", "t": "Geopolitical concentration risk (TSMC in Taiwan) is a systemic military vulnerability and venture opportunity. Redundancy in chip manufacturing is strategic infrastructure.", "guest": "Josh Wolfe & Tony Thomas", "slug": "wolfe-the-past-present-and-future-of-defense", "date": "2021-03-09", "type": "VC"}, {"id": "wolfe-the-past-present-and-future-of-defense#2", "t": "Defense-focused venture (Anduril, Varda) operates at domain intersections—autonomy, space, information—rather than single-technology bets. Diversified competitive advantages compound.", "guest": "Josh Wolfe & Tony Thomas", "slug": "wolfe-the-past-present-and-future-of-defense", "date": "2021-03-09", "type": "VC"}, {"id": "maqubela-dawn-of-the-21st-century#1", "t": "Infrastructure bottlenecks (healthcare, taxes, tools) constrain entrepreneurship more than capital; back companies removing friction.", "guest": "Kanyi Maqubela", "slug": "maqubela-dawn-of-the-21st-century", "date": "2021-03-30", "type": "VC"}, {"id": "jacobs-content-to-commerce#0", "t": "Invest in identity-driven passion brands built by authentic creators, not polished pitches. Look for founders who stumbled into audience first, monetization second.", "guest": "Jesse Jacobs & Mike Kerns", "slug": "jacobs-content-to-commerce", "date": "2021-04-06", "type": "VC"}, {"id": "jacobs-content-to-commerce#1", "t": "Couple media (top of funnel) with owned commerce (bottom of funnel). This reduces customer acquisition cost and defensibility against larger competitors.", "guest": "Jesse Jacobs & Mike Kerns", "slug": "jacobs-content-to-commerce", "date": "2021-04-06", "type": "VC"}, {"id": "dixon-the-potential-of-blockchain-technology#0", "t": "Invest in protocols and infrastructure that enable new capabilities, not just ports of existing businesses. The killer apps for blockchains are things we haven't imagined yet.", "guest": "Chris Dixon", "slug": "dixon-the-potential-of-blockchain-technology", "date": "2021-04-13", "type": "VC"}, {"id": "dixon-the-potential-of-blockchain-technology#1", "t": "Multiple specialized blockchains will coexist, optimized for different trade-offs (security vs. performance). They'll interoperate via trustless bridges, like CPU/GPU in a computer.", "guest": "Chris Dixon", "slug": "dixon-the-potential-of-blockchain-technology", "date": "2021-04-13", "type": "VC"}, {"id": "enright-the-buy-side-primer#0", "t": "Understand which competitive bucket the market has placed a stock in, then look for evidence it belongs in a different bucket. Reframing ('good software company with mobile problem' → 'great mobile-first company') drives outsized returns.", "guest": "Paul Enright", "slug": "enright-the-buy-side-primer", "date": "2021-04-20", "type": "Hedge Fund"}, {"id": "enright-the-buy-side-primer#1", "t": "Great research requires sideways digging: footnotes, regulatory history, sector trends, private competitors, language shifts. Reading the last 2 10-Ks is table stakes; it's insufficient.", "guest": "Paul Enright", "slug": "enright-the-buy-side-primer", "date": "2021-04-20", "type": "Hedge Fund"}, {"id": "buckley-identifying-legendary-start-ups#0", "t": "Identify markets with high growth rates, not size. The iPhone app store was tiny in 2008 but growing exponentially—the right vector for breakthrough companies.", "guest": "Josh Buckley", "slug": "buckley-identifying-legendary-start-ups", "date": "2021-04-27", "type": "VC"}, {"id": "buckley-identifying-legendary-start-ups#2", "t": "Find businesses where power-law economics dominate and the product naturally captures variable value from high-intensity, willing-to-pay users (Twilio, Roblox, Fortnite model).", "guest": "Josh Buckley", "slug": "buckley-identifying-legendary-start-ups", "date": "2021-04-27", "type": "VC"}, {"id": "sugrue-investing-in-paradigm-shifts#0", "t": "Only invest in businesses with high unit-level economics. Measure contribution margin at customer/cohort level, not aggregate. If CAC payback exceeds customer lifetime value, it won't scale.", "guest": "Andrew Sugrue", "slug": "sugrue-investing-in-paradigm-shifts", "date": "2021-05-04", "type": "VC"}, {"id": "dourado-frontiers-for-productivity#0", "t": "Total factor productivity stalling (0.3% post-2005) signals structural problems. Back founders attacking rate limiters: regulatory friction, energy costs, biotech development speed.", "guest": "Eli Dourado", "slug": "dourado-frontiers-for-productivity", "date": "2021-05-11", "type": "Academic / Author"}, {"id": "dourado-frontiers-for-productivity#1", "t": "Complacency is real. Crisis removes it temporarily (COVID vaccine timeline). Invest in founders willing to work at crisis-pace even in peacetime.", "guest": "Eli Dourado", "slug": "dourado-frontiers-for-productivity", "date": "2021-05-11", "type": "Academic / Author"}, {"id": "leydon-designing-digital-economies#0", "t": "Broken but exponentially growing products signal active innovation. Invest there; once they're polished, the arc is flattening.", "guest": "Gabe Leydon", "slug": "leydon-designing-digital-economies", "date": "2021-06-07", "type": "Founder / Operator"}, {"id": "leydon-designing-digital-economies#2", "t": "Spaces still in innovation phase (crypto, DeFi) shouldn't get design polish yet. Messy + growing = healthy. Polished + stalled = warning sign.", "guest": "Gabe Leydon", "slug": "leydon-designing-digital-economies", "date": "2021-06-07", "type": "Founder / Operator"}, {"id": "harris-resilience-and-imagination#0", "t": "Regrets are omissions, not commissions. Missing MasterCard IPO opportunity taught that opportunity cost vastly exceeds actual portfolio losses.", "guest": "John Harris", "slug": "harris-resilience-and-imagination", "date": "2021-06-14", "type": "Public Markets"}, {"id": "harris-resilience-and-imagination#1", "t": "Quality + trustworthy people reduce burden of annual decision-making; 1-3 annual bets beats 15-30. Fewer bets compound into better results.", "guest": "John Harris", "slug": "harris-resilience-and-imagination", "date": "2021-06-14", "type": "Public Markets"}, {"id": "marks-embracing-the-psychology-of-investing#0", "t": "Regrets are omissions not commissions; missing a 10x opportunity costs vastly more than realizing a 30% loss. Focus on opportunity cost.", "guest": "Howard Marks", "slug": "marks-embracing-the-psychology-of-investing", "date": "2021-06-21", "type": "PE / Buyout"}, {"id": "marks-embracing-the-psychology-of-investing#1", "t": "Psychology extremes require contrarian discipline. All buy at highs, all sell at lows. Winner buys what depressed herd sells in panic.", "guest": "Howard Marks", "slug": "marks-embracing-the-psychology-of-investing", "date": "2021-06-21", "type": "PE / Buyout"}, {"id": "mandel-investing-behind-change#0", "t": "Short selling returns have deteriorated since late 1990s due to hedge fund competition and tighter borrow costs; long-side investing remains primary alpha source.", "guest": "Steve Mandel", "slug": "mandel-investing-behind-change", "date": "2021-07-20", "type": "Hedge Fund"}, {"id": "mandel-investing-behind-change#2", "t": "In 24/7 markets with perfect information, edge comes from understanding structural business changes (AWS, Netflix pivots, digital payments) early and owning patiently.", "guest": "Steve Mandel", "slug": "mandel-investing-behind-change", "date": "2021-07-20", "type": "Hedge Fund"}, {"id": "kawaja-wisdom-from-decades-of-investing#1", "t": "Competitive advantages vary dramatically in durability: steel and geographic resources (Vale) last centuries, while tech moats can erode in years.", "guest": "Carl Kawaja", "slug": "kawaja-wisdom-from-decades-of-investing", "date": "2021-07-27", "type": "Public Markets"}, {"id": "kawaja-wisdom-from-decades-of-investing#2", "t": "Information quality matters more than quantity; one clear graph (Edward Tufte) communicates more than 13 pages of data—apply this discipline to thesis development.", "guest": "Carl Kawaja", "slug": "kawaja-wisdom-from-decades-of-investing", "date": "2021-07-27", "type": "Public Markets"}, {"id": "karniol-tambour-all-things-macro#0", "t": "Understanding your personal inflation risk and diversifying across inflation scenarios (bonds, commodities, gold, currencies) matters more than predicting inflation.", "guest": "Karen Karniol-Tambour", "slug": "karniol-tambour-all-things-macro", "date": "2021-08-03", "type": "Hedge Fund"}, {"id": "karniol-tambour-all-things-macro#1", "t": "Retail investor participation through fractional shares and options is reshaping volatility dynamics; expect larger boom-bust cycles and different historical value signals.", "guest": "Karen Karniol-Tambour", "slug": "karniol-tambour-all-things-macro", "date": "2021-08-03", "type": "Hedge Fund"}, {"id": "ramaswamy-the-past-present-and-future-of-search#0", "t": "Google's authority model (PageRank) created a defensible quality moat that keyword-matching couldn't replicate, justifying market dominance.", "guest": "Sridhar Ramaswamy", "slug": "ramaswamy-the-past-present-and-future-of-search", "date": "2021-08-10", "type": "Founder / Operator"}, {"id": "ramaswamy-the-past-present-and-future-of-search#2", "t": "Subscription models succeed when personalization/control reaches an 'aha moment' that free ad-supported versions can't match.", "guest": "Sridhar Ramaswamy", "slug": "ramaswamy-the-past-present-and-future-of-search", "date": "2021-08-10", "type": "Founder / Operator"}, {"id": "ciani-exploring-the-creative-process#0", "t": "Creating tools for creators requires close collaboration with end-users, not just engineers; Don Buchla designed hand-sized controls based on human hand, not available chips.", "guest": "Suzanne Ciani", "slug": "ciani-exploring-the-creative-process", "date": "2021-08-16", "type": "Other"}, {"id": "ciani-exploring-the-creative-process#2", "t": "Permission and freedom are more valuable than pay for creative work; electronic music attracted women precisely because it needed no gatekeepers.", "guest": "Suzanne Ciani", "slug": "ciani-exploring-the-creative-process", "date": "2021-08-16", "type": "Other"}, {"id": "quintini-investing-at-the-supercritical-stage#1", "t": "Quality revenue is stickiness + core to customer operations + pricing power + buyer belief in ROI; willingness-to-pay signals renewal confidence.", "guest": "Renata Quintini & Roseanne Wincek", "slug": "quintini-investing-at-the-supercritical-stage", "date": "2021-08-24", "type": "VC"}, {"id": "quintini-investing-at-the-supercritical-stage#2", "t": "Founder scalability (ability to hire talent, delegate, evolve role) matters more than initial product brilliance; seek self-aware founders.", "guest": "Renata Quintini & Roseanne Wincek", "slug": "quintini-investing-at-the-supercritical-stage", "date": "2021-08-24", "type": "VC"}, {"id": "malpass-building-a-great-endowment#0", "t": "Partner only with top-decile managers in venture, PE, and public markets; the median universe isn't worth the effort or fees. Identify the 1%.", "guest": "Scott Malpass", "slug": "malpass-building-a-great-endowment", "date": "2021-08-31", "type": "Other"}, {"id": "malpass-building-a-great-endowment#2", "t": "Build organizational capacity to identify and maintain 10-20 year partnerships: requires constant travel, deep networks, and expert teams to win allocations.", "guest": "Scott Malpass", "slug": "malpass-building-a-great-endowment", "date": "2021-08-31", "type": "Other"}, {"id": "ek-enabling-creators-everywhere#0", "t": "Atoms businesses require 10-100X more capital upfront and years to product; optimize for long-term bets and solving structural problems, not fast cycles.", "guest": "Daniel Ek", "slug": "ek-enabling-creators-everywhere", "date": "2021-09-14", "type": "Founder / Operator"}, {"id": "ek-enabling-creators-everywhere#1", "t": "Infrastructure plays in emerging fields (Ginkgo in biotech, data tools) create foundations that accelerate thousands of downstream innovations; that's where leverage exists.", "guest": "Daniel Ek", "slug": "ek-enabling-creators-everywhere", "date": "2021-09-14", "type": "Founder / Operator"}, {"id": "fialkow-paint-outside-the-lines#0", "t": "Seek founders who love product so deeply they pivot, not pivot away; protect them from co-investors with misaligned timelines and incentives.", "guest": "David Fialkow", "slug": "fialkow-paint-outside-the-lines", "date": "2021-09-21", "type": "VC"}, {"id": "hoag-calibrating-market-adoption#0", "t": "Growth-stage crossover investing beats early-stage venture: by calibrating market adoption after tech risk is eliminated, TCV achieves lower loss ratios with equal or better multiples via scale and competitive moats.", "guest": "Jay Hoag", "slug": "hoag-calibrating-market-adoption", "date": "2021-09-28", "type": "VC"}, {"id": "hoag-calibrating-market-adoption#1", "t": "Counter-cycle conviction compounds. Netflix in 2001 couldn't raise from anyone; TCV stepped in when no capital existed for consumer e-commerce. That bet returned multiples while enabling a trillion-dollar company.", "guest": "Jay Hoag", "slug": "hoag-calibrating-market-adoption", "date": "2021-09-28", "type": "VC"}, {"id": "lefcourt-the-go-to-market-motion#0", "t": "Customer obsession beats pitch craft. Build it into your process: Who is the customer today? Where do they have needs? Where do they need education? This is how seed investors find winners before Series A.", "guest": "Jenny Lefcourt", "slug": "lefcourt-the-go-to-market-motion", "date": "2021-10-05", "type": "VC"}, {"id": "lefcourt-the-go-to-market-motion#1", "t": "Go-to-market is 50% of the win. The one-two punch (solve today's acute problem + paint future vision) closes enterprise deals 10x faster than pain-only or vision-only selling.", "guest": "Jenny Lefcourt", "slug": "lefcourt-the-go-to-market-motion", "date": "2021-10-05", "type": "VC"}, {"id": "neuman-becoming-your-own-bank#0", "t": "Self-custody with multi-key setups is safer than centralized exchanges: Bitcoin transactions are irreversible, so exchanges holding your keys means their security = your security. Distribute keys to reduce single points of failure.", "guest": "Nick Neuman", "slug": "neuman-becoming-your-own-bank", "date": "2021-10-12", "type": "Founder / Operator"}, {"id": "bankman-fried-creating-a-perfect-market#0", "t": "Crypto's fragmented exchanges and capital controls create the largest arbitrage opportunities in modern finance (10%+ spreads across venues in 2017-2018).", "guest": "Sam Bankman-Fried", "slug": "bankman-fried-creating-a-perfect-market", "date": "2021-10-19", "type": "Founder / Operator"}, {"id": "bankman-fried-creating-a-perfect-market#1", "t": "Derivatives volume/spot ratio (2.5:1 globally vs 0.1:1 in US) indicates $25B+ regulatory-gap opportunity in CFTC-licensed futures.", "guest": "Sam Bankman-Fried", "slug": "bankman-fried-creating-a-perfect-market", "date": "2021-10-19", "type": "Founder / Operator"}, {"id": "rampell-investing-in-operating-systems#0", "t": "Fintech OS investments (Stripe, Square, Brex) have outsized returns because they own payment/trust infrastructure, not because of superior UX.", "guest": "Alex Rampell", "slug": "rampell-investing-in-operating-systems", "date": "2021-10-26", "type": "VC"}, {"id": "rampell-investing-in-operating-systems#2", "t": "Payment infrastructure businesses scale across verticals via API; point-solution competitors get trapped in one vertical.", "guest": "Alex Rampell", "slug": "rampell-investing-in-operating-systems", "date": "2021-10-26", "type": "VC"}, {"id": "friar-building-the-local-graph#0", "t": "Local platforms defensible at neighborhood granularity (800-1K homes) where Facebook's scale advantage disappears.", "guest": "Sarah Friar", "slug": "friar-building-the-local-graph", "date": "2021-11-02", "type": "Public-Co CEO"}, {"id": "friar-building-the-local-graph#2", "t": "Advertising reaches inflection only at granular targeting; before that, format innovation (maps, campaigns) matters more than scale.", "guest": "Sarah Friar", "slug": "friar-building-the-local-graph", "date": "2021-11-02", "type": "Public-Co CEO"}, {"id": "botha-sequoias-crucible-moment#0", "t": "Patient capital after IPO generates exponentially higher returns: Square earned 9x by IPO but 90x from patient distributions years later.", "guest": "Roelof Botha", "slug": "botha-sequoias-crucible-moment", "date": "2021-11-05", "type": "VC"}, {"id": "botha-sequoias-crucible-moment#2", "t": "Permanent capital structures let VCs hold through full lifecycle, founders think longer-term, and LPs capture full post-IPO value creation.", "guest": "Roelof Botha", "slug": "botha-sequoias-crucible-moment", "date": "2021-11-05", "type": "VC"}, {"id": "marshall-indexing-the-earth#0", "t": "Proprietary hardware creates insurmountable moats: 450 satellites, 6+ years to deploy, 18 design iterations. Competitors face 10-year setup cost.", "guest": "Will Marshall", "slug": "marshall-indexing-the-earth", "date": "2021-11-16", "type": "Founder / Operator"}, {"id": "marshall-indexing-the-earth#1", "t": "Data businesses scale to zero marginal cost: collect imagery once, resell to agriculture, insurance, finance, government infinitely. Profit margins explode.", "guest": "Will Marshall", "slug": "marshall-indexing-the-earth", "date": "2021-11-16", "type": "Founder / Operator"}, {"id": "shah-developing-every-skill#1", "t": "Repeat customers drive profit curves: year 1 acquisition cost; years 2-5 extremely profitable as marketing efficiency soars and spend per customer grows.", "guest": "Niraj Shah", "slug": "shah-developing-every-skill", "date": "2021-11-23", "type": "Founder / Operator"}, {"id": "shah-developing-every-skill#2", "t": "Vertical integration in logistics creates rare asymmetry: simultaneous lower costs, faster delivery, less damage. Few businesses get this trifecta.", "guest": "Niraj Shah", "slug": "shah-developing-every-skill", "date": "2021-11-23", "type": "Founder / Operator"}, {"id": "davidson-design-led-hospitality#0", "t": "Hospitality franchises earn percentage-of-revenue, so cost reduction destroys their value—tech operators filling this gap have structural competitive advantage.", "guest": "Francis Davidson", "slug": "davidson-design-led-hospitality", "date": "2021-11-30", "type": "Founder / Operator"}, {"id": "davidson-design-led-hospitality#1", "t": "Asset-light operators managing properties without owning them can match property-owner margins (25%+) through tech efficiency, enabling capital velocity to scale faster.", "guest": "Francis Davidson", "slug": "davidson-design-led-hospitality", "date": "2021-11-30", "type": "Founder / Operator"}, {"id": "gurley-back-to-the-future#0", "t": "Centralized platforms with network effects (Discord, Twitter Spaces) currently outperform decentralized alternatives; governance overhead may not justify token complexity.", "guest": "Philip Rosedale & Bill Gurley", "slug": "gurley-back-to-the-future", "date": "2021-12-07", "type": "Founder / Operator"}, {"id": "gurley-back-to-the-future#1", "t": "Market for avatar-based escapism may be 10-50M adults globally, not billions; communication-centric digital places (audio-first) have much larger addressable market.", "guest": "Philip Rosedale & Bill Gurley", "slug": "gurley-back-to-the-future", "date": "2021-12-07", "type": "Founder / Operator"}, {"id": "colkitt-the-evolution-of-markets#0", "t": "Market infrastructure efficiency compounds across millions of transactions; small friction reductions (latency, gas, slippage) create massive advantage.", "guest": "Doug Colkitt", "slug": "colkitt-the-evolution-of-markets", "date": "2021-12-14", "type": "Founder / Operator"}, {"id": "johnson-seven-decades-of-investing-expertise#1", "t": "Democratizing private assets to retail (once gated to qualified investors) is the industry's next frontier—just as mutual funds opened equities in the 1920s.", "guest": "Jenny Johnson", "slug": "johnson-seven-decades-of-investing-expertise", "date": "2021-12-21", "type": "Public-Co CEO"}, {"id": "johnson-seven-decades-of-investing-expertise#2", "t": "AI and alternative data sources (geolocation, employer capitalization, submission timing) surface micro-signals that traditional analysis misses and reduce adverse selection.", "guest": "Jenny Johnson", "slug": "johnson-seven-decades-of-investing-expertise", "date": "2021-12-21", "type": "Public-Co CEO"}, {"id": "bravo-the-art-of-software-buyouts#0", "t": "Market-leading SaaS (best product, 20%+ growth, 35%+ EBITDA) at 30-35 PE offers better risk-adjusted returns than S&P 500 at 23 PE growth rate of 7%.", "guest": "Orlando Bravo", "slug": "bravo-the-art-of-software-buyouts", "date": "2021-12-28", "type": "PE / Buyout"}, {"id": "bravo-the-art-of-software-buyouts#1", "t": "Operational leverage, not financial leverage, drives PE software returns; returns come from profitability + growth, not debt; high entry multiples constrain leverage benefit.", "guest": "Orlando Bravo", "slug": "bravo-the-art-of-software-buyouts", "date": "2021-12-28", "type": "PE / Buyout"}, {"id": "sandler-building-an-investment-compass#0", "t": "Mispricings arise from passive flows, event uncertainty, negative sentiment cascades; understanding the other side's logic is the sustainable edge vs indices.", "guest": "Ricky Sandler", "slug": "sandler-building-an-investment-compass", "date": "2022-01-18", "type": "Hedge Fund"}, {"id": "sandler-building-an-investment-compass#2", "t": "Private company valuations (50+ sales multiples) will compress toward 12-15x earnings when IPOs distribute to public markets; current crossover pricing is speculative.", "guest": "Ricky Sandler", "slug": "sandler-building-an-investment-compass", "date": "2022-01-18", "type": "Hedge Fund"}, {"id": "englebardt-investing-in-immersive-worlds#0", "t": "Avoid beta plays in infinite-supply categories. Invest in platform proxies, first-mover collections, and artists with community velocity instead.", "guest": "Sam Englebardt & Richard Kim", "slug": "englebardt-investing-in-immersive-worlds", "date": "2022-01-20", "type": "VC"}, {"id": "englebardt-investing-in-immersive-worlds#2", "t": "Community forms around shared values first, currency second. Tokens that don't answer 'why would someone buy this?' beyond speculation eventually collapse.", "guest": "Sam Englebardt & Richard Kim", "slug": "englebardt-investing-in-immersive-worlds", "date": "2022-01-20", "type": "VC"}, {"id": "baker-the-cyclone-under-the-surface#0", "t": "Treat lead-time inflections as the semi-cycle signal — reported demand is always distorted above or below true demand by the inventory feedback loop.", "guest": "Gavin Baker", "slug": "baker-the-cyclone-under-the-surface", "date": "2022-01-25", "type": "Public Markets"}, {"id": "baker-the-cyclone-under-the-surface#1", "t": "Hire public-markets investors for one trait: the ability to stay rational when wrong. Batting average matters less than capturing the fat tails.", "guest": "Gavin Baker", "slug": "baker-the-cyclone-under-the-surface", "date": "2022-01-25", "type": "Public Markets"}, {"id": "moore-building-gorilla-businesses#0", "t": "Identify which phase of adoption a category is in before investing. Tornado phase companies with weak fundamentals beat main-street companies with strong ones. Category phase dominates all else.", "guest": "Geoffrey Moore", "slug": "moore-building-gorilla-businesses", "date": "2022-01-27", "type": "Academic / Author"}, {"id": "moore-building-gorilla-businesses#2", "t": "Chimps lose systematically. They often have good businesses but can't compete on the gorilla's standards. Avoid them; go gorilla or go home.", "guest": "Geoffrey Moore", "slug": "moore-building-gorilla-businesses", "date": "2022-01-27", "type": "Academic / Author"}, {"id": "levin-building-an-anti-conglomerate#1", "t": "Investing on a forever timeline is a very different structure than a lot of capital is organized.", "guest": "Joey Levin", "slug": "levin-building-an-anti-conglomerate", "date": "2022-02-15", "type": "PE / Buyout"}, {"id": "slootman-narrow-the-focus-increase-the-quality#0", "t": "Master your own distribution channel; relying on OEM models or third-party platforms surrenders control of destiny and moat-building.", "guest": "Frank Slootman", "slug": "slootman-narrow-the-focus-increase-the-quality", "date": "2022-02-22", "type": "Public-Co CEO"}, {"id": "slootman-narrow-the-focus-increase-the-quality#1", "t": "Growth is mechanical and observable: break it into components, instrument each, and push boundaries to find where limits actually exist.", "guest": "Frank Slootman", "slug": "slootman-narrow-the-focus-increase-the-quality", "date": "2022-02-22", "type": "Public-Co CEO"}, {"id": "mandelblatt-investing-in-the-industrial-economy#1", "t": "Railroads as picks-and-shovels play: CSX and Union Pacific have ~40% EBIT margins, capital returns approaching 100% of market cap over 10 years, and 150-year moat.", "guest": "Eric Mandelblatt", "slug": "mandelblatt-investing-in-the-industrial-economy", "date": "2022-03-01", "type": "VC"}, {"id": "mandelblatt-investing-in-the-industrial-economy#2", "t": "Carbon taxes and decarbonization create second-order profits: clean aluminum producers (Alcoa) gain $1,200/ton vs. Chinese competitors, worth $8+ per share per $100 carbon tax.", "guest": "Eric Mandelblatt", "slug": "mandelblatt-investing-in-the-industrial-economy", "date": "2022-03-01", "type": "VC"}, {"id": "tan-unwrapping-the-gift#0", "t": "Systematize venture through speed (48-72 hour decisions), diverse expertise, and blind voting; throughput beats genius investor.", "guest": "Garry Tan", "slug": "tan-unwrapping-the-gift", "date": "2022-03-08", "type": "VC"}, {"id": "tan-unwrapping-the-gift#1", "t": "Product quality is founder quality: smooth scrolling, polished demo, and attention to detail reveal whether builder can attract other builders.", "guest": "Garry Tan", "slug": "tan-unwrapping-the-gift", "date": "2022-03-08", "type": "VC"}, {"id": "papic-a-multi-polar-world#0", "t": "Stagflation scenario (6-9% CPI with Fed accommodation): favor real assets—energy, commodities, real estate, gold. No final rally before recession if yield curve inverted.", "guest": "Marko Papic", "slug": "papic-a-multi-polar-world", "date": "2022-03-15", "type": "Other"}, {"id": "papic-a-multi-polar-world#1", "t": "Supply chain fragmentation into spheres creates structural inflation and scarcity premiums; bet on critical materials (palladium, potash, semiconductors) and national redundancy winners.", "guest": "Marko Papic", "slug": "papic-a-multi-polar-world", "date": "2022-03-15", "type": "Other"}, {"id": "kapadia-everything-compounds#0", "t": "Cable stocks looked cheap because TV was high-revenue, low-profit; real value was broadband monopoly. Look for businesses mislabeled by the market.", "guest": "Gaurav Kapadia", "slug": "kapadia-everything-compounds", "date": "2022-03-22", "type": "Hedge Fund"}, {"id": "kapadia-everything-compounds#2", "t": "Building decades-long relationships with management and boards unlocks early access to best deals. Depth of knowledge beats breadth of portfolio.", "guest": "Gaurav Kapadia", "slug": "kapadia-everything-compounds", "date": "2022-03-22", "type": "Hedge Fund"}, {"id": "rubenstein-life-leadership-and-lbos#0", "t": "Private equity's 20-30% carry aligns incentives with returns; attracts world-class talent and consistently outperforms because economic rewards are tied to actual performance.", "guest": "David Rubenstein", "slug": "rubenstein-life-leadership-and-lbos", "date": "2022-03-29", "type": "PE / Buyout"}, {"id": "rubenstein-life-leadership-and-lbos#1", "t": "Government policy drives more returns than most investors recognize; companies ignoring lobbying/policy miss outsized opportunities (AWS/CIA contract example shows how policy legitimizes and scales categories).", "guest": "David Rubenstein", "slug": "rubenstein-life-leadership-and-lbos", "date": "2022-03-29", "type": "PE / Buyout"}, {"id": "balyasny-building-a-better-model#0", "t": "Platform models with 125+ diversified risk-takers across strategies produce durable alpha; single-manager model volatility is structural, not talent-dependent.", "guest": "Dmitry Balyasny", "slug": "balyasny-building-a-better-model", "date": "2022-04-26", "type": "Public Markets"}, {"id": "balyasny-building-a-better-model#2", "t": "Structure short books as relative value spreads across diverse trades, not binary zero-vs-winner bets; this dramatically reduces volatility and diversifies edge sources.", "guest": "Dmitry Balyasny", "slug": "balyasny-building-a-better-model", "date": "2022-04-26", "type": "Public Markets"}, {"id": "glyman-reimagining-corporate-finance#0", "t": "Customer insight beats feature list; real problems (chaos, inefficiency) matter more than wishlist features (points, lounges).", "guest": "Eric Glyman", "slug": "glyman-reimagining-corporate-finance", "date": "2022-05-03", "type": "Founder / Operator"}, {"id": "glyman-reimagining-corporate-finance#1", "t": "Founder equity with aligned incentives attracts talent better than cash; founder shares, delayed incorporation, tax optimization signal founder commitment.", "guest": "Eric Glyman", "slug": "glyman-reimagining-corporate-finance", "date": "2022-05-03", "type": "Founder / Operator"}, {"id": "jordan-building-investing-in-marketplaces#0", "t": "Marketplace defensibility requires network effects; avoid D2C (mattress, meals, tiles) without defensibility—all hit growth ceilings within years without moat.", "guest": "Jeff Jordan", "slug": "jordan-building-investing-in-marketplaces", "date": "2022-05-10", "type": "VC"}, {"id": "jordan-building-investing-in-marketplaces#1", "t": "Fragmented supply creates moat; optimize for buyers because they drive supply growth; seller concentration means platform weakness and defection risk.", "guest": "Jeff Jordan", "slug": "jordan-building-investing-in-marketplaces", "date": "2022-05-10", "type": "VC"}, {"id": "gross-identifying-talent#0", "t": "Search for undervalued traits (low market price), not intrinsically good ones. Competitors have already bid up conscientiousness and smarts.", "guest": "Tyler Cowen & Daniel Gross", "slug": "gross-identifying-talent", "date": "2022-05-17", "type": "Academic / Author"}, {"id": "gross-identifying-talent#2", "t": "High-variance outliers beat consensus hires. Find specialists where uneven skills fit niche roles; avoid committee hiring that optimizes for agreeableness.", "guest": "Tyler Cowen & Daniel Gross", "slug": "gross-identifying-talent", "date": "2022-05-17", "type": "Academic / Author"}, {"id": "lutke-embrace-the-unexpected#1", "t": "Unit economics and profitability control destiny better than capital optionality. Raise in good times for rainy days; profit your way through downturns.", "guest": "Tobi Lütke", "slug": "lutke-embrace-the-unexpected", "date": "2022-05-24", "type": "Founder / Operator"}, {"id": "lutke-embrace-the-unexpected#2", "t": "Most infrastructure value is unquantifiable. Second and third-order effects drive returns; resist spreadsheet primacy and trust informed intuition.", "guest": "Tobi Lütke", "slug": "lutke-embrace-the-unexpected", "date": "2022-05-24", "type": "Founder / Operator"}, {"id": "damodaran-teaching-the-world-finance#0", "t": "Unexpected inflation is the killer; focus portfolio on assets and companies that can adjust prices rapidly (subscription, non-discretionary, short-term investments).", "guest": "Aswath Damodaran", "slug": "damodaran-teaching-the-world-finance", "date": "2022-05-31", "type": "Academic / Author"}, {"id": "damodaran-teaching-the-world-finance#1", "t": "Narratives compound value more than ratios; find companies with consistent 10-20 year stories and CEOs who act on them, not quarterly pivots.", "guest": "Aswath Damodaran", "slug": "damodaran-teaching-the-world-finance", "date": "2022-05-31", "type": "Academic / Author"}, {"id": "casado-the-past-present-and-future-of-digital-infrastructure#0", "t": "For API-first companies, abandon traditional due diligence; trust usage graphs over your go-to-market thesis. Consumption patterns reveal truth faster than analysis.", "guest": "Martin Casado", "slug": "casado-the-past-present-and-future-of-digital-infrastructure", "date": "2022-06-07", "type": "VC"}, {"id": "casado-the-past-present-and-future-of-digital-infrastructure#2", "t": "SaaS companies pay cloud providers as COGS. $200B in market cap could unlock by halving cloud spend—a major re-optimization opportunity for public companies.", "guest": "Martin Casado", "slug": "casado-the-past-present-and-future-of-digital-infrastructure", "date": "2022-06-07", "type": "VC"}, {"id": "wolfe-factories-of-the-future#0", "t": "Hiring velocity is a leading signal: ex-SpaceX and ex-Blue Origin engineers racing to join reveals deeper conviction than any market research. Focus on who the founder can attract.", "guest": "Josh Wolfe & Chris Power", "slug": "wolfe-factories-of-the-future", "date": "2022-06-14", "type": "VC"}, {"id": "wolfe-factories-of-the-future#1", "t": "Deep tech requires capital intensity by design; it's a moat. Unlike software (bootstrappable), hardware defensibility grows with manufacturing scale and supply chain control.", "guest": "Josh Wolfe & Chris Power", "slug": "wolfe-factories-of-the-future", "date": "2022-06-14", "type": "VC"}, {"id": "jett-investing-in-e-commerce#0", "t": "Coupang proves vertical integration works but costs $3B+ upfront to prefund. Durable moat requires obsessive efficiency culture + operational excellence, not just capital.", "guest": "Lydia Jett", "slug": "jett-investing-in-e-commerce", "date": "2022-06-21", "type": "VC"}, {"id": "jett-investing-in-e-commerce#1", "t": "Vision Fund's scale ($100B AUM) shows capital-intensive businesses consume money fast without financial controls. Series B founders need CFO equivalents by definition.", "guest": "Lydia Jett", "slug": "jett-investing-in-e-commerce", "date": "2022-06-21", "type": "VC"}, {"id": "stanley-greatness-without-goals#0", "t": "Innovation requires proliferating stepping stones broadly and exposing them widely, not pursuing a single objective metric through a centralized authority.", "guest": "Ken Stanley", "slug": "stanley-greatness-without-goals", "date": "2022-06-28", "type": "Academic / Author"}, {"id": "lee-designing-investment-products#0", "t": "Venture as product: winning firms differentiate via portfolio of scalable supports (Arc curriculum, Ampersand app, data science platform) that create tangible founder moats beyond capital.", "guest": "Jess Lee", "slug": "lee-designing-investment-products", "date": "2022-07-05", "type": "VC"}, {"id": "lee-designing-investment-products#1", "t": "Underserved personas unlock venture returns: women control 80% household purchases and 70% healthcare decisions yet received flat capital allocation for 4+ years—solving this gap creates outsized returns.", "guest": "Jess Lee", "slug": "lee-designing-investment-products", "date": "2022-07-05", "type": "VC"}, {"id": "bentinck-building-a-start-up-machine#0", "t": "Constrained founder supply outside Silicon Valley means 3-4x valuation discounts at pre-seed and seed rounds. Smart US capital can access 10-15M seed valuations vs 30-40M locally.", "guest": "Alice Bentinck", "slug": "bentinck-building-a-start-up-machine", "date": "2022-07-12", "type": "Founder / Operator"}, {"id": "bentinck-building-a-start-up-machine#1", "t": "Talent-matching requires operational intensity: selection, cohort culture, difficult-conversation norms, weekly checkins. Most VC model can't justify this; balance-sheet company enables it.", "guest": "Alice Bentinck", "slug": "bentinck-building-a-start-up-machine", "date": "2022-07-12", "type": "Founder / Operator"}, {"id": "ball-a-primer-on-the-metaverse#0", "t": "Interoperability is the unseen asset in the metaverse economy: platforms that enable portability of identity, avatars, payments, and objects across worlds create the network effects that compound valuations.", "guest": "Matthew Ball", "slug": "ball-a-primer-on-the-metaverse", "date": "2022-07-19", "type": "VC"}, {"id": "ball-a-primer-on-the-metaverse#2", "t": "Platform power and payment rails are underpriced risks: whoever controls metaverse transactions takes a cut on trillions of GDP; Apple's 30% fee already extracted billions from Meta, making platform wars the real battleground.", "guest": "Matthew Ball", "slug": "ball-a-primer-on-the-metaverse", "date": "2022-07-19", "type": "VC"}, {"id": "vasudev-searching-for-white-space#0", "t": "Retail speculation has been underestimated as a driver of innovation funding in crypto. Many DeFi yields traced back to token appreciation (retail-driven), not structural cash flows. When retail vanishes, so do eye-popping yields.", "guest": "Alok Vasudev", "slug": "vasudev-searching-for-white-space", "date": "2022-07-26", "type": "VC"}, {"id": "vasudev-searching-for-white-space#1", "t": "Sustainable yields in crypto come from blockchain security (staking), not speculation. Real structural sources (MakerDAO fees, liquidity provision) will be smaller but durable.", "guest": "Alok Vasudev", "slug": "vasudev-searching-for-white-space", "date": "2022-07-26", "type": "VC"}, {"id": "thorndike-the-power-of-long-holding-periods#0", "t": "Holding periods compound returns exponentially: 20%+ IRR over 20 years (50X MOIC) is the measurable bar. This requires CEO/investor conviction through crises (9/11, COVID, 60 Minutes investigations). Conviction is built through deep research and adding to positions during dislocations.", "guest": "Will Thorndike", "slug": "thorndike-the-power-of-long-holding-periods", "date": "2022-08-02", "type": "PE / Buyout"}, {"id": "thorndike-the-power-of-long-holding-periods#1", "t": "Debt as leverage for long-term acquisition is asymmetric: if you have low-churn revenue and high ROTC, leverage unlocks geometric acquisition scaling without equity dilution. TransDigm required only $25M equity for $35B today.", "guest": "Will Thorndike", "slug": "thorndike-the-power-of-long-holding-periods", "date": "2022-08-02", "type": "PE / Buyout"}, {"id": "gupta-focus#0", "t": "Identify your fund's singular main thing (e.g., stage, thesis, geography) and don't compromise it with secondary goals that dilute returns.", "guest": "Ravi Gupta", "slug": "gupta-focus", "date": "2022-08-09", "type": "VC"}, {"id": "boyle-investing-for-america#1", "t": "Defense/aerospace/hardware faces a procurement/talent bottleneck; startup founders with tech talent have outsized leverage.", "guest": "Katherine Boyle", "slug": "boyle-investing-for-america", "date": "2022-08-16", "type": "VC"}, {"id": "boyle-investing-for-america#2", "t": "Regulatory complexity (not government size) is the real moat for innovative companies; fix one bottleneck and create 10x value.", "guest": "Katherine Boyle", "slug": "boyle-investing-for-america", "date": "2022-08-16", "type": "VC"}, {"id": "smith-investing-in-enterprise-software#0", "t": "Enterprise software multiples expand and contract with capital cycles; buy at rational multiples (0.4x revenue/growth vs. market 0.6x+) for outsized returns.", "guest": "Robert Smith", "slug": "smith-investing-in-enterprise-software", "date": "2022-08-23", "type": "PE / Buyout"}, {"id": "smith-investing-in-enterprise-software#2", "t": "Net dollar retention >100% + low customer concentration = recession-proof software; churn analysis reveals industry health, not just company performance.", "guest": "Robert Smith", "slug": "smith-investing-in-enterprise-software", "date": "2022-08-23", "type": "PE / Buyout"}, {"id": "senra-passion-pain#0", "t": "Study founder psychology through biographies; exceptional outcomes correlate with fanatical obsession and pain tolerance.", "guest": "David Senra", "slug": "senra-passion-pain", "date": "2022-08-30", "type": "Founder / Operator"}, {"id": "senra-passion-pain#2", "t": "Generational thinking—how decisions affect unborn descendants—yields different choices than short-term optimization.", "guest": "David Senra", "slug": "senra-passion-pain", "date": "2022-08-30", "type": "Founder / Operator"}, {"id": "spear-billion-dollar-scrubs#0", "t": "Fragmented, intermediary-heavy industries leave massive margin on table; vertical integration in non-discretionary categories unlocks 30-50% gross margins.", "guest": "Trina Spear", "slug": "spear-billion-dollar-scrubs", "date": "2022-09-20", "type": "Founder / Operator"}, {"id": "spear-billion-dollar-scrubs#1", "t": "D2C replenishment models work because they combine low CAC (word-of-mouth), high LTV (repeat buys), and pricing power—opposite of discretionary D2C apparel.", "guest": "Trina Spear", "slug": "spear-billion-dollar-scrubs", "date": "2022-09-20", "type": "Founder / Operator"}, {"id": "pencz-investing-in-latin-america#0", "t": "LatAm's tech penetration at 1.5% of GDP (vs 50% in US) creates greenfield opportunities in fintech, SMB software, real estate that dwarf US market size despite lower GDP.", "guest": "Julio Vasconcellos & Mate Pencz", "slug": "pencz-investing-in-latin-america", "date": "2022-09-27", "type": "VC"}, {"id": "wilson-global-endowment-investing#0", "t": "Non-traditional endowment models with 30 core manager partners and 20%+ co-investment allocations outperform benchmarks by 100-200 bps—compounding to $12B+ over 20 years.", "guest": "Scott Wilson", "slug": "wilson-global-endowment-investing", "date": "2022-10-04", "type": "VC"}, {"id": "wilson-global-endowment-investing#1", "t": "Venture entry valuation inflation is structural: entry multiples 5-8x today after producing 5-8x returns historically—future industry returns face permanent headwind vs private equity.", "guest": "Scott Wilson", "slug": "wilson-global-endowment-investing", "date": "2022-10-04", "type": "VC"}, {"id": "ramanujam-how-to-price-products#0", "t": "Test pricing hypotheses with potential customers before launch using relative anchors (e.g., 'If Salesforce is $100, where should we be?') rather than absolute price questions.", "guest": "Madhavan Ramanujam", "slug": "ramanujam-how-to-price-products", "date": "2022-10-11", "type": "Academic / Author"}, {"id": "ramanujam-how-to-price-products#1", "t": "Build different product versions for different willingness-to-pay segments, not one product positioned to many. Apple iPhone's multi-tier pricing is productization, not positioning.", "guest": "Madhavan Ramanujam", "slug": "ramanujam-how-to-price-products", "date": "2022-10-11", "type": "Academic / Author"}, {"id": "orfalea-its-about-the-money#0", "t": "Watch the founder's behavior with service staff and family at dinner—integrity shown in private mirrors how they'll treat partners and employees.", "guest": "Paul Orfalea", "slug": "orfalea-its-about-the-money", "date": "2022-10-18", "type": "Founder / Operator"}, {"id": "orfalea-its-about-the-money#1", "t": "Beware post-acquisition culture clash. Founders prioritize the achieving organization; acquirers often care only about loyalty. This triggers talent exodus.", "guest": "Paul Orfalea", "slug": "orfalea-its-about-the-money", "date": "2022-10-18", "type": "Founder / Operator"}, {"id": "droege-building-a-second-act#0", "t": "Don't just try lots of ideas hoping one sticks. Strong conviction on a big idea, then multiple execution paths around it, beats scatter-shot pivoting.", "guest": "Jason Droege", "slug": "droege-building-a-second-act", "date": "2022-10-25", "type": "Founder / Operator"}, {"id": "droege-building-a-second-act#1", "t": "Marketplace founders need financial acumen (margin structure, willingness to pay, unit economics) as much as product intuition. This is founder market fit.", "guest": "Jason Droege", "slug": "droege-building-a-second-act", "date": "2022-10-25", "type": "Founder / Operator"}, {"id": "droege-building-a-second-act#2", "t": "Growing 600% then 300% then 250% pulls forward growth but defers hyperpain. Restarted today, these businesses would have lower headcount, slower growth, but more runway.", "guest": "Jason Droege", "slug": "droege-building-a-second-act", "date": "2022-10-25", "type": "Founder / Operator"}, {"id": "droege-building-a-second-act#3", "t": "Incentive structures matter. Entrepreneurial outcomes require more than equity. Build trust first, then align on outsized economic outcome without tying it to specific revenue milestones.", "guest": "Jason Droege", "slug": "droege-building-a-second-act", "date": "2022-10-25", "type": "Founder / Operator"}, {"id": "green-investing-in-consumer-change#1", "t": "Brand-led differentiation in commodity categories is possible (Warby Parker in eyeglasses). Look for founders with unique insight into customer psychology.", "guest": "Kirsten Green", "slug": "green-investing-in-consumer-change", "date": "2022-11-01", "type": "VC"}, {"id": "elliott-a-macro-tour#0", "t": "Identify which macro regime you're in (easy vs. tight, growth vs. stagflation). Asset allocation differs radically across regimes—60-40 fails in inflation.", "guest": "Bob Elliott", "slug": "elliott-a-macro-tour", "date": "2022-11-08", "type": "Hedge Fund"}, {"id": "elliott-a-macro-tour#2", "t": "Quantitative approaches to venture outperform gut-feel. Founder age, repeat status, data patterns generate repeatable edge better than gut-based hiring decisions.", "guest": "Bob Elliott", "slug": "elliott-a-macro-tour", "date": "2022-11-08", "type": "Hedge Fund"}, {"id": "conrad-building-a-compound-company#0", "t": "Compound businesses achieve unit economics in smaller markets by capturing high wallet share per customer, justifying lower CAC than point solutions need.", "guest": "Parker Conrad", "slug": "conrad-building-a-compound-company", "date": "2022-11-15", "type": "Founder / Operator"}, {"id": "conrad-building-a-compound-company#1", "t": "Deep integration with employee data and middleware creates structural advantages competitors cannot match without complete architectural redesign.", "guest": "Parker Conrad", "slug": "conrad-building-a-compound-company", "date": "2022-11-15", "type": "Founder / Operator"}, {"id": "battier-how-to-win#0", "t": "Seek high-ROI catalysts: humility + selflessness + work ethic at 95th+ percentile. These compound value at low cost, like Shane's defense.", "guest": "Shane Battier", "slug": "battier-how-to-win", "date": "2022-11-22", "type": "Athlete / Coach"}, {"id": "battier-how-to-win#1", "t": "Build gel teams (high trust + high mission). Brittle teams (mission-driven but distrustful) shatter under stress.", "guest": "Shane Battier", "slug": "battier-how-to-win", "date": "2022-11-22", "type": "Athlete / Coach"}, {"id": "lowin-explaining-the-new-ai-paradigm#2", "t": "Success depends on finding underexploited use cases where the model output quality matches real user needs, not just pushing generalized models.", "guest": "Jeremiah Lowin", "slug": "lowin-explaining-the-new-ai-paradigm", "date": "2022-12-13", "type": "Founder / Operator"}, {"id": "mauboussin-sharpening-investor-executive-toolkits#0", "t": "Buy companies showing positive ROIC transitions (moving from low to high quintiles) with evidence their advantage is sustainable, not priced in.", "guest": "Michael Mauboussin", "slug": "mauboussin-sharpening-investor-executive-toolkits", "date": "2022-12-20", "type": "Public Markets"}, {"id": "mauboussin-sharpening-investor-executive-toolkits#1", "t": "When concentrating capital, focus on market share stability and entry/exit rates—these predict real competitive moats better than current dominance.", "guest": "Michael Mauboussin", "slug": "mauboussin-sharpening-investor-executive-toolkits", "date": "2022-12-20", "type": "Public Markets"}, {"id": "lynn-finding-your-customers#0", "t": "CMO/GTM expertise is rare at early stage; VCs with go-to-market networks (advisors, hires, agencies) create material edge helping Series A/B scale.", "guest": "Rebecca Lynn", "slug": "lynn-finding-your-customers", "date": "2022-12-27", "type": "VC"}, {"id": "lynn-finding-your-customers#2", "t": "Market needs to be big enough for simple product adoption; if it requires 15 decisions, most consumers fail; design friction out.", "guest": "Rebecca Lynn", "slug": "lynn-finding-your-customers", "date": "2022-12-27", "type": "VC"}, {"id": "masad-the-future-of-software-creation#0", "t": "Invest in AI infrastructure: hardware (NVIDIA), foundational models (OpenAI), and accessible platforms (Replit). These capture disproportionate value as AI becomes general-purpose.", "guest": "Amjad Masad", "slug": "masad-the-future-of-software-creation", "date": "2023-01-03", "type": "Founder / Operator"}, {"id": "masad-the-future-of-software-creation#2", "t": "Entire industries will fail if tied to pre-AI skill verification (interview prep). Companies teaching algorithm memorization have 2-year runway before obsolescence.", "guest": "Amjad Masad", "slug": "masad-the-future-of-software-creation", "date": "2023-01-03", "type": "Founder / Operator"}, {"id": "fiorentino-creating-magic-for-consumers#0", "t": "Consumer products don't require venture funding if they tap real demand. A 20% conversion rate on 1,000-person test = product-market fit on day one. If you need investment, you don't have a business.", "guest": "John Fiorentino", "slug": "fiorentino-creating-magic-for-consumers", "date": "2023-01-10", "type": "Founder / Operator"}, {"id": "fiorentino-creating-magic-for-consumers#2", "t": "Venture mechanics kill consumer magic. Short-term shareholder pressure forces founders to quantify the unquantifiable, destroying the soul that made the business valuable in the first place.", "guest": "John Fiorentino", "slug": "fiorentino-creating-magic-for-consumers", "date": "2023-01-10", "type": "Founder / Operator"}, {"id": "grimshaw-assessing-the-dna-of-software-companies#0", "t": "Spot business genetics early: sticky data (high switching cost), cross-functional adoption (seat expansion), ecosystem potential (platforms others build on), and multi-product expansion capacity are more predictive than current revenue.", "guest": "Miles Grimshaw", "slug": "grimshaw-assessing-the-dna-of-software-companies", "date": "2023-01-17", "type": "VC"}, {"id": "grimshaw-assessing-the-dna-of-software-companies#1", "t": "Customer selection determines product evolution. Seek fast-moving market leaders (Stripe had Lyft/DoorDash; Benchling had Regeneron) who pull you forward. Avoid big-name customers who slow you down or demand custom work.", "guest": "Miles Grimshaw", "slug": "grimshaw-assessing-the-dna-of-software-companies", "date": "2023-01-17", "type": "VC"}, {"id": "morey-systems-thinking-in-sports#1", "t": "Use expected-value frameworks for high-uncertainty decisions. Balance odds increase against variance; place decisions on efficient frontier, not on conviction alone.", "guest": "Daryl Morey", "slug": "morey-systems-thinking-in-sports", "date": "2023-01-24", "type": "Founder / Operator"}, {"id": "morey-systems-thinking-in-sports#2", "t": "Concentrate resources on proven value creators. Marginal players add 1-2 wins; superstars shift championships. This power-law concentration repeats across business.", "guest": "Daryl Morey", "slug": "morey-systems-thinking-in-sports", "date": "2023-01-24", "type": "Founder / Operator"}, {"id": "kawaja-dealing-with-regime-change#0", "t": "Regime changes create opportunity. Rising capital costs cut chaff projects; identify sectors shifting from growth to cash flow for outsized returns.", "guest": "Carl Kawaja", "slug": "kawaja-dealing-with-regime-change", "date": "2023-01-31", "type": "Public Markets"}, {"id": "kawaja-dealing-with-regime-change#1", "t": "Deep industry expertise beats trend-chasing. Energy transitions matter more than AI expertise for sustainable alpha. Study infrastructure, not just software.", "guest": "Carl Kawaja", "slug": "kawaja-dealing-with-regime-change", "date": "2023-01-31", "type": "Public Markets"}, {"id": "green-building-nyse-for-advertisers#0", "t": "Long-term business success requires choosing stakeholder allegiance carefully. Serving one side better than competitors creates objectivity advantage justifying premium multiples.", "guest": "Jeff Green", "slug": "green-building-nyse-for-advertisers", "date": "2023-02-07", "type": "Founder / Operator"}, {"id": "green-building-nyse-for-advertisers#1", "t": "Capital efficiency in early stages (profitability on <$10M vs competitors' $100M+) builds discipline that scales. Scarcity creates better habits than abundance.", "guest": "Jeff Green", "slug": "green-building-nyse-for-advertisers", "date": "2023-02-07", "type": "Founder / Operator"}, {"id": "rose-how-stunning-founders-operate#0", "t": "Evaluate founders on whether they've been right repeatedly, not just once. Prove judgment over time, not luck.", "guest": "Dan Rose", "slug": "rose-how-stunning-founders-operate", "date": "2023-02-14", "type": "VC"}, {"id": "rose-how-stunning-founders-operate#2", "t": "Look for founders who attract the best talent around them. That's a proxy for articulating and executing vision.", "guest": "Dan Rose", "slug": "rose-how-stunning-founders-operate", "date": "2023-02-14", "type": "VC"}, {"id": "leone-clear-and-simple#1", "t": "Go-to-market strategy must match product complexity. Applying sales playbooks from one category to another is a common, costly mistake.", "guest": "Doug Leone", "slug": "leone-clear-and-simple", "date": "2023-02-28", "type": "VC"}, {"id": "leone-clear-and-simple#2", "t": "Operational drag is invisible until it's too late. Calculate back-end resource consumption per sale before scaling sales headcount.", "guest": "Doug Leone", "slug": "leone-clear-and-simple", "date": "2023-02-28", "type": "VC"}, {"id": "stephens-find-good-quests#0", "t": "Deploy capital into 'n of one' founders in sectors that matter, even if valuation is slightly uncomfortable.", "guest": "Trae Stephens", "slug": "stephens-find-good-quests", "date": "2023-03-07", "type": "VC"}, {"id": "stephens-find-good-quests#2", "t": "Hire lobbyists early ($100K+/year minimum) for government-facing companies; it's table stakes, not optional.", "guest": "Trae Stephens", "slug": "stephens-find-good-quests", "date": "2023-03-07", "type": "VC"}, {"id": "hoffman-a-deep-dive-on-data#1", "t": "Create or adopt join keys in fragmented data categories; this is a powerful innovation vector that unlocks network value.", "guest": "Auren Hoffman", "slug": "hoffman-a-deep-dive-on-data", "date": "2023-03-14", "type": "Founder / Operator"}, {"id": "hoffman-a-deep-dive-on-data#2", "t": "Focus on one quadrant (truth vs religion × data vs application) until revenue reaches $300M+; most failures come from trying too much too soon.", "guest": "Auren Hoffman", "slug": "hoffman-a-deep-dive-on-data", "date": "2023-03-14", "type": "Founder / Operator"}, {"id": "goldfarb-the-disruptive-economics-of-ai#0", "t": "Find industries where most resources go to compensating customers for failures, not delivering the core mission—AI can strip that waste.", "guest": "Avi Goldfarb", "slug": "goldfarb-the-disruptive-economics-of-ai", "date": "2023-03-21", "type": "Academic / Author"}, {"id": "goldfarb-the-disruptive-economics-of-ai#2", "t": "Start data strategy by defining what you're trying to predict, then work backward to data needs. Collecting first, asking questions later wastes capital.", "guest": "Avi Goldfarb", "slug": "goldfarb-the-disruptive-economics-of-ai", "date": "2023-03-21", "type": "Academic / Author"}, {"id": "einhorn-the-long-and-short-of-investing#0", "t": "Shift from betting on revaluation to buying deeply discounted companies that return capital via buybacks/dividends; few analysts cover these names, but economics compound reliably.", "guest": "David Einhorn", "slug": "einhorn-the-long-and-short-of-investing", "date": "2023-03-28", "type": "Hedge Fund"}, {"id": "einhorn-the-long-and-short-of-investing#1", "t": "Concentrate beyond 15-20 holdings when conviction is high and insights rare; risking 20%+ on a best idea with asymmetric upside beats diversification into mediocre positions.", "guest": "David Einhorn", "slug": "einhorn-the-long-and-short-of-investing", "date": "2023-03-28", "type": "Hedge Fund"}, {"id": "varty-trail-magic#1", "t": "Invest in complex unglamorous sectors (accounting, audit software) where talented founders avoid, reducing entrepreneur supply and improving odds of founder quality.", "guest": "Sam Hinkie, Boyd Varty, & Charlie Songhurst", "slug": "varty-trail-magic", "date": "2023-04-04", "type": "Other"}, {"id": "wertheimer-lessons-from-the-industrial-titans#0", "t": "Industrial survivor bias teaches: companies lasting 100+ years proved systems work across cycles; tech's dismissal of these lessons as 'dinosaur advice' created vulnerability to correction.", "guest": "Scott Davis & Rob Wertheimer", "slug": "wertheimer-lessons-from-the-industrial-titans", "date": "2023-04-11", "type": "Public Markets"}, {"id": "wertheimer-lessons-from-the-industrial-titans#2", "t": "Boring operational leverage compounds best: Waste Management grows revenue 10%, earnings 15-20% through continuous improvement, low-risk capital redeployment, and internalized corporate wisdom.", "guest": "Scott Davis & Rob Wertheimer", "slug": "wertheimer-lessons-from-the-industrial-titans", "date": "2023-04-11", "type": "Public Markets"}, {"id": "simo-creating-delightful-consumer-experiences#0", "t": "Grocery remains vastly under-penetrated online (12% vs 25-30% for apparel/electronics); scale is the only path to unit-economics profitability through order batching and density.", "guest": "Fidji Simo", "slug": "simo-creating-delightful-consumer-experiences", "date": "2023-05-09", "type": "Public-Co CEO"}, {"id": "simo-creating-delightful-consumer-experiences#1", "t": "Data infrastructure is a defensible moat: rich catalogs, availability intel, and nutritional data enable AI experiences competitors can't easily replicate.", "guest": "Fidji Simo", "slug": "simo-creating-delightful-consumer-experiences", "date": "2023-05-09", "type": "Public-Co CEO"}, {"id": "karniol-tambour-macro-headwinds-vs-tech-tailwinds#0", "t": "AI-driven deflation could offset structural inflation from supply-chain resilience, decarbonization, and defense spending; net macro outcome determines regime", "guest": "Karen Karniol-Tambour", "slug": "karniol-tambour-macro-headwinds-vs-tech-tailwinds", "date": "2023-05-15", "type": "Hedge Fund"}, {"id": "karniol-tambour-macro-headwinds-vs-tech-tailwinds#1", "t": "U.S. equity valuations price in Fed pivot + contained recession + continued U.S. dominance; asymmetric downside if any assumption breaks", "guest": "Karen Karniol-Tambour", "slug": "karniol-tambour-macro-headwinds-vs-tech-tailwinds", "date": "2023-05-15", "type": "Hedge Fund"}, {"id": "karniol-tambour-macro-headwinds-vs-tech-tailwinds#2", "t": "Geopolitical multipolar shift reshuffles valuations: China repriced down (undervalued), U.S. repriced up (at risk), Japan ignored (deep value)", "guest": "Karen Karniol-Tambour", "slug": "karniol-tambour-macro-headwinds-vs-tech-tailwinds", "date": "2023-05-15", "type": "Hedge Fund"}, {"id": "schuck-finding-your-next-best-customer#0", "t": "Unique data is defensible only when embedded in automated workflows; standalone data is a painful lookup tool; workflows + data triggers + contact scoring = command center", "guest": "Henry Schuck", "slug": "schuck-finding-your-next-best-customer", "date": "2023-05-23", "type": "Founder / Operator"}, {"id": "schuck-finding-your-next-best-customer#1", "t": "Bootstrap companies that escape early survival bias high-bar founders; 7-year no-VC bootstrap forces real product-market fit discovery and cost discipline", "guest": "Henry Schuck", "slug": "schuck-finding-your-next-best-customer", "date": "2023-05-23", "type": "Founder / Operator"}, {"id": "schuck-finding-your-next-best-customer#2", "t": "Successful M&A requires running acquiree far more efficiently than they operated independently; integration playbook changes if acquired company has higher growth than acquirer", "guest": "Henry Schuck", "slug": "schuck-finding-your-next-best-customer", "date": "2023-05-23", "type": "Founder / Operator"}, {"id": "goodwin-imagination-volatility-and-the-pursuit-of-alpha#0", "t": "Private credit's vol washing masks leverage risk: fund-level leverage + mark-to-market delays create cascade risk when defaults rise and banks cut lending lines.", "guest": "Kieran Goodwin", "slug": "goodwin-imagination-volatility-and-the-pursuit-of-alpha", "date": "2023-05-30", "type": "Hedge Fund"}, {"id": "goodwin-imagination-volatility-and-the-pursuit-of-alpha#1", "t": "Long volatility in options at 100:1+ payoff multiples is systematically underpriced; the market can't price tail risk efficiently, creating asymmetric bets.", "guest": "Kieran Goodwin", "slug": "goodwin-imagination-volatility-and-the-pursuit-of-alpha", "date": "2023-05-30", "type": "Hedge Fund"}, {"id": "goodwin-imagination-volatility-and-the-pursuit-of-alpha#2", "t": "Information edges erode fast (distressed bankruptcy alpha flattened by Reorg; time & permanence of capital are durable alpha sources.", "guest": "Kieran Goodwin", "slug": "goodwin-imagination-volatility-and-the-pursuit-of-alpha", "date": "2023-05-30", "type": "Hedge Fund"}, {"id": "goodwin-know-the-names#0", "t": "Liability structure mismatches (long-dated assets + short-dated liabilities + leverage) create cascade risk; speed to liquidity provision is alpha when banks retreat.", "guest": "Scott Goodwin", "slug": "goodwin-know-the-names", "date": "2023-06-13", "type": "Hedge Fund"}, {"id": "goodwin-know-the-names#1", "t": "Credit cycle convexity: buy deeply distressed first-lien debt at $0.70+ when it's unfairly marked alongside junky names down 50%+; hold through commodity/sector recovery.", "guest": "Scott Goodwin", "slug": "goodwin-know-the-names", "date": "2023-06-13", "type": "Hedge Fund"}, {"id": "goodwin-know-the-names#2", "t": "Private credit opportunities shift from legacy vol-washed funds (most leverage, second-lien, equity co-invest) to de novo senior-secured first-lien at 50% LTV.", "guest": "Scott Goodwin", "slug": "goodwin-know-the-names", "date": "2023-06-13", "type": "Hedge Fund"}, {"id": "mares-the-us-health-crisis#0", "t": "Consumer health brands fighting subsidized commodity inputs face structural cost disadvantage; regenerative/ancestral sourcing requires 3-5x pricing power and founder-driven mission.", "guest": "Justin Mares", "slug": "mares-the-us-health-crisis", "date": "2023-06-20", "type": "Founder / Operator"}, {"id": "mares-the-us-health-crisis#1", "t": "Healthcare recurring revenue models (Ozempic: lifetime injections, weight-back guarantee) are business gold but public-health red flags; align incentives with outcomes, not volume.", "guest": "Justin Mares", "slug": "mares-the-us-health-crisis", "date": "2023-06-20", "type": "Founder / Operator"}, {"id": "mares-the-us-health-crisis#2", "t": "Repeat founders with domain expertise outperform generalist incubators in frontier tech; build tools/capital access for the exceptional, not systems for the average.", "guest": "Justin Mares", "slug": "mares-the-us-health-crisis", "date": "2023-06-20", "type": "Founder / Operator"}, {"id": "kelly-be-generous-unique#1", "t": "Follow the principle of 'be the only, not the best'—find what only you can do in a market", "guest": "Kevin Kelly", "slug": "kelly-be-generous-unique", "date": "2023-06-27", "type": "Other"}, {"id": "kelly-be-generous-unique#2", "t": "Money is rarely the gating factor for dreams; $1M often buys less than $200K of deliberate action", "guest": "Kevin Kelly", "slug": "kelly-be-generous-unique", "date": "2023-06-27", "type": "Other"}, {"id": "yuan-a-primer-on-vertical-market-software#0", "t": "Match investment strategy to market maturity—aggressive growth in disruptive phases, disciplined expansion in leadership positions", "guest": "Dave Yuan", "slug": "yuan-a-primer-on-vertical-market-software", "date": "2023-07-04", "type": "VC"}, {"id": "yuan-a-primer-on-vertical-market-software#1", "t": "Focus on cohorts and net retention mechanics; the difference between 94% and 99% gross retention is enormous for unit economics", "guest": "Dave Yuan", "slug": "yuan-a-primer-on-vertical-market-software", "date": "2023-07-04", "type": "VC"}, {"id": "giffon-special-situations-in-private-markets#0", "t": "Use comparative hurdle rates: 'Is it roughly as good or better than the last deal?' Reject deals that don't clear that bar", "guest": "Jeremy Giffon", "slug": "giffon-special-situations-in-private-markets", "date": "2023-07-11", "type": "PE / Buyout"}, {"id": "giffon-special-situations-in-private-markets#1", "t": "Focus on coordination problems: misaligned incentives between stakeholders create special situations for astute investors", "guest": "Jeremy Giffon", "slug": "giffon-special-situations-in-private-markets", "date": "2023-07-11", "type": "PE / Buyout"}, {"id": "giffon-special-situations-in-private-markets#2", "t": "Simple qualitative judgment beats complex quantitative analysis; smack-you-in-the-face obviousness is the key signal", "guest": "Jeremy Giffon", "slug": "giffon-special-situations-in-private-markets", "date": "2023-07-11", "type": "PE / Buyout"}, {"id": "kushner-building-thrive-capital#0", "t": "Concentrate in category leaders and hold for decades — sector value accrues to the number-one player, and trimming winners for perceived risk destroys outcomes.", "guest": "Josh Kushner", "slug": "kushner-building-thrive-capital", "date": "2023-07-18", "type": "VC"}, {"id": "kushner-building-thrive-capital#1", "t": "Interrogate the why-now before people or price: Oscar existed because the ACA flipped a 20%-of-GDP industry from B2B to B2C in a single moment.", "guest": "Josh Kushner", "slug": "kushner-building-thrive-capital", "date": "2023-07-18", "type": "VC"}, {"id": "traynor-the-reality-of-ai#0", "t": "Incumbent with speed beats startup with novelty. Measure competitive threat by % of legacy architecture still relevant. If 80%+ is, incumbents win.", "guest": "Des Traynor", "slug": "traynor-the-reality-of-ai", "date": "2023-08-08", "type": "Founder / Operator"}, {"id": "traynor-the-reality-of-ai#1", "t": "Beautiful product + high-velocity releases aren't moats. Moats are network effects (Twitter), irreplaceable data, or brand so strong it feels default (Slack, Figma).", "guest": "Des Traynor", "slug": "traynor-the-reality-of-ai", "date": "2023-08-08", "type": "Founder / Operator"}, {"id": "traynor-the-reality-of-ai#2", "t": "Rule out companies with 2-5 year runway claiming eventual profitability. If not growing in 6-12 months, shut down. Burning best years on zombies helps no one.", "guest": "Des Traynor", "slug": "traynor-the-reality-of-ai", "date": "2023-08-08", "type": "Founder / Operator"}, {"id": "ainslie-lee-ainslie#0", "t": "Concentrate (3.25 positions per analyst), hold long (17 months avg), and go deep (management dialogues). Information advantage comes from focus, not diversification.", "guest": "Lee Ainslie", "slug": "ainslie-lee-ainslie", "date": "2023-08-22", "type": "Hedge Fund"}, {"id": "ainslie-lee-ainslie#1", "t": "Higher rates environment (>2.5% Fed funds) outperforms by 6.5% alpha for long-short; low rates underperform by 4%. Macro regime is foundational, not secondary.", "guest": "Lee Ainslie", "slug": "ainslie-lee-ainslie", "date": "2023-08-22", "type": "Hedge Fund"}, {"id": "ainslie-lee-ainslie#2", "t": "Emotional consistency in investors predicts returns. Brilliant but volatile decision-makers destroy long-term value; steady performers with passion compound reliably.", "guest": "Lee Ainslie", "slug": "ainslie-lee-ainslie", "date": "2023-08-22", "type": "Hedge Fund"}, {"id": "england-a-primer-on-multi-strategy-hedge-funds#0", "t": "Multi-strategy beats single-strategy at scale. Individual strategies hit nimbleness/transaction-cost limits; pods diversify across tactics (long/short, quant, event-driven, macro) to unlock scale.", "guest": "Will England", "slug": "england-a-primer-on-multi-strategy-hedge-funds", "date": "2023-09-05", "type": "Hedge Fund"}, {"id": "england-a-primer-on-multi-strategy-hedge-funds#1", "t": "Hire for intellectual honesty first, not past performance. Many successful investors rode market tailwinds; ask them to articulate their edge and why it will repeat. Luck is not a hiring criterion.", "guest": "Will England", "slug": "england-a-primer-on-multi-strategy-hedge-funds", "date": "2023-09-05", "type": "Hedge Fund"}, {"id": "collison-a-business-state-of-mind#0", "t": "Prefer $0 billion markets to $10 billion ones — 'your margin is my opportunity' is a bet on stasis; causing new GDP beats displacing incumbents.", "guest": "Patrick Collison &amp; John Collison", "slug": "collison-a-business-state-of-mind", "date": "2023-10-17", "type": "Founder / Operator"}, {"id": "collison-a-business-state-of-mind#1", "t": "Infrastructure compounds slowly but durably: the internet never had an insane year, just 30% for decades — and 1.3^40 is a very large number.", "guest": "Patrick Collison &amp; John Collison", "slug": "collison-a-business-state-of-mind", "date": "2023-10-17", "type": "Founder / Operator"}, {"id": "collison-a-business-state-of-mind#2", "t": "In power-law customer bases, investigate single anecdotes of failure aggressively — the problems may be concentrated in your future biggest winners.", "guest": "Patrick Collison &amp; John Collison", "slug": "collison-a-business-state-of-mind", "date": "2023-10-17", "type": "Founder / Operator"}, {"id": "damodaran-making-sense-of-the-market-pt2#0", "t": "Stop blaming the Fed for underperformance; take responsibility for your strategy given actual market conditions and macro environment.", "guest": "Aswath Damodaran", "slug": "damodaran-making-sense-of-the-market-pt2", "date": "2023-10-24", "type": "Academic / Author"}, {"id": "damodaran-making-sense-of-the-market-pt2#1", "t": "Value companies by their narrative consistency, not ESG scores; a 250-year-old firm that adapts is more durable than virtue signaling.", "guest": "Aswath Damodaran", "slug": "damodaran-making-sense-of-the-market-pt2", "date": "2023-10-24", "type": "Academic / Author"}, {"id": "luckey-inventing-the-future-of-defense#0", "t": "Look for contrarian bets where the crowd has mis-sized the odds; governments making trillion-dollar technology bets on inferior paths create opportunity.", "guest": "Palmer Luckey", "slug": "luckey-inventing-the-future-of-defense", "date": "2023-10-31", "type": "Founder / Operator"}, {"id": "luckey-inventing-the-future-of-defense#1", "t": "Founder persistence through early friction—proven by shipping to market—often predicts ability to scale through future obstacles and criticism.", "guest": "Palmer Luckey", "slug": "luckey-inventing-the-future-of-defense", "date": "2023-10-31", "type": "Founder / Operator"}, {"id": "zalman-founder-vs-investor#0", "t": "Don't underestimate founder storytelling ability—it's not manipulation, it's marshaling resources through compelling vision articulation.", "guest": "Elizabeth Zalman & Jerry Neumann", "slug": "zalman-founder-vs-investor", "date": "2023-11-07", "type": "Founder / Operator"}, {"id": "zalman-founder-vs-investor#1", "t": "Seek VCs who can handle radical transparency rather than those who need sanitized board updates; transparency increases decision quality.", "guest": "Elizabeth Zalman & Jerry Neumann", "slug": "zalman-founder-vs-investor", "date": "2023-11-07", "type": "Founder / Operator"}, {"id": "jacobs-think-big-and-move-fast#2", "t": "If you look at the 500 or so acquisitions that I and my team have done, average multiples in the mid to high single digits.", "guest": "Brad Jacobs", "slug": "jacobs-think-big-and-move-fast", "date": "2023-11-14", "type": "Founder / Operator"}, {"id": "munger-a-conversation-with-charlie-munger-john-collison#0", "t": "Evaluate any track record dollar-weighted: a manager who compounded small money then fumbled big money can show a great history and a zero per-dollar-year return.", "guest": "Charlie Munger", "slug": "munger-a-conversation-with-charlie-munger-john-collison", "date": "2023-12-05", "type": "Public Markets"}, {"id": "munger-a-conversation-with-charlie-munger-john-collison#1", "t": "Diagnose industry structure before brand strength — capital-heavy idle capacity (airlines, early railroads) forces destructive competition no brand can survive.", "guest": "Charlie Munger", "slug": "munger-a-conversation-with-charlie-munger-john-collison", "date": "2023-12-05", "type": "Public Markets"}, {"id": "munger-a-conversation-with-charlie-munger-john-collison#2", "t": "Concentrate ruthlessly: wait patiently for the few clearly identifiable opportunities, then pounce hard — four great pounces make a lifetime.", "guest": "Charlie Munger", "slug": "munger-a-conversation-with-charlie-munger-john-collison", "date": "2023-12-05", "type": "Public Markets"}, {"id": "ishbia-a-system-for-success#1", "t": "And my view of the world is the last inefficient part of the private market ecosystem is a microcap", "guest": "Justin Ishbia", "slug": "ishbia-a-system-for-success", "date": "2023-12-19", "type": "Public-Co CEO"}, {"id": "serrano-the-investors-investor#0", "t": "When investing in asset managers, evaluate the founder-operator's discipline applied to building the business itself, not just their strategy.", "guest": "Erik Serrano", "slug": "serrano-the-investors-investor", "date": "2024-01-02", "type": "VC"}, {"id": "serrano-the-investors-investor#1", "t": "Distinguish between small-scale outperformance and repeatable, scalable returns—many managers excel with small capital but stumble at scale.", "guest": "Erik Serrano", "slug": "serrano-the-investors-investor", "date": "2024-01-02", "type": "VC"}, {"id": "ovitz-knowledge-is-power#0", "t": "When evaluating founders and operators, assess their ability to build mystique and create an aura that attracts talent—this is a force multiplier.", "guest": "Michael Ovitz", "slug": "ovitz-knowledge-is-power", "date": "2024-01-09", "type": "Founder / Operator"}, {"id": "ovitz-knowledge-is-power#2", "t": "Long-term power in any industry comes from positional advantage (knowledge, access, relationships) rather than individual talent alone.", "guest": "Michael Ovitz", "slug": "ovitz-knowledge-is-power", "date": "2024-01-09", "type": "Founder / Operator"}, {"id": "telford-unlocking-innovation-in-pharma#0", "t": "In biotech, investor success comes from understanding the regulatory landscape and timeline—a promising drug is worthless without approval.", "guest": "Alex Telford", "slug": "telford-unlocking-innovation-in-pharma", "date": "2024-01-30", "type": "Founder / Operator"}, {"id": "banister-investing-for-a-higher-purpose#0", "t": "Early-stage investing is qualitative, not quantitative; immerse yourself in diverse environments to spot unmet needs before others.", "guest": "Cyan Banister", "slug": "banister-investing-for-a-higher-purpose", "date": "2024-02-20", "type": "VC"}, {"id": "banister-investing-for-a-higher-purpose#1", "t": "Hold successful investments through volatility; avoid selling too early by setting and forgetting, then aligning exits with your north star.", "guest": "Cyan Banister", "slug": "banister-investing-for-a-higher-purpose", "date": "2024-02-20", "type": "VC"}, {"id": "banister-investing-for-a-higher-purpose#2", "t": "Scout founders in unconventional places (conventions, communities) where you encounter real problems; great founders often come from lived experience.", "guest": "Cyan Banister", "slug": "banister-investing-for-a-higher-purpose", "date": "2024-02-20", "type": "VC"}, {"id": "banister-investing-for-a-higher-purpose#3", "t": "The best early-stage value is being a 'bubbe'—providing hard feedback with unconditional love, then opening doors when founders need help.", "guest": "Cyan Banister", "slug": "banister-investing-for-a-higher-purpose", "date": "2024-02-20", "type": "VC"}, {"id": "banister-investing-for-a-higher-purpose#4", "t": "Your intuition improves with exposure; see hundreds of companies, internalize failures, and trust the lightning bolt when it hits.", "guest": "Cyan Banister", "slug": "banister-investing-for-a-higher-purpose", "date": "2024-02-20", "type": "VC"}, {"id": "hamed-multi-disciplinary-investing#0", "t": "Multi-asset investing increases surface area; invest in the same company across venture, credit, real estate to maximize engagement and returns.", "guest": "Ali Hamed", "slug": "hamed-multi-disciplinary-investing", "date": "2024-02-27", "type": "PE / Buyout"}, {"id": "hamed-multi-disciplinary-investing#1", "t": "Market spotting trumps market sizing; identify uninvestable or ignored niches that will scale; enter before institutional capital arrives.", "guest": "Ali Hamed", "slug": "hamed-multi-disciplinary-investing", "date": "2024-02-27", "type": "PE / Buyout"}, {"id": "hamed-multi-disciplinary-investing#3", "t": "Asset class maturity varies; YouTube Catalogues and music royalties offer credit-like stability; iBuyers show why bad unit economics fail.", "guest": "Ali Hamed", "slug": "hamed-multi-disciplinary-investing", "date": "2024-02-27", "type": "PE / Buyout"}, {"id": "srinivas-building-an-answer-engine#0", "t": "Answer engines represent a fundamental shift from link-list search; 90% of users satisfied with synthesis means Google's model breaks.", "guest": "Aravind Srinivas", "slug": "srinivas-building-an-answer-engine", "date": "2024-03-05", "type": "Founder / Operator"}, {"id": "srinivas-building-an-answer-engine#1", "t": "Speed and latency are product features, not engineering details; Perplexity reduced query time from 7 seconds to enable consumer adoption.", "guest": "Aravind Srinivas", "slug": "srinivas-building-an-answer-engine", "date": "2024-03-05", "type": "Founder / Operator"}, {"id": "srinivas-building-an-answer-engine#2", "t": "Early-stage capital efficiency forces focus; with $2M, validate weekly active use and user demand before scaling infrastructure.", "guest": "Aravind Srinivas", "slug": "srinivas-building-an-answer-engine", "date": "2024-03-05", "type": "Founder / Operator"}, {"id": "srinivas-building-an-answer-engine#4", "t": "Next frontier: reasoning in smaller models; cost per query collapses if smaller models can match GPT-4 accuracy; this unlocks profitability.", "guest": "Aravind Srinivas", "slug": "srinivas-building-an-answer-engine", "date": "2024-03-05", "type": "Founder / Operator"}, {"id": "peterson-a-people-first-approach#0", "t": "Capital Group's distributed ownership and long-term shareholder alignment have enabled compound growth to $2.5T without the 'star manager' burnout that kills most firms; people-first culture is a defensible moat.", "guest": "Anne-Marie Peterson", "slug": "peterson-a-people-first-approach", "date": "2024-03-12", "type": "Public Markets"}, {"id": "peterson-a-people-first-approach#1", "t": "Retail's durable economics flow from cult-like discipline: when management refuses to maximize short-term margins (Costco's 10% cap, Jim Sinegal's ethics) loyalty locks in and pricing power grows.", "guest": "Anne-Marie Peterson", "slug": "peterson-a-people-first-approach", "date": "2024-03-12", "type": "Public Markets"}, {"id": "peterson-a-people-first-approach#2", "t": "Big Tech's AI dominance is consensus, not contrarian; study less-obvious plays (Shopify as 'Microsoft 30 years ago') where founder vision and ecosystem power might deliver generational returns.", "guest": "Anne-Marie Peterson", "slug": "peterson-a-people-first-approach", "date": "2024-03-12", "type": "Public Markets"}, {"id": "fontenot-the-monastery-of-code#0", "t": "Residency models (not traditional accelerators) will become the infrastructure for top founders; the 3% equity + $500K uncapped structure attracts unicorn founders who wouldn't take 7% at lower-selectivity programs.", "guest": "Dave Fontenot", "slug": "fontenot-the-monastery-of-code", "date": "2024-03-19", "type": "Founder / Operator"}, {"id": "fontenot-the-monastery-of-code#1", "t": "Product sense—the ability to ship end-to-end consumer features in days—is a rarer founding skill than raw engineering prowess; batch-select for this signal over credentials.", "guest": "Dave Fontenot", "slug": "fontenot-the-monastery-of-code", "date": "2024-03-19", "type": "Founder / Operator"}, {"id": "fontenot-the-monastery-of-code#2", "t": "Flow state multiplication (12 weeks vs. 2 hours daily) unlocks permanent confidence gains; founders report 2x yearly progress in single batch because mental ceiling expands alongside code output.", "guest": "Dave Fontenot", "slug": "fontenot-the-monastery-of-code", "date": "2024-03-19", "type": "Founder / Operator"}, {"id": "feeney-reinventing-the-restaurant-business#0", "t": "Applying finance rigor to archaic industries (restaurants) reveals massive innovation opportunities; variable rent, dynamic pricing, and non-traditional landlord partnerships enable unit-level scalability that traditional restaurants can't achieve.", "guest": "Sean Feeney", "slug": "feeney-reinventing-the-restaurant-business", "date": "2024-03-26", "type": "Founder / Operator"}, {"id": "feeney-reinventing-the-restaurant-business#1", "t": "Smaller, focused concepts (Misi with 20 items vs Lilia's 100+) drive higher per-unit profitability and cult loyalty; scarcity and simplicity compound brand power more than expansion.", "guest": "Sean Feeney", "slug": "feeney-reinventing-the-restaurant-business", "date": "2024-03-26", "type": "Founder / Operator"}, {"id": "feeney-reinventing-the-restaurant-business#2", "t": "People are the moat; when teams write their own job descriptions and feel ownership over brand evolution (like Lilia's content director evolving from host to Instagram strategist), talent density compounds and churn collapses.", "guest": "Sean Feeney", "slug": "feeney-reinventing-the-restaurant-business", "date": "2024-03-26", "type": "Founder / Operator"}, {"id": "dunbar-optimizing-human-connection#0", "t": "Small cohesive teams (under 15) outperform large committees; homophilous core teams execute faster. Diversify only at leadership layers to avoid silos.", "guest": "Robin Dunbar", "slug": "dunbar-optimizing-human-connection", "date": "2024-04-02", "type": "Academic / Author"}, {"id": "dunbar-optimizing-human-connection#2", "t": "Remote work is a cost-cutting illusion: absent endorphin-bonding activities, productivity falls, turnover rises, and onboarding of new relationships stalls entirely.", "guest": "Robin Dunbar", "slug": "dunbar-optimizing-human-connection", "date": "2024-04-02", "type": "Academic / Author"}, {"id": "langone-the-american-dream#0", "t": "Invest in people, not models. Bet on character and resilience; hold positions 35-42 years if management stays quality. Lilly stock compounded at 15% annually for 47 years.", "guest": "Ken Langone", "slug": "langone-the-american-dream", "date": "2024-04-09", "type": "Founder / Operator"}, {"id": "langone-the-american-dream#1", "t": "Trust multiplies returns. Long holding periods (tax-efficient) + deep management knowledge + loyalty to vision = 15% annualized returns over decades unavailable to traders.", "guest": "Ken Langone", "slug": "langone-the-american-dream", "date": "2024-04-09", "type": "Founder / Operator"}, {"id": "langone-the-american-dream#2", "t": "Culture creates moats. Home Depot's $400B valuation came from inverting hierarchy and celebrating hourly workers, not from real estate or inventory logistics.", "guest": "Ken Langone", "slug": "langone-the-american-dream", "date": "2024-04-09", "type": "Founder / Operator"}, {"id": "ferriss-curating-curiosities#0", "t": "Spot emerging platforms by asking bestselling authors which undervalued channels drove sales. Blogs in 2007, podcasts in 2012, etc. Enter before crowds arrive.", "guest": "Tim Ferriss", "slug": "ferriss-curating-curiosities", "date": "2024-04-16", "type": "Founder / Operator"}, {"id": "ferriss-curating-curiosities#2", "t": "Small team, long holding periods, and focus on learning/people over returns compounds wealth and sanity. Stress-testing portfolio for quality-of-life impact matters as much as IRR.", "guest": "Tim Ferriss", "slug": "ferriss-curating-curiosities", "date": "2024-04-16", "type": "Founder / Operator"}, {"id": "ittycheria-the-database-evolution#0", "t": "Market size directly correlates to outcome; prioritize large TAM and proof of expanding customer usage (NDR 120%+) over single logos.", "guest": "Dev Ittycheria", "slug": "ittycheria-the-database-evolution", "date": "2024-05-14", "type": "Public-Co CEO"}, {"id": "ittycheria-the-database-evolution#2", "t": "Consumption-based revenue gives real-time demand signals and demands deep customer success engagement; stickiness alone doesn't guarantee durability.", "guest": "Dev Ittycheria", "slug": "ittycheria-the-database-evolution", "date": "2024-05-14", "type": "Public-Co CEO"}, {"id": "groden-the-future-of-flying#0", "t": "Market adoption of aviation safety tech approaches 100% within years because pilots have direct life-or-death incentive; this is the rare regulatory domain where user preference drives adoption faster than mandates.", "guest": "Mark Groden", "slug": "groden-the-future-of-flying", "date": "2024-05-21", "type": "Founder / Operator"}, {"id": "groden-the-future-of-flying#1", "t": "General aviation produces 2,500 aircraft/year vs 25,000 Model Ts built daily in 1925; unlocking economies of scale (not new physics) is the path to affordability.", "guest": "Mark Groden", "slug": "groden-the-future-of-flying", "date": "2024-05-21", "type": "Founder / Operator"}, {"id": "groden-the-future-of-flying#2", "t": "OEM incentives are perfectly aligned: bigger installed base = more spare parts revenue over aircraft's 30-50 year life; safety and ease-of-use expand the installed base.", "guest": "Mark Groden", "slug": "groden-the-future-of-flying", "date": "2024-05-21", "type": "Founder / Operator"}, {"id": "liu-building-airtable#0", "t": "Market timing is as important as founding team; behavioral shifts (remote work, SMB tooling, AI adoption) trigger platform consolidation around products that capture the shift.", "guest": "Howie Liu", "slug": "liu-building-airtable", "date": "2024-05-28", "type": "Founder / Operator"}, {"id": "liu-building-airtable#1", "t": "Platform businesses with metadata-driven customization eventually win over hard-coded solutions; but require clear templates and co-participant onboarding to avoid overwhelming users.", "guest": "Howie Liu", "slug": "liu-building-airtable", "date": "2024-05-28", "type": "Founder / Operator"}, {"id": "liu-building-airtable#2", "t": "The third wave of AI startups will be industry operators + technologists fused together, not pure tech founders; Pixar-like hybrids that apply AI within domain expertise contexts.", "guest": "Howie Liu", "slug": "liu-building-airtable", "date": "2024-05-28", "type": "Founder / Operator"}, {"id": "sandow-building-brand-new-businesses#0", "t": "Media companies should pursue high-value customers through premium channels, not mass audiences; advertising economics follow customer quality, not size.", "guest": "Adam Sandow", "slug": "sandow-building-brand-new-businesses", "date": "2024-06-04", "type": "Founder / Operator"}, {"id": "sandow-building-brand-new-businesses#1", "t": "Build adjacent revenue streams (products, services, data) on top of distribution channels to create value 100x+ the media property itself.", "guest": "Adam Sandow", "slug": "sandow-building-brand-new-businesses", "date": "2024-06-04", "type": "Founder / Operator"}, {"id": "sandow-building-brand-new-businesses#2", "t": "Use cash flow from mature businesses to fund zero-to-one creations without external capital, maintaining control and long-term compounding.", "guest": "Adam Sandow", "slug": "sandow-building-brand-new-businesses", "date": "2024-06-04", "type": "Founder / Operator"}, {"id": "blake-investing-in-your-people#0", "t": "Stop store growth when returns diminish; optimize existing assets instead of chasing top-line growth. Free capital to improve supply chain and return to shareholders.", "guest": "Frank Blake", "slug": "blake-investing-in-your-people", "date": "2024-06-11", "type": "Public-Co CEO"}, {"id": "blake-investing-in-your-people#2", "t": "Build adjacent revenue streams (credit cards, Wi-Fi, loyalty) that leverage existing capital-intensive assets for increased valuation and customer lifetime value.", "guest": "Frank Blake", "slug": "blake-investing-in-your-people", "date": "2024-06-11", "type": "Public-Co CEO"}, {"id": "grady-relentless-application-of-force#0", "t": "Evaluate founder quality with intimate questions on decision-making and character; intentions matter more than credentials. One person seeing potential can move votes.", "guest": "Pat Grady", "slug": "grady-relentless-application-of-force", "date": "2024-06-18", "type": "VC"}, {"id": "grady-relentless-application-of-force#2", "t": "Venture returns concentrate in 1-2 companies per 100; mass-market funds dilute to noise. Concentrate capital, dedicate to pure-motive founders and investors.", "guest": "Pat Grady", "slug": "grady-relentless-application-of-force", "date": "2024-06-18", "type": "VC"}, {"id": "proposal-ai-commoditization-and-capital-dynamics#0", "t": "Capital cycle inflections in overcapacity troughs create asymmetric opportunities; freight, beverages, transportation all showing post-COVID hangover signals", "guest": "Modest Proposal", "slug": "proposal-ai-commoditization-and-capital-dynamics", "date": "2024-07-02", "type": "Public Markets"}, {"id": "proposal-ai-commoditization-and-capital-dynamics#1", "t": "Identify choke points (NVIDIA, ASML, TSMC) where barriers to entry are structural; capitalism targets these relentlessly for disruption", "guest": "Modest Proposal", "slug": "proposal-ai-commoditization-and-capital-dynamics", "date": "2024-07-02", "type": "Public Markets"}, {"id": "proposal-ai-commoditization-and-capital-dynamics#2", "t": "Bonds offer real yield for first time in 15 years; real interest rate environment reshapes $100B allocator calculus entirely", "guest": "Modest Proposal", "slug": "proposal-ai-commoditization-and-capital-dynamics", "date": "2024-07-02", "type": "Public Markets"}, {"id": "casado-entering-uncharted-ai-territory#0", "t": "Invest in teams building models trained on human-created data—economics proven. For robotics/real-world, become specialist in that vertical, not just in tech", "guest": "Martin Casado", "slug": "casado-entering-uncharted-ai-territory", "date": "2024-07-09", "type": "VC"}, {"id": "casado-entering-uncharted-ai-territory#1", "t": "Market annealing requires true north on tech evolution + market education; asking customers what they want is leading the witness—most successful founders know the answer", "guest": "Martin Casado", "slug": "casado-entering-uncharted-ai-territory", "date": "2024-07-09", "type": "VC"}, {"id": "casado-entering-uncharted-ai-territory#2", "t": "Defensibility emerges from traditional moats (community, API, workflows, brand) after first-mover advantage erodes; model superiority alone is not defensible long-term", "guest": "Martin Casado", "slug": "casado-entering-uncharted-ai-territory", "date": "2024-07-09", "type": "VC"}, {"id": "taneja-engineering-global-resilience#0", "t": "Volume-based healthcare incentives (paid for sick care, not prevention) misalign provider interests; payer-provider convergence is essential for value-based outcomes.", "guest": "Hemant Taneja", "slug": "taneja-engineering-global-resilience", "date": "2024-07-31", "type": "VC"}, {"id": "taneja-engineering-global-resilience#1", "t": "Revenue-based financing models (funding 80% of CAC) allow founders to scale cash flow and acquisitions without dilution, outperforming traditional venture for subscription businesses.", "guest": "Hemant Taneja", "slug": "taneja-engineering-global-resilience", "date": "2024-07-31", "type": "VC"}, {"id": "tenev-navigating-robinhoods-evolution#1", "t": "Robo-advisor thesis was wrong; value is not in portfolio automation (commodity) but in holistic advisory (tax, estate, financial planning).", "guest": "Vlad Tenev", "slug": "tenev-navigating-robinhoods-evolution", "date": "2024-08-13", "type": "Founder / Operator"}, {"id": "tenev-navigating-robinhoods-evolution#2", "t": "Crypto's sustained adoption is driven by real economic value (remittances, tokenization) not speculation; stablecoins are leading indicator.", "guest": "Vlad Tenev", "slug": "tenev-navigating-robinhoods-evolution", "date": "2024-08-13", "type": "Founder / Operator"}, {"id": "ric-elias-the-art-of-living-well#0", "t": "Companies built to outlast their founders create lasting value; structure deals around performance, not just valuation.", "guest": "Ric Elias", "slug": "ric-elias-the-art-of-living-well", "date": "2024-09-17", "type": "VC"}, {"id": "ric-elias-the-art-of-living-well#1", "t": "Invest in people who've been coached heavily—athletes, musicians—they understand feedback as growth, not criticism.", "guest": "Ric Elias", "slug": "ric-elias-the-art-of-living-well", "date": "2024-09-17", "type": "VC"}, {"id": "transforming-company-narrative#0", "t": "Founders who communicate their vision directly build stronger reputations than those who rely on intermediaries.", "guest": "Lulu Meservey", "slug": "transforming-company-narrative", "date": "2024-09-24", "type": "Founder / Operator"}, {"id": "transforming-company-narrative#1", "t": "Crisis management is about the long-term narrative, not managing the day's news cycle.", "guest": "Lulu Meservey", "slug": "transforming-company-narrative", "date": "2024-09-24", "type": "Founder / Operator"}, {"id": "transforming-company-narrative#2", "t": "A well-articulated company manifesto clarifies strategy and unifies internal and external communication.", "guest": "Lulu Meservey", "slug": "transforming-company-narrative", "date": "2024-09-24", "type": "Founder / Operator"}, {"id": "the-future-of-intelligent-machines#2", "t": "Accessibility determines adoption velocity; technologies only scale when SMEs can implement them without PhDs or huge budgets.", "guest": "Ray Ozzie", "slug": "the-future-of-intelligent-machines", "date": "2024-10-01", "type": "Founder / Operator"}, {"id": "small-ideas-attract-competition#0", "t": "Bet concentrated on founders pursuing big, category-redefining visions; small incremental ideas face excessive competition.", "guest": "Kareem Zaki", "slug": "small-ideas-attract-competition", "date": "2024-10-08", "type": "VC"}, {"id": "the-art-of-franchise-investing#0", "t": "Unit-level variance reveals skill gaps; the best operators earn 2-3x more than average, creating massive upside when consolidated.", "guest": "Matt Perelman & Alex Sloane", "slug": "the-art-of-franchise-investing", "date": "2024-10-15", "type": "PE / Buyout"}, {"id": "the-art-of-franchise-investing#1", "t": "Operating leverage from multi-unit consolidation (labor pooling, technology, distribution) is the primary value creation lever.", "guest": "Matt Perelman & Alex Sloane", "slug": "the-art-of-franchise-investing", "date": "2024-10-15", "type": "PE / Buyout"}, {"id": "building-islands-of-innovation#0", "t": "In times of significant change, invest in teams willing to do what's correct even when easier paths exist. Principles create long-term defensibility.", "guest": "Tobi Lütke", "slug": "building-islands-of-innovation", "date": "2024-10-22", "type": "Founder / Operator"}, {"id": "building-islands-of-innovation#1", "t": "Most valuable company assets—customer trust, talent attraction, being a system of record—cannot be written on a balance sheet but determine survival.", "guest": "Tobi Lütke", "slug": "building-islands-of-innovation", "date": "2024-10-22", "type": "Founder / Operator"}, {"id": "building-islands-of-innovation#2", "t": "Founder-run companies can rederive strategy against new information without requiring consensus. This speeds adaptation when the world changes.", "guest": "Tobi Lütke", "slug": "building-islands-of-innovation", "date": "2024-10-22", "type": "Founder / Operator"}, {"id": "redefining-semiconductor-progress#0", "t": "Geopolitical manufacturing control is now a first-order economic factor. U.S. onshoring of semiconductor manufacturing creates structural cost inflation but also new venture opportunities.", "guest": "Andrew Homan & Chris Miller", "slug": "redefining-semiconductor-progress", "date": "2024-11-05", "type": "VC"}, {"id": "redefining-semiconductor-progress#1", "t": "The moat isn't the GPU anymore—it's the entire ecosystem: software, memory, power efficiency, and integration. Attack the architecture's weaknesses, not its strengths.", "guest": "Andrew Homan & Chris Miller", "slug": "redefining-semiconductor-progress", "date": "2024-11-05", "type": "VC"}, {"id": "redefining-semiconductor-progress#2", "t": "Supplier-customer power imbalance kills innovation. When NVIDIA's market cap exceeds hyperscalers', incentives misalign. Look for ventures that either build alternatives or help customers integrate vertically.", "guest": "Andrew Homan & Chris Miller", "slug": "redefining-semiconductor-progress", "date": "2024-11-05", "type": "VC"}, {"id": "jared-kushner-the-mechanic#0", "t": "In real estate, winning deals hinge on understanding the other party's true constraints and objectives, not their opening position.", "guest": "Jared Kushner", "slug": "jared-kushner-the-mechanic", "date": "2024-12-20", "type": "PE / Buyout"}, {"id": "building-alphasense#0", "t": "Beachhead strategy works: identify one user type who desperately needs you (investor relations), nail that, expand horizontally from word-of-mouth.", "guest": "Jack Kokko", "slug": "building-alphasense", "date": "2024-12-31", "type": "Founder / Operator"}, {"id": "building-alphasense#1", "t": "AI commoditization risk is real, but moat shifts to data quality, distribution network, and embedded workflows—not the model.", "guest": "Jack Kokko", "slug": "building-alphasense", "date": "2024-12-31", "type": "Founder / Operator"}, {"id": "building-alphasense#2", "t": "LLM reasoning capabilities matter more than scale. System that reasons well through planning/execution/validation beats raw parameters.", "guest": "Jack Kokko", "slug": "building-alphasense", "date": "2024-12-31", "type": "Founder / Operator"}, {"id": "building-captions#0", "t": "AI businesses solving bounded problems (video generation) will be won by best models + data flywheel. GPL issues will be competed on, not owned.", "guest": "Dwight Churchill & Gaurav Misra", "slug": "building-captions", "date": "2025-01-07", "type": "Founder / Operator"}, {"id": "building-captions#1", "t": "Margin expansion comes automatically from GPU deflation. Real competition is software layer and workflow—not the model.", "guest": "Dwight Churchill & Gaurav Misra", "slug": "building-captions", "date": "2025-01-07", "type": "Founder / Operator"}, {"id": "building-captions#2", "t": "Watch for false causality in growth: companies can succeed despite bad decisions if product-market fit is strong. Distinguish signal from noise.", "guest": "Dwight Churchill & Gaurav Misra", "slug": "building-captions", "date": "2025-01-07", "type": "Founder / Operator"}, {"id": "bridging-science-medicine-and-returns#0", "t": "Success in therapeutics investing requires pattern recognition from studying successes (not failures). Learn what works by dissecting winners, then apply that pattern repeatedly across your portfolio.", "guest": "Tal Zaks", "slug": "bridging-science-medicine-and-returns", "date": "2025-01-14", "type": "VC"}, {"id": "bridging-science-medicine-and-returns#1", "t": "Build portfolio companies with degrees of freedom (capital, team structure, scientific optionality) so they can adjust course when reality diverges from assumptions. Underfunded, over-constrained bets fail even with brilliant science.", "guest": "Tal Zaks", "slug": "bridging-science-medicine-and-returns", "date": "2025-01-14", "type": "VC"}, {"id": "bridging-science-medicine-and-returns#2", "t": "Clinical benefit magnitude is the hardest variable to predict pre-launch. You can de-risk biology and pharmacology, but whether a drug is dramatically better than alternatives remains unknowable until late-stage trials.", "guest": "Tal Zaks", "slug": "bridging-science-medicine-and-returns", "date": "2025-01-14", "type": "VC"}, {"id": "designing-the-future#0", "t": "Design literacy is becoming table-stakes for founders. The next wave of entrepreneurs are starting in Figma, thinking through design before hiring designers. This is a permanent shift.", "guest": "Dylan Field", "slug": "designing-the-future", "date": "2025-01-21", "type": "Founder / Operator"}, {"id": "designing-the-future#1", "t": "Software volume will explode with AI, but quality won't follow linearly. Craft and intentional design differentiate. Invest in builders who care about more than shipping fast.", "guest": "Dylan Field", "slug": "designing-the-future", "date": "2025-01-21", "type": "Founder / Operator"}, {"id": "designing-the-future#2", "t": "The role of a CEO includes ownership of design, not just delegation. If design is how you win or lose the business, you must be intimately involved.", "guest": "Dylan Field", "slug": "designing-the-future", "date": "2025-01-21", "type": "Founder / Operator"}, {"id": "combat-service-and-innovation#1", "t": "Align hiring around shared core values, not just skills. Diversity of thought within value-alignment creates strong culture. Diversity without alignment creates politics and defensive behavior.", "guest": "Blake Hall", "slug": "combat-service-and-innovation", "date": "2025-01-28", "type": "Founder / Operator"}, {"id": "combat-service-and-innovation#2", "t": "Identity verification and fraud prevention will be foundational infrastructure. Every transaction, access, and platform needs to know who users are. ID.me's 100M+ member network is a defensible moat.", "guest": "Blake Hall", "slug": "combat-service-and-innovation", "date": "2025-01-28", "type": "Founder / Operator"}, {"id": "graham-duncan-talent-whisperer#0", "t": "Only seed a manager on terms you'd accept without seed economics — capital that 'needs to be deployed' guarantees adverse selection.", "guest": "Graham Duncan", "slug": "graham-duncan-talent-whisperer", "date": "2025-02-04", "type": "Public Markets"}, {"id": "graham-duncan-talent-whisperer#1", "t": "Launch timing is brutally path-dependent: AQR and an identical-pedigree peer launched months apart with opposite fates, so start hot and raise the bar on deal one.", "guest": "Graham Duncan", "slug": "graham-duncan-talent-whisperer", "date": "2025-02-04", "type": "Public Markets"}, {"id": "graham-duncan-talent-whisperer#2", "t": "Hire a CIO on three criteria: taste in people that overlaps the principal's, a quiet ego that makes money through others, and bone-deep conservatism.", "guest": "Graham Duncan", "slug": "graham-duncan-talent-whisperer", "date": "2025-02-04", "type": "Public Markets"}, {"id": "building-granola#0", "t": "In explore-mode problems like AI applications, deep product thinking matters more than capital; investors should evaluate founders' sensibility about what makes tools genuinely useful.", "guest": "Chris Pedregal", "slug": "building-granola", "date": "2025-02-25", "type": "Founder / Operator"}, {"id": "building-granola#1", "t": "Defensibility comes from UI/UX optimization tailored to a specific use case, not raw model intelligence; specialized products beat general assistants by design.", "guest": "Chris Pedregal", "slug": "building-granola", "date": "2025-02-25", "type": "Founder / Operator"}, {"id": "building-granola#2", "t": "Small AI teams scale revenue without proportional headcount by leveraging foundational model improvements; growth doesn't require traditional hiring curves.", "guest": "Chris Pedregal", "slug": "building-granola", "date": "2025-02-25", "type": "Founder / Operator"}, {"id": "how-to-create-a-new-town#0", "t": "New towns generate premium returns (Chautauqua homes sell for 2x outside-town comps; Seabrook delivered strong IRR) but require 15-20 year equity capital, not traditional 5-7 year debt funds structured for quick flips.", "guest": "Devon Zuegel", "slug": "how-to-create-a-new-town", "date": "2025-03-04", "type": "Founder / Operator"}, {"id": "how-to-create-a-new-town#1", "t": "Acquire land entirely with equity to avoid artificial timeline pressure; debt introduces early cash-flow deadlines that force compromises on vision before learning what works.", "guest": "Devon Zuegel", "slug": "how-to-create-a-new-town", "date": "2025-03-04", "type": "Founder / Operator"}, {"id": "how-to-create-a-new-town#2", "t": "Regional comps accelerate capital formation; demonstrating success (Seabrook in Washington relative to California context) shifts institutional perception from speculative to replicable model.", "guest": "Devon Zuegel", "slug": "how-to-create-a-new-town", "date": "2025-03-04", "type": "Founder / Operator"}, {"id": "investing-at-lone-pine#0", "t": "Market structure has fundamentally changed; fundamental research is necessary but insufficient when setup dynamics (pod positioning, short covering, event-driven surprises) drive as much price action as underlying business quality. Duration-oriented investors need hybrid approach: navigate both dislocations and macro backdrops.", "guest": "Kelly Granat", "slug": "investing-at-lone-pine", "date": "2025-03-11", "type": "Hedge Fund"}, {"id": "investing-at-lone-pine#1", "t": "Leadership quality is increasingly mispriced and increasingly important as cost of capital normalizes. Pattern recognition across geographies shows strategy clarity, accountability culture, customer treatment, and long-term incentives explain 80%+ of winner-loser divergence. Identify and concentrate on exceptional operators.", "guest": "Kelly Granat", "slug": "investing-at-lone-pine", "date": "2025-03-11", "type": "Hedge Fund"}, {"id": "investing-at-lone-pine#2", "t": "Competitive advantage compounds through process excellence (apprenticeship model, cross-functional collaboration, data augmentation) and culture (curiosity, disagreement, humility) more than through individual brilliance. Organizational excellence compounds over decades.", "guest": "Kelly Granat", "slug": "investing-at-lone-pine", "date": "2025-03-11", "type": "Hedge Fund"}, {"id": "giving-computers-a-sense-of-smell#0", "t": "Fragrance incumbents have exceptional economics (recession-proof, 90% household penetration, high margins, sticky customers) but zero tech modernization in 300 years—massive arbitrage window.", "guest": "Alex Wiltschko", "slug": "giving-computers-a-sense-of-smell", "date": "2025-03-18", "type": "Founder / Operator"}, {"id": "giving-computers-a-sense-of-smell#1", "t": "Counterfeit detection via scent is a fast-TAM revenue business: 20-second deployment, clear ROI for platforms like StockX, low competition, scales to luxury goods.", "guest": "Alex Wiltschko", "slug": "giving-computers-a-sense-of-smell", "date": "2025-03-18", "type": "Founder / Operator"}, {"id": "giving-computers-a-sense-of-smell#2", "t": "Scent design currently takes 12-18 months; AI can shrink to weeks. Vertical application (Generation) funds platform R&D better than selling software to legacy incumbents.", "guest": "Alex Wiltschko", "slug": "giving-computers-a-sense-of-smell", "date": "2025-03-18", "type": "Founder / Operator"}, {"id": "cybersecurity-investment-playbook#0", "t": "Cybersecurity economics are exceptional: large budgets, switching costs, 50%+ reorder rates, recession-proof (luxury + hygiene). Cyberstarts' first fund hit 4-5 unicorns; $50M → $2B in 3 years.", "guest": "Gili Raanan", "slug": "cybersecurity-investment-playbook", "date": "2025-03-25", "type": "VC"}, {"id": "cybersecurity-investment-playbook#1", "t": "Resilience + Sunrise methodology + urgent pain + single-persona buyer = compounding wins. Wiz hit $32B in 5 years; Gili predicts another company will break that record within 10 years, likely in cyber.", "guest": "Gili Raanan", "slug": "cybersecurity-investment-playbook", "date": "2025-03-25", "type": "VC"}, {"id": "cybersecurity-investment-playbook#2", "t": "Enterprise SaaS wins by targeting single buyer with budget, authority, usage over PLG. Wiz: $1M→$2M→$8M→$25M ARR in 4 quarters; high price point + large deals > logo chase.", "guest": "Gili Raanan", "slug": "cybersecurity-investment-playbook", "date": "2025-03-25", "type": "VC"}, {"id": "the-business-of-defense#0", "t": "Defense moats: identify one-of-one suppliers where replacement cost ≫ purchase price (10-20x), locked in 10-year take-or-pay contracts. Pair with leverage and embedded war-upside optionality.", "guest": "Darren Farber", "slug": "the-business-of-defense", "date": "2025-04-01", "type": "PE / Buyout"}, {"id": "the-business-of-defense#1", "t": "Consolidation winners: well-capitalized companies (Anduril, Northrop, TransDigm) building industrial scale survive capital cycles. Undercapitalized tech plays don't, regardless of innovation.", "guest": "Darren Farber", "slug": "the-business-of-defense", "date": "2025-04-01", "type": "PE / Buyout"}, {"id": "the-business-of-defense#2", "t": "Budget structure locks returns: 80%+ DoD budget is multi-year contracted. New ventures need brand-new requirements (where no incumbent exists) or must drive acquisition reform via responsible-party doctrine.", "guest": "Darren Farber", "slug": "the-business-of-defense", "date": "2025-04-01", "type": "PE / Buyout"}, {"id": "investing-in-carvana#2", "t": "Use mental models from game theory and psychology to identify moats that markets have missed or misvalued due to moral panic or structural biases.", "guest": "Cliff Sosin", "slug": "investing-in-carvana", "date": "2025-04-29", "type": "VC"}, {"id": "entrepreneurship-through-acquisition#0", "t": "Search fund model offers an alternative path to wealth creation for those willing to be hands-on operators, not passive investors.", "guest": "Rick Ruback & Royce Yudkoff", "slug": "entrepreneurship-through-acquisition", "date": "2025-05-13", "type": "Academic / Author"}, {"id": "entrepreneurship-through-acquisition#2", "t": "Working capital management, cash flow optimization, and disciplined growth are where actual value creation happens post-acquisition.", "guest": "Rick Ruback & Royce Yudkoff", "slug": "entrepreneurship-through-acquisition", "date": "2025-05-13", "type": "Academic / Author"}, {"id": "the-gift-and-the-curse-of-staying-private#0", "t": "Late-stage mega-funds (now $5B+ vs $500M historically) now participate in massive 'big check' rounds that distort incentives and prevent healthy market corrections.", "guest": "Bill Gurley", "slug": "the-gift-and-the-curse-of-staying-private", "date": "2025-06-10", "type": "VC"}, {"id": "the-gift-and-the-curse-of-staying-private#1", "t": "IPO process costs 33% in banker underpricing (25%) plus fees (7%), making private markets more attractive and keeping great companies from public shareholders.", "guest": "Bill Gurley", "slug": "the-gift-and-the-curse-of-staying-private", "date": "2025-06-10", "type": "VC"}, {"id": "a-fathers-call-to-action#2", "t": "Biotech early-stage funding is broken—modest coordinated investment could bridge 80% of development gap at fraction of full cost if structured as translational research.", "guest": "Dinakar Singh", "slug": "a-fathers-call-to-action", "date": "2025-06-15", "type": "Founder / Operator"}, {"id": "keys-to-successful-growth-investing#0", "t": "Contrarian positioning in consumer internet while herd moves to SaaS/AI creates opportunity—great franchises will be built on 5B engaged smartphone users worldwide.", "guest": "Jay Hoag", "slug": "keys-to-successful-growth-investing", "date": "2025-06-17", "type": "VC"}, {"id": "keys-to-successful-growth-investing#1", "t": "Growth investing requires eliminating technology risk first, then focusing on adoption rates and scaling—returns from operational compounding beat financial engineering.", "guest": "Jay Hoag", "slug": "keys-to-successful-growth-investing", "date": "2025-06-17", "type": "VC"}, {"id": "keys-to-successful-growth-investing#2", "t": "Patient capital holding best companies through extended public phases generates superior returns versus fund liquidation; permanent capital structures warrant consideration.", "guest": "Jay Hoag", "slug": "keys-to-successful-growth-investing", "date": "2025-06-17", "type": "VC"}, {"id": "full-contact-capitalism#1", "t": "Build direct relationships with regional banks and understand underlying borrowers to source deals before broader market recognition.", "guest": "Andrew Milgram", "slug": "full-contact-capitalism", "date": "2025-08-05", "type": "PE / Buyout"}, {"id": "full-contact-capitalism#2", "t": "Distressed investing requires human insight—understanding motivations, relationships, and psychology of participants is as critical as financial metrics.", "guest": "Andrew Milgram", "slug": "full-contact-capitalism", "date": "2025-08-05", "type": "PE / Buyout"}, {"id": "backing-the-best-managers-in-private-markets#0", "t": "Backing emerging managers like Thrive early—before institutional validation—can generate 10x+ returns and become foundational partnerships.", "guest": "Peter Lacaillade", "slug": "backing-the-best-managers-in-private-markets", "date": "2025-08-12", "type": "VC"}, {"id": "backing-the-best-managers-in-private-markets#2", "t": "Pooled vehicles in wealth management enable institutional-scale competitive advantage by consolidating family capital for negotiating power.", "guest": "Peter Lacaillade", "slug": "backing-the-best-managers-in-private-markets", "date": "2025-08-12", "type": "VC"}, {"id": "performance-during-pain#0", "t": "Employee wellness programs and flexible healthcare choices generate 652%+ TSR; culture compounds harder than most financial metrics.", "guest": "Mark Bertolini", "slug": "performance-during-pain", "date": "2025-08-19", "type": "Public-Co CEO"}, {"id": "performance-during-pain#1", "t": "Healthcare transformation requires moral clarity—firing administrators who prioritize cost over patient life forces institutional change.", "guest": "Mark Bertolini", "slug": "performance-during-pain", "date": "2025-08-19", "type": "Public-Co CEO"}, {"id": "building-insight-partners#0", "t": "Build systematic sourcing infrastructure (60+ person team) as competitive moat for deal flow", "guest": "Jeff Horing", "slug": "building-insight-partners", "date": "2025-09-16", "type": "VC"}, {"id": "building-insight-partners#1", "t": "One Fund across all sizes creates optionality and reduces timing risk vs sector-focused funds", "guest": "Jeff Horing", "slug": "building-insight-partners", "date": "2025-09-16", "type": "VC"}, {"id": "building-ramp#0", "t": "TPV-only model hits ceiling with large enterprise customers who bypass cards for AP/procurement. Dual model (TPV+SaaS) captures value across customer lifecycle.", "guest": "Karim Atiyeh", "slug": "building-ramp", "date": "2025-10-21", "type": "Founder / Operator"}, {"id": "building-ramp#1", "t": "First sign of major competitive threat is when incumbents start complaining about you. Survival demonstrates differentiation worth defending.", "guest": "Karim Atiyeh", "slug": "building-ramp", "date": "2025-10-21", "type": "Founder / Operator"}, {"id": "building-ramp#2", "t": "Conversion ceiling exists (~50%+), TAM expansion is unlimited. Growth must come from lead generation, not monetization/conversion optimization.", "guest": "Karim Atiyeh", "slug": "building-ramp", "date": "2025-10-21", "type": "Founder / Operator"}, {"id": "luca-ferrari-building-bending-spoons#0", "t": "Focus on profundity over scale early. One great feature beats 10 mediocre ones; users stay loyal to solutions that deeply solve their problem.", "guest": "Luca Ferrari", "slug": "luca-ferrari-building-bending-spoons", "date": "2025-11-04", "type": "Founder / Operator"}, {"id": "luca-ferrari-building-bending-spoons#1", "t": "Team composition is destiny. Hire talent that attracts more talent; mediocre founding team cannot later attract exceptional people.", "guest": "Luca Ferrari", "slug": "luca-ferrari-building-bending-spoons", "date": "2025-11-04", "type": "Founder / Operator"}, {"id": "the-anti-ai-bet#0", "t": "Sports remain recession-resistant and increasingly valuable as streaming content commoditizes; UFC went from $15M/year (Spike) to major broadcaster/streaming rights.", "guest": "Ari Emanuel", "slug": "the-anti-ai-bet", "date": "2025-11-19", "type": "Founder / Operator"}, {"id": "the-anti-ai-bet#1", "t": "Premium experiences have unlimited demand at extreme price points—people will pay $300k for exclusive social status and access.", "guest": "Ari Emanuel", "slug": "the-anti-ai-bet", "date": "2025-11-19", "type": "Founder / Operator"}, {"id": "inside-general-atlantic#0", "t": "US equities at 97th-percentile premium (26x earnings, 4% growth) vs. emerging at 9-14x—geographic diversification is compelling when US debt-to-GDP hits 145% within 5 years.", "guest": "Martín Escobari", "slug": "inside-general-atlantic", "date": "2025-11-25", "type": "VC"}, {"id": "inside-general-atlantic#1", "t": "Growth equity now offers 40-50% revenue growers at 15x EBITDA (40% discount to public comps)—best window since 2009 due to 4-year IPO drought creating dry powder pressure.", "guest": "Martín Escobari", "slug": "inside-general-atlantic", "date": "2025-11-25", "type": "VC"}, {"id": "inside-general-atlantic#2", "t": "AI wave is healthier than dot-com because profitable mega-cap firms (Magnificent Six) fund CapEx, not junk-bond speculators over-leveraging thin-margin telecom.", "guest": "Martín Escobari", "slug": "inside-general-atlantic", "date": "2025-11-25", "type": "VC"}, {"id": "inside-a16z-growth#0", "t": "Consumer AI monetization completely open-ended: ChatGPT reaches 1B users but monetizes <50M; 90% of tech surplus goes to end-users; new discovery/affiliate models emerging.", "guest": "David George", "slug": "inside-a16z-growth", "date": "2025-12-02", "type": "VC"}, {"id": "inside-a16z-growth#2", "t": "Market leaders capture 50-90% of value; ABC test applies: number two usually risky. Cloud 7x growth split 50/50 between incumbents and startups because market size massive.", "guest": "David George", "slug": "inside-a16z-growth", "date": "2025-12-02", "type": "VC"}, {"id": "creating-on-principle#0", "t": "Judge people by the artifact: if the invention is good, the inventor is probably good — skip the attribute checklists and consume the work itself.", "guest": "Patrick O’Shaughnessy", "slug": "creating-on-principle", "date": "2026-01-20", "type": "Founder / Operator"}, {"id": "creating-on-principle#1", "t": "Ask founders for two hours of life story before discussing the company; path dependency (originality, hardship, transformation) predicts who wins.", "guest": "Patrick O’Shaughnessy", "slug": "creating-on-principle", "date": "2026-01-20", "type": "Founder / Operator"}, {"id": "creating-on-principle#2", "t": "Get nervous when an idea sounds good to everyone — hunt instead for things that sound dumb but aren't, like starting a magazine in 2025.", "guest": "Patrick O’Shaughnessy", "slug": "creating-on-principle", "date": "2026-01-20", "type": "Founder / Operator"}, {"id": "the-art-of-public-private-market-investing#0", "t": "LLM businesses combine Netflix capex model with Spotify personalization moat. High gross margins and differentiation are real; commoditization fears overblown. Edge: track adoption speed, capital efficiency, and user stickiness metrics.", "guest": "Dan Sundheim", "slug": "the-art-of-public-private-market-investing", "date": "2026-02-24", "type": "VC"}, {"id": "the-art-of-public-private-market-investing#1", "t": "First-mover advantage in AI emerges from accumulated user data and context, not model superiority. Switching costs are real (like Spotify playlists). Investing thesis: which LLM builds broadest, stickiest user base fastest?", "guest": "Dan Sundheim", "slug": "the-art-of-public-private-market-investing", "date": "2026-02-24", "type": "VC"}, {"id": "the-art-of-public-private-market-investing#2", "t": "Hyperscalers face margin compression. As LLM companies turn profitable, they insource compute from AWS/Azure/GCP. Customer concentration risk rising. Short thesis on hyperscaler margins relative to capex-heavy AI buildout.", "guest": "Dan Sundheim", "slug": "the-art-of-public-private-market-investing", "date": "2026-02-24", "type": "VC"}, {"id": "the-best-seat-in-the-market#0", "t": "Structural advantage (the 'seat') compounds more than skill. Build: (1) superior economics to attract capital, (2) investor trust for down-period capital, (3) hiring power for talent. This flywheel beats pure trading acumen.", "guest": "John Arnold", "slug": "the-best-seat-in-the-market", "date": "2026-03-04", "type": "Other"}, {"id": "the-best-seat-in-the-market#1", "t": "Market-making reveals market psychology. See others' positioning → reverse-engineer their conviction → informational edge. Liquidity provision creates visibility no other market participant has.", "guest": "John Arnold", "slug": "the-best-seat-in-the-market", "date": "2026-03-04", "type": "Other"}, {"id": "the-best-seat-in-the-market#2", "t": "China's speed advantage is infrastructure permitting, not labor. US projects take 10+ years to permit; China 17 months to factory. Regulatory reform is the leverage point for US competitiveness.", "guest": "John Arnold", "slug": "the-best-seat-in-the-market", "date": "2026-03-04", "type": "Other"}, {"id": "the-best-seat-in-the-market#3", "t": "Energy sector: solar panel costs fell 90% but system costs stable. Growth opportunities are in labor reduction (robotics) and transmission/grid modernization, not panel tech.", "guest": "John Arnold", "slug": "the-best-seat-in-the-market", "date": "2026-03-04", "type": "Other"}, {"id": "celebrating-heretics#1", "t": "Manufacturing reindustrialization is where innovation happens. Offshoring production kills innovation (WuXi proved it). US has asymmetric advantage: Tesla, Elon, Ford, GM still make things well. Bet on vertical integration.", "guest": "Shyam Sankar", "slug": "celebrating-heretics", "date": "2026-03-10", "type": "Founder / Operator"}, {"id": "celebrating-heretics#2", "t": "AI value accrues at chips and ontology layers, not middle infrastructure. Invest in companies validating AI through real outcomes forward-deployed with customers, not selling abstractions.", "guest": "Shyam Sankar", "slug": "celebrating-heretics", "date": "2026-03-10", "type": "Founder / Operator"}, {"id": "celebrating-heretics#4", "t": "Beginner's mind dominates AI adoption. Youngest hires outproduce 20-year veterans. Empower insurgents over gatekeepers. Cultural transmission matters more than individual skill.", "guest": "Shyam Sankar", "slug": "celebrating-heretics", "date": "2026-03-10", "type": "Founder / Operator"}, {"id": "playing-a-different-game#0", "t": "Founder risk alignment drives long-term thinking: bootstrapped founders betting their net worth make structurally better capital decisions than VC-funded founders optimizing for funding rounds.", "guest": "William Hockey", "slug": "playing-a-different-game", "date": "2026-03-17", "type": "Founder / Operator"}, {"id": "playing-a-different-game#1", "t": "Capital structure should match business model; not all companies can deploy billions effectively, so VC isn't the right fit for sustainable, profitable plays with healthy unit economics.", "guest": "William Hockey", "slug": "playing-a-different-game", "date": "2026-03-17", "type": "Founder / Operator"}, {"id": "playing-a-different-game#2", "t": "Emerging markets will leapfrog developed infrastructure; the best fintech founders should build globally from day one, learning from DRC, Argentina, and Iran's creative constraints.", "guest": "William Hockey", "slug": "playing-a-different-game", "date": "2026-03-17", "type": "Founder / Operator"}, {"id": "building-a-machine#1", "t": "Avoid home-run bias; hitting doubles and triples with very low loss rates (85% of deals return >1x) outperforms concentrated bets with asymmetric downside.", "guest": "Mitchell Green", "slug": "building-a-machine", "date": "2026-03-24", "type": "VC"}, {"id": "building-a-machine#2", "t": "Create value through LP introductions and portfolio support (customer intros, diligence help, hiring support), not board seats; network is the moat in software investing.", "guest": "Mitchell Green", "slug": "building-a-machine", "date": "2026-03-24", "type": "VC"}, {"id": "building-general-physical-intelligence#0", "t": "General-purpose foundation models scale better than narrow specialists; diverse data beats repeated problem-solving; portability requires breadth over depth per-domain.", "guest": "Sergey Levine", "slug": "building-general-physical-intelligence", "date": "2026-03-31", "type": "Scientist"}, {"id": "building-general-physical-intelligence#1", "t": "Bootstrap challenge is real: systems must reach useful-enough threshold to deploy and autonomously collect data; pre-deployment scaling and manufacturing are premature bets.", "guest": "Sergey Levine", "slug": "building-general-physical-intelligence", "date": "2026-03-31", "type": "Scientist"}, {"id": "clarity-of-purpose#0", "t": "Underwriting standards are the primary control lever—lower standards accelerate deployment but destroy risk-adjusted returns when cycles turn.", "guest": "Alan Waxman", "slug": "clarity-of-purpose", "date": "2026-04-08", "type": "PE / Buyout"}, {"id": "clarity-of-purpose#2", "t": "System risk emerges from behavioral misalignment: when firms optimize for fundraising multiples over investor returns, asset-liability mismatches compound across the industry.", "guest": "Alan Waxman", "slug": "clarity-of-purpose", "date": "2026-04-08", "type": "PE / Buyout"}, {"id": "betting-on-atoms#1", "t": "US uranium enrichment capacity collapse creates a 2+ billion-dollar existing LEU market plus HALEU optionality as nuclear grows.", "guest": "Scott Nolan", "slug": "betting-on-atoms", "date": "2026-04-14", "type": "Founder / Operator"}, {"id": "betting-on-atoms#2", "t": "Problem-founder fit matters more than problem-market fit; true believers in hard problems outperform trend-riders even in growing spaces.", "guest": "Scott Nolan", "slug": "betting-on-atoms", "date": "2026-04-14", "type": "Founder / Operator"}, {"id": "trillion-dollar-health-revolution#0", "t": "GLP-1 medicines are consumer-adopted due to friction reduction (weekly injection vs daily discipline); direct-to-consumer channels disrupt pharma pricing power.", "guest": "Alex Karnal", "slug": "trillion-dollar-health-revolution", "date": "2026-04-21", "type": "VC"}, {"id": "trillion-dollar-health-revolution#1", "t": "PCSK9 inhibitors demonstrate that some medical breakthroughs are true free lunches—high efficacy, low toxicity, discovered via human genetics.", "guest": "Alex Karnal", "slug": "trillion-dollar-health-revolution", "date": "2026-04-21", "type": "VC"}, {"id": "supply-demand-of-tokens#0", "t": "Frontier model access is asymmetrically distributed and self-reinforcing: capital-rich firms buy earliest access, deploy highest-ROI use cases, compound advantages faster than cost curves improve.", "guest": "Dylan Patel", "slug": "supply-demand-of-tokens", "date": "2026-04-23", "type": "Founder / Operator"}, {"id": "supply-demand-of-tokens#1", "t": "Memory (DRAM) is the binding constraint for 2027-2028; prices will double/triple as demand destruction via pricing becomes only lever—watch for capacity announcements from SK Hynix and Micron.", "guest": "Dylan Patel", "slug": "supply-demand-of-tokens", "date": "2026-04-23", "type": "Founder / Operator"}, {"id": "supply-demand-of-tokens#2", "t": "AI infrastructure plays (GPU renewals, fab equipment, CPUs) maintain or expand margins despite commoditization because supply-demand gap persists for years, not quarters.", "guest": "Dylan Patel", "slug": "supply-demand-of-tokens", "date": "2026-04-23", "type": "Founder / Operator"}, {"id": "you-retire-you-die#0", "t": "Equity valuation at 252% of GDP is 4x 1929, 3x 2000; mean reversion of 30-35% is historical precedent—prepare for 80-90% GDP wealth destruction and capital-gains tax collapse.", "guest": "Paul Tudor Jones", "slug": "you-retire-you-die", "date": "2026-04-28", "type": "Hedge Fund"}, {"id": "you-retire-you-die#1", "t": "All major crashes since 1970 trace to leverage and derivatives (portfolio insurance, LTCM, 2008 CDOs). Track leverage ratios and derivative notional flows as leading risk indicators.", "guest": "Paul Tudor Jones", "slug": "you-retire-you-die", "date": "2026-04-28", "type": "Hedge Fund"}, {"id": "you-retire-you-die#2", "t": "Exquisite execution beats market timing: focus on maximum-pain moments (33% down days in single assets) to identify opening; pre-plan all scenarios before market open.", "guest": "Paul Tudor Jones", "slug": "you-retire-you-die", "date": "2026-04-28", "type": "Hedge Fund"}, {"id": "ai-founder-mode#0", "t": "Founder mode founders outcompete 'ham sandwich' businesses in AI era because execution difficulty collapses—only obsessive product vision and belief leadership create durable moat.", "guest": "Brian Chesky", "slug": "ai-founder-mode", "date": "2026-05-05", "type": "Founder / Operator"}, {"id": "ai-founder-mode#2", "t": "Design thinking and constraint-driven simplicity are antifragile to AI disruption; founders trained in industrial design/product rigor maintain edge as implementation outsources to AI.", "guest": "Brian Chesky", "slug": "ai-founder-mode", "date": "2026-05-05", "type": "Founder / Operator"}, {"id": "the-cone-of-uncertainty#0", "t": "ROI on total compute spend (training + inference + research) is the primary financial metric; separating into variable vs fixed costs misses the fungibility and interdependence that drive outsized returns.", "guest": "Krishna Rao", "slug": "the-cone-of-uncertainty", "date": "2026-05-13", "type": "Other"}, {"id": "the-cone-of-uncertainty#1", "t": "Customer ROI is proven via 500%+ net dollar retention, Fortune 10 multi-year commitments, and 10x revenue growth (Q1: $9B to $30B run-rate) driven by model capability leaps, not hyperscaling sales.", "guest": "Krishna Rao", "slug": "the-cone-of-uncertainty", "date": "2026-05-13", "type": "Other"}, {"id": "watts-and-wafers#0", "t": "Frontier token value concentration is extreme and persisting; 500%+ NDR, Fortune 10 adoption, and Pareto frontier dominance by Anthropic/OpenAI/Grok mean most AI economic value flows to three labs, not distributed.", "guest": "Gavin Baker", "slug": "watts-and-wafers", "date": "2026-05-20", "type": "Hedge Fund"}, {"id": "watts-and-wafers#1", "t": "Infrastructure plays (energy, chips, data centers, cooling, financing) capture durable margin by being upstream of AI consumption; shortage cycles reward highest-cost suppliers who become cash-flow machines.", "guest": "Gavin Baker", "slug": "watts-and-wafers", "date": "2026-05-20", "type": "Hedge Fund"}, {"id": "watts-and-wafers#2", "t": "TSMC's capacity discipline is a black-swan risk to AI profitability: either they constrain (bubble unlikely but upside capped) or they expand (competitors emerge and margins compress across the sector).", "guest": "Gavin Baker", "slug": "watts-and-wafers", "date": "2026-05-20", "type": "Hedge Fund"}, {"id": "the-new-rules-of-war#0", "t": "Defense contractors and neoprime startups require multi-year Congressional appropriations and platform commitments to scale; continuing resolutions and single-year money destroy industrial capability and kill investor returns.", "guest": "Darren Farber", "slug": "the-new-rules-of-war", "date": "2026-05-26", "type": "Other"}, {"id": "the-new-rules-of-war#1", "t": "Magazine depth (ordnance, spare parts, production capacity) is the binding constraint to projecting sustained force; requires Manhattan-Project-scale commitment (~1% GDP equivalent) across multiple years, not annual budget cycles.", "guest": "Darren Farber", "slug": "the-new-rules-of-war", "date": "2026-05-26", "type": "Other"}, {"id": "the-new-rules-of-war#2", "t": "Theater of war is the only laboratory for validating military innovation; Ukraine's drone iteration (50 variants in 3 years via commercial supply chains) proves that actual contingencies, not exercises, drive technological dominance.", "guest": "Darren Farber", "slug": "the-new-rules-of-war", "date": "2026-05-26", "type": "Other"}, {"id": "reminiscences-of-an-investor#0", "t": "Credit investing is a strategic arsenal—develop relationships and expertise in private credit to hedge equity exposure during uncertainty.", "guest": "Dan Loeb", "slug": "reminiscences-of-an-investor", "date": "2026-05-28", "type": "Hedge Fund"}, {"id": "reminiscences-of-an-investor#2", "t": "Target high-status companies with obvious operational underperformance; activism via writing creates social pressure without always needing board seats.", "guest": "Dan Loeb", "slug": "reminiscences-of-an-investor", "date": "2026-05-28", "type": "Hedge Fund"}, {"id": "order-out-of-chaos#0", "t": "Supply-led marketplaces are powerful: build supply (drivers, merchants, restaurants) first, trust that demand will follow organically.", "guest": "Dara Khosrowshahi", "slug": "order-out-of-chaos", "date": "2026-06-03", "type": "Public-Co CEO"}, {"id": "order-out-of-chaos#2", "t": "In capital allocation, prioritize organic growth and innovation over financial engineering; buybacks are the third priority if cash flows well.", "guest": "Dara Khosrowshahi", "slug": "order-out-of-chaos", "date": "2026-06-03", "type": "Public-Co CEO"}, {"id": "investing-on-the-s-curve#0", "t": "Buy exponential S-curves with durable competitive advantages and underappreciated earnings at low multiples (4-5x PE, not 20x forward).", "guest": "Alex Sacerdote", "slug": "investing-on-the-s-curve", "date": "2026-06-09", "type": "Hedge Fund"}, {"id": "investing-on-the-s-curve#2", "t": "Private markets require direct relationships: spend 2,500+ management meetings/year, get to know founding teams, wait for allocation at scale.", "guest": "Alex Sacerdote", "slug": "investing-on-the-s-curve", "date": "2026-06-09", "type": "Hedge Fund"}, {"id": "courage-truth-justice#1", "t": "Real risk requires genuine uncertainty and potential for shame. Without both, people think they're taking risks when they're not.", "guest": "Kareem Amin", "slug": "courage-truth-justice", "date": "2026-06-16", "type": "Founder / Operator"}, {"id": "the-power-of-permanent-capital#0", "t": "Permanent capital structures maintain investment hygiene: no redemption pressure, no conflicting LPs, pure focus on returns and impact.", "guest": "Vlad Barbalat", "slug": "the-power-of-permanent-capital", "date": "2026-06-23", "type": "VC"}, {"id": "the-power-of-permanent-capital#2", "t": "Build reputation as an entrepreneurial partner, not a mega-allocator. GPs remember LPs that move fast, help them build, and refer others.", "guest": "Vlad Barbalat", "slug": "the-power-of-permanent-capital", "date": "2026-06-23", "type": "VC"}, {"id": "the-future-of-ai-hardware#0", "t": "Inference demand will exceed training demand by orders of magnitude. Companies building inference infrastructure will capture massive value.", "guest": "Gavin Uberti & Rob Wachen", "slug": "the-future-of-ai-hardware", "date": "2026-06-30", "type": "Founder / Operator"}, {"id": "the-future-of-ai-hardware#2", "t": "Economics of scale in inference mirror those in traditional infrastructure (fabs, power plants). Multi-hundred-billion-dollar data centers are inevitable.", "guest": "Gavin Uberti & Rob Wachen", "slug": "the-future-of-ai-hardware", "date": "2026-06-30", "type": "Founder / Operator"}, {"id": "posting-priests-private-markets#0", "t": "In private markets, storytelling ability filters funds more than realized returns; narrative drives LP perception during the 10-year hold.", "guest": "Jeremy Giffon", "slug": "posting-priests-private-markets", "date": "2026-07-07", "type": "VC"}, {"id": "posting-priests-private-markets#1", "t": "Avoid underwriting emerging managers based only on thesis and track record—examine personal finances to see if they're intimidated or confident with fund size.", "guest": "Jeremy Giffon", "slug": "posting-priests-private-markets", "date": "2026-07-07", "type": "VC"}, {"id": "how-to-raise-a-few-billion-dollars#0", "t": "Start fundraising by identifying who already trusts you—leverage friends/family to achieve 2-3x your initial close via credible referral networks.", "guest": "John Kim", "slug": "how-to-raise-a-few-billion-dollars", "date": "2026-07-14", "type": "VC"}, {"id": "how-to-raise-a-few-billion-dollars#1", "t": "Reduce complexity by giving investors one memorable phrase they can repeat to others; this enables trust transfer and accelerates capital flow.", "guest": "John Kim", "slug": "how-to-raise-a-few-billion-dollars", "date": "2026-07-14", "type": "VC"}];
